import { GoogleGenAI } from "@google/genai";

const apiKey = process.env.API_KEY || '';

// Initialize the client only if the key is present to avoid immediate errors, 
// though robust apps should handle missing keys gracefully.
const ai = apiKey ? new GoogleGenAI({ apiKey }) : null;

export const generateAIResponse = async (prompt: string, context?: string): Promise<string> => {
  if (!ai) {
    return "API Key is missing. Please configure process.env.API_KEY.";
  }

  try {
    const fullPrompt = context 
      ? `Context: ${context}\n\nTask: ${prompt}`
      : prompt;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: fullPrompt,
    });

    return response.text || "No response generated.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "I encountered an error processing your request. Please try again later.";
  }
};

