import React, { useState } from 'react';
import { MOCK_EMPLOYEES } from '../constants';
import { Employee } from '../types';
import { Search, Plus, Filter, MoreHorizontal, Mail, Phone, X, CheckCircle, Send } from 'lucide-react';

const StaffDirectory: React.FC = () => {
  const [employees, setEmployees] = useState<Employee[]>(MOCK_EMPLOYEES);
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [notification, setNotification] = useState<{show: boolean, ticketId: string | null, count?: number}>({ show: false, ticketId: null });
  const [selectedIds, setSelectedIds] = useState<string[]>([]);

  // Form State
  const [formData, setFormData] = useState<Partial<Employee>>({
    firstName: '',
    lastName: '',
    id: '',
    department: '',
    role: '',
    phone: '',
    joinDate: new Date().toISOString().split('T')[0],
  });

  const filteredEmployees = employees.filter(emp =>
    emp.lastName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    emp.firstName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    emp.department.toLowerCase().includes(searchTerm.toLowerCase()) ||
    emp.role.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSelectAll = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.checked) {
      setSelectedIds(filteredEmployees.map(emp => emp.id));
    } else {
      setSelectedIds([]);
    }
  };

  const handleSelectOne = (id: string) => {
    setSelectedIds(prev => 
      prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]
    );
  };

  const handleBulkEmail = () => {
    if (selectedIds.length === 0) return;

    // Simulate IT Ticket generation for bulk action
    const ticketId = `IT-BULK-${Math.floor(1000 + Math.random() * 9000)}`;

    setNotification({ show: true, ticketId, count: selectedIds.length });
    setSelectedIds([]);
    setTimeout(() => setNotification({ show: false, ticketId: null }), 6000);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    // Simulate IT Ticket generation
    const ticketId = `IT-${Math.floor(1000 + Math.random() * 9000)}`;

    const newEmployee: Employee = {
      ...formData as Employee,
      id: formData.id || `EMP-${Math.floor(Math.random() * 1000)}`,
      email: 'pending.verification@ola.edu.gh' // Placeholder until IT processes it
    };

    setEmployees(prev => [newEmployee, ...prev]);
    setIsModalOpen(false);

    // Show notification
    setNotification({ show: true, ticketId, count: 1 });
    setTimeout(() => setNotification({ show: false, ticketId: null }), 6000);

    // Reset form
    setFormData({
      firstName: '',
      lastName: '',
      id: '',
      department: '',
      role: '',
      phone: '',
      joinDate: new Date().toISOString().split('T')[0],
    });
  };

  return (
    <div className="space-y-6 relative">
      {/* Notification Toast */}
