                  <td className="px-6 py-4">
                    <div>
                      <p className="font-medium text-slate-900">{req.employeeName}</p>
                      <p className="text-xs text-slate-500">{req.employeeId}</p>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <span className="inline-block px-2 py-1 rounded border border-slate-200 bg-slate-50 text-slate-600 text-xs font-medium">
                      {req.type}
                    </span>
                  </td>
                  <td className="px-6 py-4 text-slate-600">
                    <div className="flex flex-col">
                      <span className="font-medium">{req.startDate} to {req.endDate}</span>
                      <span className="text-xs text-slate-400">Request Date: {req.requestDate}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-slate-600 max-w-xs truncate" title={req.reason}>
                    {req.reason}
                  </td>
                  <td className="px-6 py-4">
                    <span className={`inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-medium border ${getStatusColor(req.status)}`}>
                      {getStatusIcon(req.status)}
                      {req.status}
                    </span>
                  </td>
                  <td className="px-6 py-4 text-right">
                    {req.status === LeaveStatus.PENDING && (
                      <div className="flex justify-end gap-2">
                        <button 
                          onClick={() => handleStatusChange(req.id, LeaveStatus.APPROVED)}
                          className="p-1.5 bg-green-50 text-green-600 hover:bg-green-100 rounded-md transition-colors" 
                          title="Approve"
                        >
                          <Check size={16} />
                        </button>
                        <button 
                          onClick={() => handleStatusChange(req.id, LeaveStatus.REJECTED)}
                          className="p-1.5 bg-red-50 text-red-600 hover:bg-red-100 rounded-md transition-colors" 
                          title="Reject"
                        >
                          <X size={16} />
                        </button>
                      </div>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          {filteredRequests.length === 0 && (
            <div className="p-8 text-center text-slate-500">
              No leave requests found.
            </div>
          )}
        </div>
      </div>

      {/* New Request Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
          <div className="bg-white rounded-xl shadow-2xl w-full max-w-lg overflow-hidden animate-in fade-in zoom-in duration-200">
            <div className="flex justify-between items-center p-6 border-b border-slate-100 bg-slate-50">
              <h3 className="text-lg font-bold text-slate-800">New Leave Request</h3>
              <button 
                onClick={() => setIsModalOpen(false)}
                className="text-slate-400 hover:text-slate-600 transition-colors"
              >
                <X size={20} />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="p-6 space-y-4">
              <div className="space-y-1.5">
                <label className="text-sm font-medium text-slate-700">Employee</label>
                <select 
                  name="employeeId"
                  required
                  value={formData.employeeId}
                  onChange={handleInputChange}
                  className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all text-sm"
                >
                  <option value="">Select Employee</option>
                  {MOCK_EMPLOYEES.map(emp => (
                    <option key={emp.id} value={emp.id}>{emp.firstName} {emp.lastName} ({emp.id})</option>
                  ))}
                </select>
              </div>

              <div className="space-y-1.5">
                <label className="text-sm font-medium text-slate-700">Leave Type</label>
                <select 
                  name="type"
                  required
                  value={formData.type}
                  onChange={handleInputChange}
                  className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all text-sm"
                >
                  {Object.values(LeaveType).map(type => (
                    <option key={type} value={type}>{type}</option>
                  ))}
                </select>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-sm font-medium text-slate-700">Start Date</label>
                  <input 
                    type="date"
                    name="startDate"
                    required
                    value={formData.startDate}
                    onChange={handleInputChange}
                    className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all text-sm"
                  />
                </div>
                <div className="space-y-1.5">
                  <label className="text-sm font-medium text-slate-700">End Date</label>
                  <input 
                    type="date"
                    name="endDate"
                    required
                    value={formData.endDate}
                    onChange={handleInputChange}
                    className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all text-sm"
                  />
                </div>
              </div>

              <div className="space-y-1.5">
                <label className="text-sm font-medium text-slate-700">Reason</label>
                <textarea 
                  name="reason"
                  required
                  rows={3}
                  value={formData.reason}
                  onChange={handleInputChange}
                  placeholder="Please provide a brief reason for the leave request..."
                  className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all text-sm resize-none"
                />
              </div>

              <div className="pt-2 flex justify-end gap-3">
                <button 
                  type="button"
                  onClick={() => setIsModalOpen(false)}
                  className="px-4 py-2 border border-slate-200 text-slate-600 rounded-lg hover:bg-slate-50 transition-colors text-sm font-medium"
                >
                  Cancel
                </button>
                <button 
                  type="submit"
                  className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors text-sm font-medium shadow-sm"
                >
                  Submit Request
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default LeaveManagement;

import React from 'react';

export enum UserRole {
  ADMIN = 'ADMIN',
  STAFF = 'STAFF',
  STUDENT = 'STUDENT'
}

export enum LeaveStatus {
  PENDING = 'PENDING',
  APPROVED = 'APPROVED',
  REJECTED = 'REJECTED'
}

export enum LeaveType {
  SICK = 'SICK',
  CASUAL = 'CASUAL',
  MATERNITY = 'MATERNITY',
  STUDY = 'STUDY',
  ANNUAL = 'ANNUAL'
}

export interface Student {
  id: string;
  firstName: string;
  lastName: string;
  email: string;
  program: string;
  year: number; // 1, 2, 3, 4
  enrollmentDate: string;
  status: 'Active' | 'Graduated' | 'Suspended';
  gpa: number;
  photo?: string;
}

export interface Employee {
  id: string;
  firstName: string;
  lastName: string;
  department: string;
  role: string;
  email: string;
  phone: string;
  joinDate: string;
  photo?: string;
}

export interface LeaveRequest {
  id: string;
  employeeId: string;
  employeeName: string;
  type: LeaveType;
  startDate: string;
  endDate: string;
  reason: string;
  status: LeaveStatus;
  requestDate: string;
}

export interface MenuItem {
  id: string;
  label: string;
  icon: React.ReactNode;
}

import React, { useState } from 'react';
import { MOCK_STUDENTS } from '../constants';
import { Student } from '../types';
import { Search, Plus, Filter, MoreHorizontal, FileText, X, Upload, User } from 'lucide-react';
import { generateAIResponse } from '../services/geminiService';

const StudentRecords: React.FC = () => {
  const [students, setStudents] = useState<Student[]>(MOCK_STUDENTS);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedStudent, setSelectedStudent] = useState<Student | null>(null);
  const [aiAnalysis, setAiAnalysis] = useState<string>('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [isModalOpen, setIsModalOpen] = useState(false);

  // Form State
  const [formData, setFormData] = useState<Partial<Student>>({
    firstName: '',
    lastName: '',
    id: '',
    program: '',
    year: 1,
    email: '',
    enrollmentDate: new Date().toISOString().split('T')[0],
    gpa: 0.0,
    status: 'Active',
    photo: undefined
  });

  const filteredStudents = students.filter(student =>
    student.lastName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    student.firstName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    student.id.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleGenerateReport = async (student: Student) => {
    setSelectedStudent(student);
    setIsGenerating(true);
    setAiAnalysis('');

    const prompt = `
      Please generate a formal academic performance summary for a student with the following details:
      Name: ${student.firstName} ${student.lastName}
      ID: ${student.id}
      Program: ${student.program}
      Current Year: Year ${student.year}
      Current GPA: ${student.gpa}
      Enrollment Date: ${student.enrollmentDate}

      The tone should be professional and encouraging, suitable for a progress report or reference letter. 
      Mention their potential based on the GPA.
    `;

    try {
      const response = await generateAIResponse(prompt);
      setAiAnalysis(response);
    } catch (error) {
      setAiAnalysis("Failed to generate report.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: name === 'year' || name === 'gpa' ? Number(value) : value
    }));
  };

  const handlePhotoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      const photoUrl = URL.createObjectURL(file);
      setFormData(prev => ({ ...prev, photo: photoUrl }));
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const newStudent: Student = {
      ...formData as Student,
      id: formData.id || `OLA-2024-${Math.floor(Math.random() * 1000)}` // Auto-gen ID if empty for demo
    };

    setStudents(prev => [newStudent, ...prev]);
    setIsModalOpen(false);
    // Reset form
    setFormData({
      firstName: '',
      lastName: '',
      id: '',
      program: '',
      year: 1,
      email: '',
      enrollmentDate: new Date().toISOString().split('T')[0],
      gpa: 0.0,
      status: 'Active',
      photo: undefined
    });
  };

  return (
    <div className="space-y-6 relative">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <h2 className="text-2xl font-bold text-slate-800">Student Records</h2>
        <button 
          onClick={() => setIsModalOpen(true)}
          className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition-colors shadow-sm"
        >
          <Plus size={18} />
          <span>Add New Student</span>
        </button>
      </div>

      {/* Filters and Search */}
      <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-100 flex flex-col sm:flex-row gap-4 justify-between items-center">
        <div className="relative w-full sm:w-96">
          <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400" size={18} />
          <input
            type="text"
            placeholder="Search by name or ID..."
            className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent text-sm"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
        <div className="flex gap-2 w-full sm:w-auto">
          <button className="flex items-center gap-2 px-3 py-2 border border-slate-200 rounded-lg text-slate-600 hover:bg-slate-50 text-sm">
            <Filter size={16} />
            Filter
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Student Table */}
        <div className="lg:col-span-2 bg-white rounded-xl shadow-sm border border-slate-100 overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-left text-sm">
              <thead className="bg-slate-50 border-b border-slate-200">
                <tr>
                  <th className="px-6 py-4 font-semibold text-slate-600">Student Info</th>
                  <th className="px-6 py-4 font-semibold text-slate-600">Program</th>
                  <th className="px-6 py-4 font-semibold text-slate-600">Year</th>
                  <th className="px-6 py-4 font-semibold text-slate-600">GPA</th>
                  <th className="px-6 py-4 font-semibold text-slate-600 text-right">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {filteredStudents.map((student) => (
                  <tr key={student.id} className="hover:bg-slate-50 transition-colors">
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-3">
                        <div className="w-10 h-10 rounded-full bg-blue-100 text-blue-600 flex items-center justify-center font-bold text-xs overflow-hidden flex-shrink-0">
                          {student.photo ? (
                             <img src={student.photo} alt={`${student.firstName} ${student.lastName}`} className="w-full h-full object-cover" />
                          ) : (
                             <span>{student.firstName[0]}{student.lastName[0]}</span>
                          )}
                        </div>
                        <div>
                          <p className="font-medium text-slate-900">{student.firstName} {student.lastName}</p>
                          <p className="text-xs text-slate-500">{student.id}</p>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4 text-slate-600">{student.program}</td>
                    <td className="px-6 py-4">
                      <span className="px-2 py-1 bg-slate-100 text-slate-600 rounded text-xs font-medium">Year {student.year}</span>
                    </td>
                    <td className="px-6 py-4 font-medium text-slate-800">{student.gpa}</td>
                    <td className="px-6 py-4 text-right">
                      <div className="flex justify-end gap-2">
                         <button 
                          onClick={() => handleGenerateReport(student)}
                          title="Generate AI Report"
                          className="p-2 hover:bg-blue-50 text-slate-400 hover:text-blue-600 rounded-lg transition-colors"
                        >
                          <FileText size={18} />
                        </button>
                        <button className="p-2 hover:bg-slate-100 text-slate-400 hover:text-slate-600 rounded-lg transition-colors">
                          <MoreHorizontal size={18} />
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
            {filteredStudents.length === 0 && (
              <div className="p-8 text-center text-slate-500">
                No students found matching your search.
              </div>
            )}
          </div>
        </div>

        {/* Detail / Analysis Panel */}
        <div className="bg-white rounded-xl shadow-sm border border-slate-100 p-6 flex flex-col h-full min-h-[400px]">
          <h3 className="text-lg font-bold text-slate-800 mb-4 flex items-center gap-2">
            <FileText size={20} className="text-blue-600"/>
            AI Student Insight
          </h3>

          {selectedStudent ? (
            <div className="flex-1 flex flex-col">
              <div className="mb-4 pb-4 border-b border-slate-100 flex items-center gap-4">
                <div className="w-16 h-16 rounded-full bg-slate-100 text-slate-400 flex items-center justify-center font-bold text-xl overflow-hidden flex-shrink-0 border-2 border-white shadow-sm">
                   {selectedStudent.photo ? (
                      <img src={selectedStudent.photo} alt="" className="w-full h-full object-cover" />
                   ) : (
                      <span>{selectedStudent.firstName[0]}{selectedStudent.lastName[0]}</span>
                   )}
                </div>
                <div>
                  <p className="text-sm font-medium text-slate-500">Selected Student</p>
                  <p className="text-lg font-bold text-slate-800">{selectedStudent.firstName} {selectedStudent.lastName}</p>
                  <p className="text-xs text-slate-400">{selectedStudent.id}</p>
                </div>
              </div>

              <div className="flex-1 overflow-y-auto pr-2 custom-scrollbar">
                {isGenerating ? (
                   <div className="flex flex-col items-center justify-center h-40 space-y-3">
                     <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div>
                     <p className="text-sm text-slate-500">Analyzing academic records...</p>
                   </div>
                ) : aiAnalysis ? (
                  <div className="prose prose-sm prose-slate max-w-none">
                    <div className="whitespace-pre-line text-slate-600 leading-relaxed text-sm">
                      {aiAnalysis}
                    </div>
                  </div>
                ) : (
                  <p className="text-sm text-slate-400 italic">
                    Click the document icon in the table to generate a performance report for this student.
                  </p>
                )}
              </div>
            </div>
          ) : (
            <div className="flex-1 flex items-center justify-center text-center p-6 text-slate-400">
              <p>Select a student from the list to view details and generate AI reports.</p>
            </div>
          )}
        </div>
      </div>

      {/* Add Student Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
          <div className="bg-white rounded-xl shadow-2xl w-full max-w-lg overflow-hidden animate-in fade-in zoom-in duration-200 flex flex-col max-h-[90vh]">
            <div className="flex justify-between items-center p-6 border-b border-slate-100 bg-slate-50">
              <h3 className="text-lg font-bold text-slate-800">Add New Student</h3>
              <button 
                onClick={() => setIsModalOpen(false)}
                className="text-slate-400 hover:text-slate-600 transition-colors"
              >
                <X size={20} />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="p-6 space-y-4 overflow-y-auto custom-scrollbar">

              {/* Photo Upload */}
              <div className="flex flex-col items-center justify-center mb-6">
                <div className="w-24 h-24 bg-slate-100 rounded-full border-2 border-dashed border-slate-300 flex items-center justify-center overflow-hidden relative group transition-colors hover:border-blue-400">
                    {formData.photo ? (
                        <img src={formData.photo} alt="Preview" className="w-full h-full object-cover" />
                    ) : (
                        <User size={32} className="text-slate-400" />
                    )}
                    <label className="absolute inset-0 flex flex-col items-center justify-center bg-black/50 opacity-0 group-hover:opacity-100 transition-opacity cursor-pointer text-white text-xs font-medium">
                        <Upload size={20} className="mb-1" />
                        <span>Upload</span>
                        <input type="file" accept="image/*" className="hidden" onChange={handlePhotoChange} />
                    </label>
                </div>
                <p className="text-xs text-slate-500 mt-2">Passport Photo</p>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-sm font-medium text-slate-700">First Name</label>
                  <input 
                    name="firstName"
                    required
                    value={formData.firstName}
                    onChange={handleInputChange}
                    className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all text-sm"
                    placeholder="e.g. Kwame"
                  />
                </div>
                <div className="space-y-1.5">
                  <label className="text-sm font-medium text-slate-700">Last Name</label>
                  <input 
                    name="lastName"
                    required
                    value={formData.lastName}
                    onChange={handleInputChange}
                    className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all text-sm"
                    placeholder="e.g. Mensah"
                  />
                </div>
              </div>

              <div className="space-y-1.5">
                <label className="text-sm font-medium text-slate-700">Student ID</label>
                <input 
                  name="id"
                  value={formData.id}
                  onChange={handleInputChange}
                  className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all text-sm"
                  placeholder="e.g. OLA-2024-001 (Optional - Auto generated if empty)"
                />
              </div>

              <div className="space-y-1.5">
                <label className="text-sm font-medium text-slate-700">Email Address</label>
                <input 
                  name="email"
                  type="email"
                  required
                  value={formData.email}
                  onChange={handleInputChange}
                  className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all text-sm"
                  placeholder="student@ola.edu.gh"
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-sm font-medium text-slate-700">Program</label>
                  <select 
                    name="program"
                    required
                    value={formData.program}
                    onChange={handleInputChange}
                    className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all text-sm"
                  >
                    <option value="">Select Program</option>
                    <option value="B.Ed. Primary Education">B.Ed. Primary Education</option>
                    <option value="B.Ed. JHS Education">B.Ed. JHS Education</option>
                    <option value="B.Ed. Early Childhood">B.Ed. Early Childhood</option>
                    <option value="B.Ed. Mathematics">B.Ed. Mathematics</option>
                  </select>
                </div>
                <div className="space-y-1.5">
                  <label className="text-sm font-medium text-slate-700">Year</label>
                  <select 
                    name="year"
                    value={formData.year}
                    onChange={handleInputChange}
                    className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all text-sm"
                  >
                    <option value={1}>Year 1</option>
                    <option value={2}>Year 2</option>
                    <option value={3}>Year 3</option>
                    <option value={4}>Year 4</option>
                  </select>
                </div>
              </div>

               <div className="grid grid-cols-2 gap-4">
                 <div className="space-y-1.5">
                  <label className="text-sm font-medium text-slate-700">Enrollment Date</label>
                  <input 
                    type="date"
                    name="enrollmentDate"
                    required
                    value={formData.enrollmentDate}
                    onChange={handleInputChange}
                    className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all text-sm"
                  />
                </div>
                 <div className="space-y-1.5">
                  <label className="text-sm font-medium text-slate-700">Initial GPA</label>
                  <input 
                    type="number"
                    step="0.01"
                    min="0"
                    max="4.0"
                    name="gpa"
                    value={formData.gpa}
                    onChange={handleInputChange}
                    className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all text-sm"
                  />
                </div>
              </div>

              <div className="pt-4 flex justify-end gap-3 sticky bottom-0 bg-white border-t border-slate-100 mt-auto">
                <button 
                  type="button"
                  onClick={() => setIsModalOpen(false)}
                  className="px-4 py-2 border border-slate-200 text-slate-600 rounded-lg hover:bg-slate-50 transition-colors text-sm font-medium"
                >
                  Cancel
                </button>
                <button 
                  type="submit"
                  className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors text-sm font-medium shadow-sm"
                >
                  Add Student
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default StudentRecords;

import React, { useState } from 'react';
import { MOCK_EMPLOYEES } from '../constants';
import { Employee } from '../types';
import { Search, Plus, Filter, MoreHorizontal, Mail, Phone, X, CheckCircle, Send, Upload, User } from 'lucide-react';

const StaffDirectory: React.FC = () => {
  const [employees, setEmployees] = useState<Employee[]>(MOCK_EMPLOYEES);
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [notification, setNotification] = useState<{show: boolean, ticketId: string | null, count?: number}>({ show: false, ticketId: null });
  const [selectedIds, setSelectedIds] = useState<string[]>([]);

  // Form State
  const [formData, setFormData] = useState<Partial<Employee>>({
    firstName: '',
    lastName: '',
    id: '',
    department: '',
    role: '',
    phone: '',
    joinDate: new Date().toISOString().split('T')[0],
    photo: undefined
  });

  const filteredEmployees = employees.filter(emp =>
    emp.lastName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    emp.firstName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    emp.department.toLowerCase().includes(searchTerm.toLowerCase()) ||
    emp.role.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handlePhotoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      const photoUrl = URL.createObjectURL(file);
      setFormData(prev => ({ ...prev, photo: photoUrl }));
    }
  };

  const handleSelectAll = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.checked) {
      setSelectedIds(filteredEmployees.map(emp => emp.id));
    } else {
      setSelectedIds([]);
    }
  };

  const handleSelectOne = (id: string) => {
    setSelectedIds(prev => 
      prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]
    );
  };

  const handleBulkEmail = () => {
    if (selectedIds.length === 0) return;

    // Simulate IT Ticket generation for bulk action
    const ticketId = `IT-BULK-${Math.floor(1000 + Math.random() * 9000)}`;

    setNotification({ show: true, ticketId, count: selectedIds.length });
    setSelectedIds([]);
    setTimeout(() => setNotification({ show: false, ticketId: null }), 6000);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    // Simulate IT Ticket generation
    const ticketId = `IT-${Math.floor(1000 + Math.random() * 9000)}`;

    const newEmployee: Employee = {
      ...formData as Employee,
      id: formData.id || `EMP-${Math.floor(Math.random() * 1000)}`,
      email: 'pending.verification@ola.edu.gh' // Placeholder until IT processes it
    };

    setEmployees(prev => [newEmployee, ...prev]);
    setIsModalOpen(false);

    // Show notification
    setNotification({ show: true, ticketId, count: 1 });
    setTimeout(() => setNotification({ show: false, ticketId: null }), 6000);

    // Reset form
    setFormData({
      firstName: '',
      lastName: '',
      id: '',
      department: '',
      role: '',
      phone: '',
      joinDate: new Date().toISOString().split('T')[0],
      photo: undefined
    });
  };

  return (
    <div className="space-y-6 relative">
      {/* Notification Toast */}
      {notification.show && (
        <div className="fixed top-24 right-8 z-50 animate-in slide-in-from-right duration-300">
           <div className="bg-white border-l-4 border-green-500 rounded-lg shadow-xl p-4 flex items-start gap-3 max-w-md">
              <div className="text-green-500 p-1">
                <CheckCircle size={24} />
              </div>
              <div>
                <h4 className="font-bold text-slate-800">Request Sent Successfully</h4>
                <p className="text-sm text-slate-600 mt-1">
                  Ticket <span className="font-mono font-bold text-slate-800">#{notification.ticketId}</span> has been sent to IT to generate 
                  {notification.count && notification.count > 1 
                    ? ` emails for ${notification.count} staff members.`
                    : ' an institutional email address.'
                  }
                </p>
              </div>
              <button 
                onClick={() => setNotification({ show: false, ticketId: null })}
                className="text-slate-400 hover:text-slate-600 ml-auto"
              >
                <X size={16} />
              </button>
           </div>
        </div>
      )}

      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <h2 className="text-2xl font-bold text-slate-800">Staff Directory</h2>
        <div className="flex items-center gap-3">
          {selectedIds.length > 0 && (
            <button 
              onClick={handleBulkEmail}
              className="bg-indigo-600 hover:bg-indigo-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition-colors shadow-sm animate-in fade-in zoom-in duration-200"
            >
              <Send size={18} />
              <span>Bulk Email IT ({selectedIds.length})</span>
            </button>
          )}
          <button 
            onClick={() => setIsModalOpen(true)}
            className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition-colors shadow-sm"
          >
            <Plus size={18} />
            <span>Add New Staff</span>
          </button>
        </div>
      </div>

      {/* Filters and Search */}
      <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-100 flex flex-col sm:flex-row gap-4 justify-between items-center">
        <div className="relative w-full sm:w-96">
          <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400" size={18} />
          <input
            type="text"
            placeholder="Search staff by name, role or dept..."
            className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent text-sm"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
        <div className="flex gap-2 w-full sm:w-auto">
          <button className="flex items-center gap-2 px-3 py-2 border border-slate-200 rounded-lg text-slate-600 hover:bg-slate-50 text-sm">
            <Filter size={16} />
            Filter
          </button>
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm">
            <thead className="bg-slate-50 border-b border-slate-200">
              <tr>
                <th className="px-6 py-4 w-12">
                   <input 
                    type="checkbox" 
                    className="rounded border-slate-300 text-blue-600 focus:ring-blue-500 h-4 w-4"
                    checked={filteredEmployees.length > 0 && selectedIds.length === filteredEmployees.length}
                    onChange={handleSelectAll}
                  />
                </th>
                <th className="px-6 py-4 font-semibold text-slate-600">Employee</th>
                <th className="px-6 py-4 font-semibold text-slate-600">Role & Dept</th>
                <th className="px-6 py-4 font-semibold text-slate-600">Contact</th>
                <th className="px-6 py-4 font-semibold text-slate-600">Join Date</th>
                <th className="px-6 py-4 font-semibold text-slate-600 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredEmployees.map((emp) => (
                <tr key={emp.id} className={`hover:bg-slate-50 transition-colors ${selectedIds.includes(emp.id) ? 'bg-blue-50/30' : ''}`}>
                  <td className="px-6 py-4">
                     <input 
                      type="checkbox" 
                      className="rounded border-slate-300 text-blue-600 focus:ring-blue-500 h-4 w-4"
                      checked={selectedIds.includes(emp.id)}
                      onChange={() => handleSelectOne(emp.id)}
                    />
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-3">
                      <div className="w-10 h-10 rounded-full bg-indigo-100 text-indigo-600 flex items-center justify-center font-bold text-sm overflow-hidden flex-shrink-0">
                         {emp.photo ? (
                            <img src={emp.photo} alt={`${emp.firstName} ${emp.lastName}`} className="w-full h-full object-cover" />
                         ) : (
                            <span>{emp.firstName[0]}{emp.lastName[0]}</span>
                         )}
                      </div>
                      <div>
                        <p className="font-medium text-slate-900">{emp.firstName} {emp.lastName}</p>
                        <p className="text-xs text-slate-500">{emp.id}</p>
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div>
                      <p className="text-slate-900 font-medium">{emp.role}</p>
                      <p className="text-slate-500 text-xs">{emp.department}</p>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex flex-col gap-1">
                      <div className="flex items-center gap-2 text-slate-600 text-xs">
                        <Mail size={12} />
                        {emp.email}
                      </div>
                      <div className="flex items-center gap-2 text-slate-600 text-xs">
                        <Phone size={12} />
                        {emp.phone}
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-slate-600">
                    {emp.joinDate}
                  </td>
                  <td className="px-6 py-4 text-right">
                    <button className="p-2 hover:bg-slate-100 text-slate-400 hover:text-slate-600 rounded-lg transition-colors">
                      <MoreHorizontal size={18} />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
           {filteredEmployees.length === 0 && (
              <div className="p-8 text-center text-slate-500">
                No staff found matching your search.
              </div>
            )}
        </div>
      </div>

       {/* Add Staff Modal */}
       {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
          <div className="bg-white rounded-xl shadow-2xl w-full max-w-lg overflow-hidden animate-in fade-in zoom-in duration-200 flex flex-col max-h-[90vh]">
            <div className="flex justify-between items-center p-6 border-b border-slate-100 bg-slate-50">
              <h3 className="text-lg font-bold text-slate-800">Add New Staff Member</h3>
              <button 
                onClick={() => setIsModalOpen(false)}
                className="text-slate-400 hover:text-slate-600 transition-colors"
              >
                <X size={20} />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="p-6 space-y-4 overflow-y-auto custom-scrollbar">

              {/* Photo Upload */}
              <div className="flex flex-col items-center justify-center mb-6">
                <div className="w-24 h-24 bg-slate-100 rounded-full border-2 border-dashed border-slate-300 flex items-center justify-center overflow-hidden relative group transition-colors hover:border-blue-400">
                    {formData.photo ? (
                        <img src={formData.photo} alt="Preview" className="w-full h-full object-cover" />
                    ) : (
                        <User size={32} className="text-slate-400" />
                    )}
                    <label className="absolute inset-0 flex flex-col items-center justify-center bg-black/50 opacity-0 group-hover:opacity-100 transition-opacity cursor-pointer text-white text-xs font-medium">
                        <Upload size={20} className="mb-1" />
                        <span>Upload</span>
                        <input type="file" accept="image/*" className="hidden" onChange={handlePhotoChange} />
                    </label>
                </div>
                <p className="text-xs text-slate-500 mt-2">Passport Photo</p>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-sm font-medium text-slate-700">First Name</label>
                  <input 
                    name="firstName"
                    required
                    value={formData.firstName}
                    onChange={handleInputChange}
                    className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all text-sm"
                    placeholder="e.g. Samuel"
                  />
                </div>
                <div className="space-y-1.5">
                  <label className="text-sm font-medium text-slate-700">Last Name</label>
                  <input 
                    name="lastName"
                    required
                    value={formData.lastName}
                    onChange={handleInputChange}
                    className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all text-sm"
                    placeholder="e.g. Adjei"
                  />
                </div>
              </div>

              <div className="space-y-1.5">
                <label className="text-sm font-medium text-slate-700">Staff ID (Optional)</label>
                <input 
                  name="id"
                  value={formData.id}
                  onChange={handleInputChange}
                  className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all text-sm"
                  placeholder="Will be auto-generated if left blank"
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-sm font-medium text-slate-700">Department</label>
                  <select 
                    name="department"
                    required
                    value={formData.department}
                    onChange={handleInputChange}
                    className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all text-sm"
                  >
                    <option value="">Select Dept</option>
                    <option value="Administration">Administration</option>
                    <option value="Academic Affairs">Academic Affairs</option>
                    <option value="Mathematics">Mathematics</option>
                    <option value="Science">Science</option>
                    <option value="Education">Education</option>
                    <option value="ICT">ICT</option>
                  </select>
                </div>
                <div className="space-y-1.5">
                  <label className="text-sm font-medium text-slate-700">Role / Job Title</label>
                  <input 
                    name="role"
                    required
                    value={formData.role}
                    onChange={handleInputChange}
                    className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all text-sm"
                    placeholder="e.g. Lecturer"
                  />
                </div>
              </div>

               <div className="grid grid-cols-2 gap-4">
                 <div className="space-y-1.5">
                  <label className="text-sm font-medium text-slate-700">Phone Number</label>
                  <input 
                    type="tel"
                    name="phone"
                    required
                    value={formData.phone}
                    onChange={handleInputChange}
                    className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all text-sm"
                    placeholder="024xxxxxxx"
                  />
                </div>
                 <div className="space-y-1.5">
                  <label className="text-sm font-medium text-slate-700">Date Joined</label>
                  <input 
                    type="date"
                    name="joinDate"
                    required
                    value={formData.joinDate}
                    onChange={handleInputChange}
                    className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all text-sm"
                  />
                </div>
              </div>

              <div className="p-4 bg-yellow-50 border border-yellow-100 rounded-lg flex gap-3 items-start">
                  <Mail className="text-yellow-600 mt-0.5 flex-shrink-0" size={16} />
                  <div>
                      <p className="text-xs font-bold text-yellow-800">Email Provisioning</p>
                      <p className="text-xs text-yellow-700 mt-0.5">
                          An institutional email will be requested from IT automatically upon creating this profile. You do not need to enter one.
                      </p>
                  </div>
              </div>

              <div className="pt-2 flex justify-end gap-3 sticky bottom-0 bg-white border-t border-slate-100 mt-auto">
                <button 
                  type="button"
                  onClick={() => setIsModalOpen(false)}
                  className="px-4 py-2 border border-slate-200 text-slate-600 rounded-lg hover:bg-slate-50 transition-colors text-sm font-medium"
                >
                  Cancel
                </button>
                <button 
                  type="submit"
                  className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors text-sm font-medium shadow-sm"
                >
                  Add Staff Member
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
