import React, { useState } from 'react';
import { MOCK_USERS, MOCK_DEPARTMENTS, MOCK_ROLES, MOCK_EMPLOYEES } from '../constants';
import { SystemUser, Department, Role, Employee } from '../types';
import { Plus, Trash2, Edit2, Shield, Users, Building, Key, Check, Search, X } from 'lucide-react';

type SettingsTab = 'users' | 'departments' | 'roles';

const Settings: React.FC = () => {
  const [activeTab, setActiveTab] = useState<SettingsTab>('users');
  const [users, setUsers] = useState<SystemUser[]>(MOCK_USERS);
  const [departments, setDepartments] = useState<Department[]>(MOCK_DEPARTMENTS);
  const [roles, setRoles] = useState<Role[]>(MOCK_ROLES);

  // Modal States
  const [isUserModalOpen, setIsUserModalOpen] = useState(false);
  const [isDeptModalOpen, setIsDeptModalOpen] = useState(false);
  const [isRoleModalOpen, setIsRoleModalOpen] = useState(false);

  // Form States (Simplified for this demo)
  const [userForm, setUserForm] = useState<Partial<SystemUser>>({ isActive: true });
  const [deptForm, setDeptForm] = useState<Partial<Department>>({});
  const [roleForm, setRoleForm] = useState<Partial<Role>>({ permissions: [] });

  // --- Handlers for Users ---

  const generateCredentials = (empId: string) => {
    const employee = MOCK_EMPLOYEES.find(e => e.id === empId);
    if (!employee) return;

    const baseUsername = `${employee.firstName.charAt(0)}.${employee.lastName}`.toLowerCase();
    // Simple logic to ensure default username
    setUserForm(prev => ({
        ...prev,
        username: baseUsername,
        password: 'Ola@2024', // Default password policy
        employeeId: empId
    }));
  };

  const handleCreateUser = (e: React.FormEvent) => {
    e.preventDefault();
    if (!userForm.username || !userForm.roleId || !userForm.employeeId) return;

    const newUser: SystemUser = {
        id: `USR-${Date.now()}`,
        username: userForm.username,
        password: userForm.password,
        employeeId: userForm.employeeId,
        roleId: userForm.roleId,
        isActive: userForm.isActive || true,
        lastLogin: undefined
    };

    setUsers([...users, newUser]);
    setIsUserModalOpen(false);
    setUserForm({ isActive: true });
  };

  // --- Handlers for Departments ---

  const handleCreateDept = (e: React.FormEvent) => {
    e.preventDefault();
    if (!deptForm.name) return;

    const newDept: Department = {
        id: `DEPT-${Date.now()}`,
        name: deptForm.name,
        headOfDept: deptForm.headOfDept,
        description: deptForm.description
    };

    setDepartments([...departments, newDept]);
    setIsDeptModalOpen(false);
    setDeptForm({});
  };

  // --- Handlers for Roles ---

  const handleCreateRole = (e: React.FormEvent) => {
    e.preventDefault();
    if (!roleForm.name) return;

    const newRole: Role = {
        id: `ROLE-${Date.now()}`,
        name: roleForm.name,
        description: roleForm.description || '',
        permissions: roleForm.permissions || []
    };

    setRoles([...roles, newRole]);
    setIsRoleModalOpen(false);
    setRoleForm({ permissions: [] });
  };


  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">System Settings</h2>
          <p className="text-sm text-slate-500 mt-1">Manage users, departments, and access roles.</p>
        </div>
      </div>

      {/* Tabs */}
      <div className="border-b border-slate-200">
        <div className="flex space-x-8">
            <button
                onClick={() => setActiveTab('users')}
                className={`pb-4 text-sm font-medium flex items-center gap-2 border-b-2 transition-colors ${
                    activeTab === 'users' ? 'border-blue-600 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'
                }`}
            >
                <Users size={18} />
                User Management
            </button>
            <button
                onClick={() => setActiveTab('departments')}
