interface RegisterProps {
  onRegister: (user: SystemUser) => void;
  onNavigateToLogin: () => void;
}

const Register: React.FC<RegisterProps> = ({ onRegister, onNavigateToLogin }) => {
  const [formData, setFormData] = useState({
    firstName: '',
    lastName: '',
    email: '',
    username: '',
    password: '',
    confirmPassword: ''
  });
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setIsLoading(true);

    if (formData.password !== formData.confirmPassword) {
      setError("Passwords do not match.");
      setIsLoading(false);
      return;
    }

    if (formData.password.length < 6) {
        setError("Password must be at least 6 characters.");
        setIsLoading(false);
        return;
    }

    // Simulate network delay and creation
    setTimeout(() => {
        // 1. Create Mock Employee
        const newEmployeeId = `EMP-${Math.floor(Math.random() * 10000)}`;
        const newEmployee: Employee = {
            id: newEmployeeId,
            firstName: formData.firstName,
            lastName: formData.lastName,
            email: formData.email,
            department: 'Administration', // Default for Admin Registration
            role: 'Administrator',
            phone: '',
            joinDate: new Date().toISOString().split('T')[0]
        };

        // 2. Create Mock System User
        const newUser: SystemUser = {
            id: `USR-${Date.now()}`,
            username: formData.username,
            password: formData.password,
            employeeId: newEmployeeId,
            roleId: 'ROLE-ADMIN', // Force Admin Role
            isActive: true,
            lastLogin: new Date().toISOString()
        };

        // In a real app, we would save these to the backend here.
        // For this demo, we assume success and auto-login.

        onRegister(newUser);
        setIsLoading(false);
    }, 1500);
  };

  return (
    <div className="min-h-screen bg-slate-100 flex items-center justify-center p-4">
      <div className="max-w-4xl w-full bg-white rounded-2xl shadow-2xl overflow-hidden flex flex-col md:flex-row animate-in fade-in zoom-in duration-300">

        {/* Brand Section */}
