import React, { useState } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import StudentRecords from './components/StudentRecords';
import LeaveManagement from './components/LeaveManagement';
import AIAssistant from './components/AIAssistant';
import StaffDirectory from './components/StaffDirectory';
import Settings from './components/Settings';
import Login from './components/Login';
import Register from './components/Register';
import { SystemUser, Employee } from './types';
import { MOCK_EMPLOYEES } from './constants';
import { Menu } from 'lucide-react';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [currentUser, setCurrentUser] = useState<SystemUser | null>(null);
  const [currentEmployees, setCurrentEmployees] = useState<Employee[]>(MOCK_EMPLOYEES);

  const [activeTab, setActiveTab] = useState('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [authView, setAuthView] = useState<'login' | 'register'>('login');

  const handleLogin = (user: SystemUser) => {
    setCurrentUser(user);
    setIsAuthenticated(true);
    setActiveTab('dashboard');
  };

  const handleRegister = (user: SystemUser) => {
    // For a demo, we essentially "auto-login" the registered user.
    // In a real app, we might require email verification or admin approval.

    // Create a mock employee record if one doesn't exist for this user in our state
    // (Note: Register component generates one, but we need to ensure it's "found" by the app logic)
    // The Register component passes a user with an employeeId.
    // Since we don't pass the Employee object back up from Register in the callback signature 
    // defined in types/interfaces for this specific prompt interaction, 
    // we will simulate finding/adding it here or just handle the user.

    // *Refined Logic*: To make the UI display correct names for the new user,
    // we should ideally add the new employee to our local state.
    // However, since the Register component is creating the Employee internally and not passing it back 
    // (it only passes SystemUser in the prop definition I used), 
    // I will assume for this display that we can extract the username.
    // Or, for a better UX, I'll assume the Register component *could* have added it to a global store.
    // To fix the "Unknown User" display, I'll create a temporary employee record here matching the user.

    const tempEmployee: Employee = {
        id: user.employeeId,
        firstName: 'Admin', // Fallback
        lastName: user.username,
        department: 'Administration',
        role: 'Administrator',
        email: 'admin@ola.edu.gh',
        phone: '',
        joinDate: new Date().toISOString()
    };

    // Add to current employees list so the header works
    setCurrentEmployees(prev => [...prev, tempEmployee]);

    setCurrentUser(user);
    setIsAuthenticated(true);
    setActiveTab('dashboard');
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setIsAuthenticated(false);
    setAuthView('login');
  };

  // Get current employee details based on login
  const currentEmployee = currentUser 
    ? currentEmployees.find(e => e.id === currentUser.employeeId) 
    : null;

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard />;
      case 'students':
        return <StudentRecords />;
      case 'leave':
        return <LeaveManagement />;
      case 'assistant':
        return <AIAssistant />;
      case 'employees':
        return <StaffDirectory />;
      case 'settings':
        return <Settings />;
      default:
        return <Dashboard />;
    }
  };

  if (!isAuthenticated) {
    if (authView === 'register') {
        return (
            <Register 
                onRegister={handleRegister} 
                onNavigateToLogin={() => setAuthView('login')} 
            />
        );
    }
    return (
        <Login 
            onLogin={handleLogin} 
            onNavigateToRegister={() => setAuthView('register')} 
        />
    );
  }

  return (
    <div className="flex min-h-screen bg-[#f3f4f6]">
      {/* Sidebar */}
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        onLogout={handleLogout} 
        isOpen={isSidebarOpen}
        onClose={() => setIsSidebarOpen(false)}
      />

      {/* Main Content Area */}
      <div className="flex-1 flex flex-col md:ml-64 transition-all duration-300 min-w-0">
        {/* Header */}
        <header className="h-16 bg-white shadow-sm border-b border-slate-200 flex items-center justify-between px-4 md:px-8 sticky top-0 z-20">
          <div className="flex items-center gap-3 md:gap-4 text-slate-600">
             <button 
                onClick={() => setIsSidebarOpen(true)}
                className="md:hidden p-1 hover:bg-slate-100 rounded-lg text-slate-600 transition-colors"
             >
                <Menu size={24} />
             </button>
             <div className="flex flex-col md:flex-row md:items-center md:gap-4">
               <span className="font-semibold text-base md:text-lg tracking-tight text-slate-800 truncate">OLA College</span>
               <span className="hidden md:inline text-slate-300">|</span>
               <span className="text-xs md:text-sm text-slate-500 hidden sm:inline">Management Information System</span>
             </div>
          </div>

          <div className="flex items-center gap-3 md:gap-4">
             <div className="text-right hidden sm:block">
                 <p className="text-sm font-bold text-slate-800">
                    {currentEmployee ? `${currentEmployee.firstName} ${currentEmployee.lastName}` : currentUser?.username}
                 </p>
                 <p className="text-xs text-slate-500">
                    {currentEmployee ? currentEmployee.role : 'System User'}
                 </p>
             </div>
             <div className="h-9 w-9 md:h-10 md:w-10 rounded-full bg-slate-900 text-white flex items-center justify-center font-bold overflow-hidden border-2 border-slate-200">
                 {currentEmployee?.photo ? (
                    <img src={currentEmployee.photo} alt="Profile" className="w-full h-full object-cover" />
                 ) : (
                    <span>
                        {currentEmployee 
                            ? `${currentEmployee.firstName[0]}${currentEmployee.lastName[0]}` 
                            : currentUser?.username?.[0]?.toUpperCase() || 'U'}
                    </span>
                 )}
             </div>
          </div>
        </header>

        {/* Dynamic Page Content */}
        <main className="p-4 md:p-8 flex-1 overflow-x-hidden">
          <div className="max-w-7xl mx-auto animate-fade-in">
            {renderContent()}
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

