import React, { useState } from 'react';
import { School, User, Lock, AlertCircle, ArrowRight, Mail, BadgeCheck, ArrowLeft } from 'lucide-react';
import { SystemUser } from '../types';
import { createUserWithEmailAndPassword } from "firebase/auth";
import { auth } from '../services/firebase';

interface RegisterProps {
  onRegister: (user: SystemUser) => void;
  onNavigateToLogin: () => void;
}

const Register: React.FC<RegisterProps> = ({ onRegister, onNavigateToLogin }) => {
  const [formData, setFormData] = useState({
    firstName: '',
    lastName: '',
    email: '',
    username: '',
    password: '',
    confirmPassword: ''
  });
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setIsLoading(true);

    if (formData.password !== formData.confirmPassword) {
      setError("Passwords do not match.");
      setIsLoading(false);
      return;
    }

    if (formData.password.length < 6) {
        setError("Password must be at least 6 characters.");
        setIsLoading(false);
        return;
    }

    try {
      // Create User in Firebase
      await createUserWithEmailAndPassword(auth, formData.email, formData.password);

      // Requirement: Do NOT save user profile data (e.g. no updateProfile, no Firestore).
      // Authentication is sufficient. 
