import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import StudentRecords from './components/StudentRecords';
import LeaveManagement from './components/LeaveManagement';
import AIAssistant from './components/AIAssistant';
import StaffDirectory from './components/StaffDirectory';
import Settings from './components/Settings';
import Login from './components/Login';
import { SystemUser } from './types';
import { MOCK_EMPLOYEES } from './constants';
import { onAuthStateChanged, signOut } from "firebase/auth";
import { auth } from './services/firebase';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [currentUser, setCurrentUser] = useState<SystemUser | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, (user) => {
      if (user) {
        // Map Firebase user to SystemUser
        // Since we don't save profile data yet, we use a default admin role or try to find a match by email
        // For demonstration, if no match is found, we create a generic user object
        const matchedEmployee = MOCK_EMPLOYEES.find(e => e.email.toLowerCase() === user.email?.toLowerCase());

        const systemUser: SystemUser = {
          id: user.uid,
          username: user.email || 'User',
          employeeId: matchedEmployee ? matchedEmployee.id : 'TEMP-ID',
          roleId: 'ROLE-ADMIN', // Defaulting to Admin for now as requested
          isActive: true
        };

        setCurrentUser(systemUser);
        setIsAuthenticated(true);
        setActiveTab('dashboard');
      } else {
        setCurrentUser(null);
        setIsAuthenticated(false);
      }
      setLoading(false);
    });

    return () => unsubscribe();
  }, []);

  const handleLogout = async () => {
    try {
      await signOut(auth);
    } catch (error) {
      console.error("Error signing out: ", error);
    }
  };

  // Get current employee details based on login (mock data mapping)
  const currentEmployee = currentUser && currentUser.employeeId !== 'TEMP-ID'
    ? MOCK_EMPLOYEES.find(e => e.id === currentUser.employeeId) 
    : null;

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard />;
      case 'students':
        return <StudentRecords />;
      case 'leave':
        return <LeaveManagement />;
      case 'assistant':
        return <AIAssistant />;
      case 'employees':
        return <StaffDirectory />;
      case 'settings':
        return <Settings />;
      default:
        return <Dashboard />;
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-[#f3f4f6]">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
      </div>
    );
  }

  if (!isAuthenticated) {
    return <Login />;
  }

  return (
    <div className="flex min-h-screen bg-[#f3f4f6]">
      {/* Sidebar */}
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} onLogout={handleLogout} />

      {/* Main Content Area */}
      <div className="flex-1 ml-64 flex flex-col">
        {/* Header */}
        <header className="h-16 bg-white shadow-sm border-b border-slate-200 flex items-center justify-between px-8 sticky top-0 z-20">
          <div className="flex items-center gap-4 text-slate-600">
             <span className="font-semibold text-lg tracking-tight text-slate-800">OLA College of Education</span>
             <span className="text-slate-300">|</span>
             <span className="text-sm">Management Information System</span>
          </div>

          <div className="flex items-center gap-4">
             <div className="text-right hidden md:block">
                 <p className="text-sm font-bold text-slate-800">
                    {currentEmployee ? `${currentEmployee.firstName} ${currentEmployee.lastName}` : (currentUser?.username || 'User')}
                 </p>
                 <p className="text-xs text-slate-500">
                    {currentEmployee ? currentEmployee.role : 'Administrator'}
                 </p>
             </div>
             <div className="h-10 w-10 rounded-full bg-slate-900 text-white flex items-center justify-center font-bold overflow-hidden border-2 border-slate-200">
                 {currentEmployee?.photo ? (
                    <img src={currentEmployee.photo} alt="Profile" className="w-full h-full object-cover" />
                 ) : (
                    <span>
                        {currentEmployee 
                            ? `${currentEmployee.firstName[0]}${currentEmployee.lastName[0]}` 
                            : (currentUser?.username?.[0].toUpperCase() || 'U')}
                    </span>
                 )}
             </div>
          </div>
        </header>

        {/* Dynamic Page Content */}
        <main className="p-8 flex-1 overflow-auto">
          <div className="max-w-7xl mx-auto animate-fade-in">
            {renderContent()}
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

