import React, { useState } from 'react';
import { School, User, Lock, AlertCircle, ArrowRight, Mail, BadgeCheck, ArrowLeft } from 'lucide-react';
import { SystemUser, Employee } from '../types';
import { createUserWithEmailAndPassword, updateProfile } from 'firebase/auth';
import { auth } from '../services/firebase';

interface RegisterProps {
  onRegister: (user: SystemUser) => void;
  onNavigateToLogin: () => void;
}

const Register: React.FC<RegisterProps> = ({ onRegister, onNavigateToLogin }) => {
  const [formData, setFormData] = useState({
    firstName: '',
    lastName: '',
    email: '',
    username: '', // Still kept for UI, but Firebase uses email mainly
    password: '',
    confirmPassword: ''
  });
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setIsLoading(true);

    if (formData.password !== formData.confirmPassword) {
      setError("Passwords do not match.");
      setIsLoading(false);
      return;
    }

    if (formData.password.length < 6) {
        setError("Password must be at least 6 characters.");
        setIsLoading(false);
        return;
    }

    try {
        const userCredential = await createUserWithEmailAndPassword(auth, formData.email, formData.password);

        // Update profile with name
        await updateProfile(userCredential.user, {
            displayName: `${formData.firstName} ${formData.lastName}`
        });

        const newEmployeeId = `EMP-GUEST`; // Since no Firestore yet

        // Construct SystemUser
        const newUser: SystemUser = {
            id: userCredential.user.uid,
            username: formData.email,
            password: '', // Don't store
            employeeId: newEmployeeId,
            roleId: 'ROLE-ADMIN',
            isActive: true,
            lastLogin: new Date().toISOString()
        };

        onRegister(newUser);
    } catch (err: any) {
        console.error(err);
        if (err.code === 'auth/email-already-in-use') {
            setError("User already exists. Please sign in");
        } else {
            setError(err.message || "Registration failed. Please try again.");
        }
    } finally {
        setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-100 flex items-center justify-center p-4">
      <div className="max-w-4xl w-full bg-white rounded-2xl shadow-2xl overflow-hidden flex flex-col md:flex-row animate-in fade-in zoom-in duration-300">

        {/* Brand Section */}
        <div className="md:w-1/2 bg-slate-900 p-12 text-white flex flex-col justify-between relative overflow-hidden">
