                </>
              )}
            </button>
          </form>

          <div className="mt-6 text-center">
             <p className="text-sm text-slate-500">
               Already have an account? {' '}
               <button onClick={onNavigateToLogin} className="text-blue-600 hover:underline font-semibold">
                 Sign In
               </button>
             </p>
          </div>
        </div>
      </div>
    </div>
  );
};

