                                 <button className="p-2 text-slate-400 hover:text-blue-600 rounded-lg hover:bg-white border border-transparent hover:border-slate-200">
                                     <Edit2 size={16} />
                                 </button>
                             </div>
                        </div>
                    ))}
                </div>
            </div>
        )}
      </div>

      {/* --- MODALS --- */}

      {/* User Modal */}
      {isUserModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
            <div className="bg-white rounded-xl shadow-2xl w-full max-w-md overflow-hidden animate-in fade-in zoom-in duration-200 max-h-[90vh] overflow-y-auto">
                <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50 sticky top-0">
                    <h3 className="font-bold text-lg text-slate-800">{editingUserId ? 'Edit User' : 'Create System User'}</h3>
                    <button onClick={() => setIsUserModalOpen(false)}><X size={20} className="text-slate-400 hover:text-slate-600" /></button>
                </div>
                <form onSubmit={handleSaveUser} className="p-6 space-y-4">
                    <div>
                        <label className="text-sm font-medium text-slate-700 mb-1 block">Employee</label>
                        <select 
                            className="w-full border border-slate-300 rounded-lg p-2 text-sm disabled:bg-slate-100 disabled:text-slate-500"
                            onChange={(e) => generateCredentials(e.target.value)}
                            value={userForm.employeeId || ''}
                            required
                            disabled={!!editingUserId}
                        >
                            <option value="">-- Select Staff --</option>
                            {MOCK_EMPLOYEES.map(emp => (
                                <option key={emp.id} value={emp.id}>{emp.firstName} {emp.lastName} ({emp.id})</option>
                            ))}
                        </select>
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                         <div>
                            <label className="text-sm font-medium text-slate-700 mb-1 block">Username</label>
                            <input 
                                value={userForm.username || ''}
                                readOnly
                                className="w-full bg-slate-50 border border-slate-300 rounded-lg p-2 text-sm font-mono text-slate-500 cursor-not-allowed"
                            />
                        </div>
                        <div>
                            <label className="text-sm font-medium text-slate-700 mb-1 block">Password</label>
                            <input 
                                value={userForm.password || ''}
                                onChange={(e) => setUserForm({...userForm, password: e.target.value})}
                                placeholder={editingUserId ? "Unchanged" : "Generated"}
                                className="w-full border border-slate-300 rounded-lg p-2 text-sm font-mono text-slate-700 placeholder:text-slate-300"
                            />
                        </div>
                    </div>
                    <div>
                        <label className="text-sm font-medium text-slate-700 mb-1 block">Assign Role</label>
                         <select 
                            className="w-full border border-slate-300 rounded-lg p-2 text-sm"
                            onChange={(e) => setUserForm({...userForm, roleId: e.target.value})}
                            value={userForm.roleId || ''}
                            required
                        >
                            <option value="">-- Select Role --</option>
                            {roles.map(r => (
                                <option key={r.id} value={r.id}>{r.name}</option>
                            ))}
                        </select>
                    </div>

                    <div className="flex items-center gap-2 pt-2">
                        <input 
                            type="checkbox" 
                            id="isActive"
                            checked={userForm.isActive}
                            onChange={(e) => setUserForm({...userForm, isActive: e.target.checked})}
                            className="rounded border-slate-300 text-blue-600 focus:ring-blue-500 h-4 w-4"
                        />
                        <label htmlFor="isActive" className="text-sm text-slate-700 select-none cursor-pointer">Account is Active</label>
                    </div>

                    {!editingUserId && (
                        <div className="p-3 bg-blue-50 text-blue-700 text-xs rounded-lg flex gap-2">
                            <Key size={16} className="shrink-0" />
                            <p>Credentials will be auto-generated based on the employee name. The user can change their password after first login.</p>
                        </div>
                    )}

                    <div className="pt-2 flex justify-end gap-2">
                        <button type="button" onClick={() => setIsUserModalOpen(false)} className="px-4 py-2 text-slate-600 text-sm hover:bg-slate-50 rounded-lg">Cancel</button>
                        <button type="submit" className="px-4 py-2 bg-blue-600 text-white text-sm rounded-lg hover:bg-blue-700">
                            {editingUserId ? 'Save Changes' : 'Create User'}
                        </button>
                    </div>
                </form>
            </div>
        </div>
      )}

      {/* Department Modal */}
      {isDeptModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
            <div className="bg-white rounded-xl shadow-2xl w-full max-w-md overflow-hidden animate-in fade-in zoom-in duration-200">
                <div className="p-6 border-b border-slate-100 flex justify-between items-center">
                    <h3 className="font-bold text-lg text-slate-800">Add Department</h3>
                    <button onClick={() => setIsDeptModalOpen(false)}><X size={20} className="text-slate-400 hover:text-slate-600" /></button>
                </div>
                <form onSubmit={handleCreateDept} className="p-6 space-y-4">
                    <div>
                        <label className="text-sm font-medium text-slate-700 mb-1 block">Department Name</label>
                        <input 
                            className="w-full border border-slate-300 rounded-lg p-2 text-sm"
                            placeholder="e.g. Social Sciences"
                            onChange={(e) => setDeptForm({...deptForm, name: e.target.value})}
                            required
                        />
                    </div>
                    <div>
                        <label className="text-sm font-medium text-slate-700 mb-1 block">Description</label>
                        <textarea 
                            className="w-full border border-slate-300 rounded-lg p-2 text-sm"
                            rows={3}
                            onChange={(e) => setDeptForm({...deptForm, description: e.target.value})}
                        />
                    </div>
                    <div>
                        <label className="text-sm font-medium text-slate-700 mb-1 block">Head of Department</label>
                         <select 
                            className="w-full border border-slate-300 rounded-lg p-2 text-sm"
                            onChange={(e) => setDeptForm({...deptForm, headOfDept: e.target.value})}
                        >
                            <option value="">-- Assign Later --</option>
                            {MOCK_EMPLOYEES.map(emp => (
                                <option key={emp.id} value={`${emp.firstName} ${emp.lastName}`}>{emp.firstName} {emp.lastName}</option>
                            ))}
                        </select>
                    </div>
                     <div className="pt-2 flex justify-end gap-2">
                        <button type="button" onClick={() => setIsDeptModalOpen(false)} className="px-4 py-2 text-slate-600 text-sm hover:bg-slate-50 rounded-lg">Cancel</button>
                        <button type="submit" className="px-4 py-2 bg-blue-600 text-white text-sm rounded-lg hover:bg-blue-700">Add Department</button>
                    </div>
                </form>
            </div>
        </div>
      )}

      {/* Role Modal */}
      {isRoleModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
            <div className="bg-white rounded-xl shadow-2xl w-full max-w-lg overflow-hidden animate-in fade-in zoom-in duration-200 max-h-[90vh] flex flex-col">
                <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
                    <h3 className="font-bold text-lg text-slate-800">{editingRoleId ? 'Edit Role' : 'Create Role'}</h3>
                    <button onClick={() => setIsRoleModalOpen(false)}><X size={20} className="text-slate-400 hover:text-slate-600" /></button>
                </div>
                <form onSubmit={handleSaveRole} className="p-6 space-y-4 overflow-y-auto">
                    <div>
                        <label className="text-sm font-medium text-slate-700 mb-1 block">Role Name</label>
                        <input 
                            className="w-full border border-slate-300 rounded-lg p-2 text-sm"
                            placeholder="e.g. Exam Officer"
                            value={roleForm.name || ''}
                            onChange={(e) => setRoleForm({...roleForm, name: e.target.value})}
                            required
                        />
                    </div>
                    <div>
                        <label className="text-sm font-medium text-slate-700 mb-1 block">Description</label>
                         <input 
                            className="w-full border border-slate-300 rounded-lg p-2 text-sm"
                            value={roleForm.description || ''}
                            onChange={(e) => setRoleForm({...roleForm, description: e.target.value})}
                        />
                    </div>

                    <div>
                        <label className="text-sm font-medium text-slate-700 mb-2 block">Permissions</label>
                        <div className="grid grid-cols-2 gap-2 max-h-48 overflow-y-auto p-2 border border-slate-100 rounded-lg bg-slate-50">
                            {AVAILABLE_PERMISSIONS.map(perm => (
                                <label key={perm} className="flex items-center gap-2 p-2 hover:bg-white rounded cursor-pointer transition-colors border border-transparent hover:border-slate-200">
                                    <div 
                                        onClick={() => togglePermission(perm)}
                                        className={`w-4 h-4 rounded border flex items-center justify-center transition-colors ${roleForm.permissions?.includes(perm) ? 'bg-blue-600 border-blue-600 text-white' : 'bg-white border-slate-300 text-transparent'}`}
                                    >
                                        <Check size={12} />
                                    </div>
                                    <span className="text-xs font-mono text-slate-600">{perm}</span>
                                </label>
                            ))}
                        </div>
                    </div>

                     <div className="pt-2 flex justify-end gap-2 sticky bottom-0 bg-white border-t border-slate-100 mt-4">
                        <button type="button" onClick={() => setIsRoleModalOpen(false)} className="px-4 py-2 text-slate-600 text-sm hover:bg-slate-50 rounded-lg">Cancel</button>
                        <button type="submit" className="px-4 py-2 bg-blue-600 text-white text-sm rounded-lg hover:bg-blue-700">
                            {editingRoleId ? 'Save Changes' : 'Create Role'}
                        </button>
                    </div>
                </form>
            </div>
        </div>
      )}

    </div>
  );
};

export default Settings;

import React, { useState } from 'react';
import { MOCK_EMPLOYEES } from '../constants';
import { Employee } from '../types';
import { Search, Plus, Filter, MoreHorizontal, Mail, Phone, X, CheckCircle, Send, Upload, User, Edit2, Trash2, Eye } from 'lucide-react';

const StaffDirectory: React.FC = () => {
  const [employees, setEmployees] = useState<Employee[]>(MOCK_EMPLOYEES);
  const [searchTerm, setSearchTerm] = useState('');

  // Modal States
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isViewModalOpen, setIsViewModalOpen] = useState(false);

  const [notification, setNotification] = useState<{show: boolean, ticketId: string | null, count?: number}>({ show: false, ticketId: null });
  const [selectedIds, setSelectedIds] = useState<string[]>([]);

  // Selection States
  const [viewingEmployee, setViewingEmployee] = useState<Employee | null>(null);
  const [editingEmployeeId, setEditingEmployeeId] = useState<string | null>(null);

  // Form State
  const [formData, setFormData] = useState<Partial<Employee>>({
    firstName: '',
    lastName: '',
    id: '',
    department: '',
    role: '',
    phone: '',
    joinDate: new Date().toISOString().split('T')[0],
    photo: undefined
  });

  const filteredEmployees = employees.filter(emp =>
    emp.lastName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    emp.firstName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    emp.department.toLowerCase().includes(searchTerm.toLowerCase()) ||
    emp.role.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handlePhotoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      const photoUrl = URL.createObjectURL(file);
      setFormData(prev => ({ ...prev, photo: photoUrl }));
    }
  };

  const handleSelectAll = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.checked) {
      setSelectedIds(filteredEmployees.map(emp => emp.id));
    } else {
      setSelectedIds([]);
    }
  };

  const handleSelectOne = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    setSelectedIds(prev => 
      prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]
    );
  };

  const handleBulkEmail = () => {
    if (selectedIds.length === 0) return;
    const ticketId = `IT-BULK-${Math.floor(1000 + Math.random() * 9000)}`;
    setNotification({ show: true, ticketId, count: selectedIds.length });
    setSelectedIds([]);
    setTimeout(() => setNotification({ show: false, ticketId: null }), 6000);
  };

  // --- Action Handlers ---

  const handleAddClick = () => {
    setEditingEmployeeId(null);
    setFormData({
      firstName: '',
      lastName: '',
      id: '',
      department: '',
      role: '',
      phone: '',
      joinDate: new Date().toISOString().split('T')[0],
      photo: undefined
    });
    setIsModalOpen(true);
  };

  const handleEditClick = (e: React.MouseEvent, emp: Employee) => {
    e.stopPropagation();
    setEditingEmployeeId(emp.id);
    setFormData(emp);
    setIsModalOpen(true);
  };

  const handleDeleteClick = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (window.confirm("Are you sure you want to delete this staff member? This action cannot be undone.")) {
      setEmployees(prev => prev.filter(emp => emp.id !== id));
      if (viewingEmployee?.id === id) {
        setIsViewModalOpen(false);
        setViewingEmployee(null);
      }
    }
  };

  const handleRowClick = (emp: Employee) => {
    setViewingEmployee(emp);
    setIsViewModalOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (editingEmployeeId) {
      // Update existing
      setEmployees(prev => prev.map(emp => 
        emp.id === editingEmployeeId ? { ...emp, ...formData } as Employee : emp
      ));
    } else {
      // Create new
      const ticketId = `IT-${Math.floor(1000 + Math.random() * 9000)}`;
      const newEmployee: Employee = {
        ...formData as Employee,
        id: formData.id || `EMP-${Math.floor(Math.random() * 1000)}`,
        email: formData.email || 'pending.verification@ola.edu.gh'
      };
      setEmployees(prev => [newEmployee, ...prev]);
      setNotification({ show: true, ticketId, count: 1 });
      setTimeout(() => setNotification({ show: false, ticketId: null }), 6000);
    }

    setIsModalOpen(false);
    setEditingEmployeeId(null);
    setFormData({
      firstName: '',
      lastName: '',
      id: '',
      department: '',
      role: '',
      phone: '',
      joinDate: new Date().toISOString().split('T')[0],
      photo: undefined
    });
  };

  return (
    <div className="space-y-6 relative">
      {/* Notification Toast */}
      {notification.show && (
        <div className="fixed top-24 right-8 z-50 animate-in slide-in-from-right duration-300">
           <div className="bg-white border-l-4 border-green-500 rounded-lg shadow-xl p-4 flex items-start gap-3 max-w-md">
              <div className="text-green-500 p-1">
                <CheckCircle size={24} />
              </div>
              <div>
                <h4 className="font-bold text-slate-800">Success</h4>
                <p className="text-sm text-slate-600 mt-1">
                  Ticket <span className="font-mono font-bold text-slate-800">#{notification.ticketId}</span> created.
                  {notification.count && notification.count > 1 
                    ? ` Processing ${notification.count} staff members.`
                    : ' IT has been notified.'
                  }
                </p>
              </div>
              <button 
                onClick={() => setNotification({ show: false, ticketId: null })}
                className="text-slate-400 hover:text-slate-600 ml-auto"
              >
                <X size={16} />
              </button>
           </div>
        </div>
      )}

      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <h2 className="text-2xl font-bold text-slate-800">Staff Directory</h2>
        <div className="flex items-center gap-3 w-full sm:w-auto">
          {selectedIds.length > 0 && (
            <button 
              onClick={handleBulkEmail}
              className="bg-indigo-600 hover:bg-indigo-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition-colors shadow-sm animate-in fade-in zoom-in duration-200 text-sm"
            >
              <Send size={18} />
              <span className="hidden sm:inline">Bulk Email IT ({selectedIds.length})</span>
            </button>
          )}
          <button 
            onClick={handleAddClick}
            className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition-colors shadow-sm text-sm ml-auto sm:ml-0"
          >
            <Plus size={18} />
            <span>Add New Staff</span>
          </button>
        </div>
      </div>

      {/* Filters and Search */}
      <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-100 flex flex-col sm:flex-row gap-4 justify-between items-center">
        <div className="relative w-full sm:w-96">
          <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400" size={18} />
          <input
            type="text"
            placeholder="Search staff by name, role or dept..."
            className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent text-sm"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
        <div className="flex gap-2 w-full sm:w-auto">
          <button className="flex items-center gap-2 px-3 py-2 border border-slate-200 rounded-lg text-slate-600 hover:bg-slate-50 text-sm">
            <Filter size={16} />
            Filter
          </button>
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm">
            <thead className="bg-slate-50 border-b border-slate-200">
              <tr>
                <th className="px-6 py-4 w-12">
                   <input 
                    type="checkbox" 
                    className="rounded border-slate-300 text-blue-600 focus:ring-blue-500 h-4 w-4"
                    checked={filteredEmployees.length > 0 && selectedIds.length === filteredEmployees.length}
                    onChange={handleSelectAll}
                  />
                </th>
                <th className="px-6 py-4 font-semibold text-slate-600">Employee</th>
                <th className="px-6 py-4 font-semibold text-slate-600">Role & Dept</th>
                <th className="px-6 py-4 font-semibold text-slate-600">Contact</th>
                <th className="px-6 py-4 font-semibold text-slate-600">Join Date</th>
                <th className="px-6 py-4 font-semibold text-slate-600 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredEmployees.map((emp) => (
                <tr 
                  key={emp.id} 
                  onClick={() => handleRowClick(emp)}
                  className={`hover:bg-slate-50 transition-colors cursor-pointer ${selectedIds.includes(emp.id) ? 'bg-blue-50/30' : ''}`}
                >
                  <td className="px-6 py-4" onClick={(e) => e.stopPropagation()}>
                     <input 
                      type="checkbox" 
                      className="rounded border-slate-300 text-blue-600 focus:ring-blue-500 h-4 w-4 cursor-pointer"
                      checked={selectedIds.includes(emp.id)}
                      onClick={(e) => handleSelectOne(e, emp.id)}
                      onChange={() => {}} // Handled by onClick to prevent propagation issues
                    />
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-3">
                      <div className="w-10 h-10 rounded-full bg-indigo-100 text-indigo-600 flex items-center justify-center font-bold text-sm overflow-hidden flex-shrink-0">
                         {emp.photo ? (
                            <img src={emp.photo} alt={`${emp.firstName} ${emp.lastName}`} className="w-full h-full object-cover" />
                         ) : (
                            <span>{emp.firstName[0]}{emp.lastName[0]}</span>
                         )}
                      </div>
                      <div>
                        <p className="font-medium text-slate-900">{emp.firstName} {emp.lastName}</p>
                        <p className="text-xs text-slate-500">{emp.id}</p>
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div>
                      <p className="text-slate-900 font-medium">{emp.role}</p>
                      <p className="text-slate-500 text-xs">{emp.department}</p>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex flex-col gap-1">
                      <div className="flex items-center gap-2 text-slate-600 text-xs">
                        <Mail size={12} />
                        {emp.email}
                      </div>
                      <div className="flex items-center gap-2 text-slate-600 text-xs">
                        <Phone size={12} />
                        {emp.phone}
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-slate-600">
                    {emp.joinDate}
                  </td>
                  <td className="px-6 py-4 text-right">
                    <div className="flex justify-end gap-2">
                        <button 
                            onClick={(e) => handleEditClick(e, emp)}
                            className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                            title="Edit Details"
                        >
                            <Edit2 size={16} />
                        </button>
                        <button 
                            onClick={(e) => handleDeleteClick(e, emp.id)}
                            className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                            title="Delete Staff"
                        >
                            <Trash2 size={16} />
                        </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
           {filteredEmployees.length === 0 && (
              <div className="p-8 text-center text-slate-500">
                No staff found matching your search.
              </div>
            )}
        </div>
      </div>

       {/* View Employee Modal */}
       {isViewModalOpen && viewingEmployee && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
            <div className="bg-white rounded-xl shadow-2xl w-full max-w-lg overflow-hidden animate-in fade-in zoom-in duration-200">
                <div className="relative h-32 bg-slate-900">
                     <button 
                        onClick={() => setIsViewModalOpen(false)}
                        className="absolute top-4 right-4 text-white/70 hover:text-white bg-black/20 hover:bg-black/40 p-2 rounded-full backdrop-blur-sm transition-all"
                    >
                        <X size={20} />
                    </button>
                </div>
                <div className="px-6 pb-6 -mt-16">
                    <div className="flex flex-col items-center">
                         <div className="w-32 h-32 rounded-full bg-white p-1 shadow-xl">
                             <div className="w-full h-full rounded-full bg-slate-100 flex items-center justify-center overflow-hidden text-2xl font-bold text-slate-400">
                                {viewingEmployee.photo ? (
                                    <img src={viewingEmployee.photo} alt="" className="w-full h-full object-cover" />
                                ) : (
                                    <span>{viewingEmployee.firstName[0]}{viewingEmployee.lastName[0]}</span>
                                )}
                             </div>
                         </div>
                         <h2 className="text-2xl font-bold text-slate-800 mt-4">{viewingEmployee.firstName} {viewingEmployee.lastName}</h2>
                         <p className="text-blue-600 font-medium">{viewingEmployee.role}</p>
                         <div className="flex items-center gap-2 text-slate-500 text-sm mt-1">
                             <Building size={14} />
                             {viewingEmployee.department}
                         </div>
                    </div>

                    <div className="mt-8 space-y-4">
                        <div className="grid grid-cols-2 gap-4">
                            <div className="p-3 bg-slate-50 rounded-lg">
                                <p className="text-xs text-slate-500 uppercase font-bold tracking-wider mb-1">Staff ID</p>
                                <p className="font-mono text-slate-700">{viewingEmployee.id}</p>
                            </div>
                            <div className="p-3 bg-slate-50 rounded-lg">
                                <p className="text-xs text-slate-500 uppercase font-bold tracking-wider mb-1">Joined</p>
                                <p className="text-slate-700">{viewingEmployee.joinDate}</p>
                            </div>
                        </div>

                        <div className="p-4 border border-slate-100 rounded-xl space-y-3">
                             <div className="flex items-center gap-3">
                                 <div className="p-2 bg-blue-50 text-blue-600 rounded-lg">
                                     <Mail size={18} />
                                 </div>
                                 <div>
                                     <p className="text-xs text-slate-500">Email Address</p>
                                     <a href={`mailto:${viewingEmployee.email}`} className="text-sm font-medium text-slate-800 hover:text-blue-600">{viewingEmployee.email}</a>
                                 </div>
                             </div>
                             <div className="flex items-center gap-3">
                                 <div className="p-2 bg-blue-50 text-blue-600 rounded-lg">
                                     <Phone size={18} />
                                 </div>
                                 <div>
                                     <p className="text-xs text-slate-500">Phone Number</p>
                                     <a href={`tel:${viewingEmployee.phone}`} className="text-sm font-medium text-slate-800 hover:text-blue-600">{viewingEmployee.phone}</a>
                                 </div>
                             </div>
                        </div>

                        <div className="flex gap-3 mt-6">
                            <button 
                                onClick={(e) => { setIsViewModalOpen(false); handleEditClick(e, viewingEmployee); }}
                                className="flex-1 py-2.5 bg-blue-600 text-white rounded-lg font-medium hover:bg-blue-700 transition-colors"
                            >
                                Edit Profile
                            </button>
                             <button 
                                onClick={(e) => { setIsViewModalOpen(false); handleDeleteClick(e, viewingEmployee.id); }}
                                className="flex-1 py-2.5 bg-white border border-slate-200 text-slate-700 rounded-lg font-medium hover:bg-slate-50 hover:text-red-600 transition-colors"
                            >
                                Delete
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        </div>
       )}

       {/* Add/Edit Staff Modal */}
       {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
          <div className="bg-white rounded-xl shadow-2xl w-full max-w-lg overflow-hidden animate-in fade-in zoom-in duration-200 flex flex-col max-h-[90vh]">
            <div className="flex justify-between items-center p-6 border-b border-slate-100 bg-slate-50">
              <h3 className="text-lg font-bold text-slate-800">{editingEmployeeId ? 'Edit Staff Member' : 'Add New Staff Member'}</h3>
              <button 
                onClick={() => setIsModalOpen(false)}
                className="text-slate-400 hover:text-slate-600 transition-colors"
              >
                <X size={20} />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="p-6 space-y-4 overflow-y-auto custom-scrollbar">

              {/* Photo Upload */}
              <div className="flex flex-col items-center justify-center mb-6">
                <div className="w-24 h-24 bg-slate-100 rounded-full border-2 border-dashed border-slate-300 flex items-center justify-center overflow-hidden relative group transition-colors hover:border-blue-400">
                    {formData.photo ? (
                        <img src={formData.photo} alt="Preview" className="w-full h-full object-cover" />
                    ) : (
                        <User size={32} className="text-slate-400" />
                    )}
                    <label className="absolute inset-0 flex flex-col items-center justify-center bg-black/50 opacity-0 group-hover:opacity-100 transition-opacity cursor-pointer text-white text-xs font-medium">
                        <Upload size={20} className="mb-1" />
                        <span>Upload</span>
                        <input type="file" accept="image/*" className="hidden" onChange={handlePhotoChange} />
                    </label>
                </div>
                <p className="text-xs text-slate-500 mt-2">Passport Photo</p>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-sm font-medium text-slate-700">First Name</label>
                  <input 
                    name="firstName"
                    required
                    value={formData.firstName}
                    onChange={handleInputChange}
                    className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all text-sm"
                    placeholder="e.g. Samuel"
                  />
                </div>
                <div className="space-y-1.5">
                  <label className="text-sm font-medium text-slate-700">Last Name</label>
                  <input 
                    name="lastName"
                    required
                    value={formData.lastName}
                    onChange={handleInputChange}
                    className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all text-sm"
                    placeholder="e.g. Adjei"
                  />
                </div>
              </div>

              <div className="space-y-1.5">
                <label className="text-sm font-medium text-slate-700">Staff ID {editingEmployeeId && '(Read Only)'}</label>
                <input 
                  name="id"
                  value={formData.id}
                  readOnly={!!editingEmployeeId}
                  onChange={handleInputChange}
                  className={`w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all text-sm ${editingEmployeeId ? 'bg-slate-50 cursor-not-allowed text-slate-500' : ''}`}
                  placeholder="Will be auto-generated if left blank"
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-sm font-medium text-slate-700">Department</label>
                  <select 
                    name="department"
                    required
                    value={formData.department}
                    onChange={handleInputChange}
                    className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all text-sm"
                  >
                    <option value="">Select Dept</option>
                    <option value="Administration">Administration</option>
                    <option value="Academic Affairs">Academic Affairs</option>
                    <option value="Mathematics">Mathematics</option>
                    <option value="Science">Science</option>
                    <option value="Education">Education</option>
                    <option value="ICT">ICT</option>
                  </select>
                </div>
                <div className="space-y-1.5">
                  <label className="text-sm font-medium text-slate-700">Role / Job Title</label>
                  <input 
                    name="role"
                    required
                    value={formData.role}
                    onChange={handleInputChange}
                    className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all text-sm"
                    placeholder="e.g. Lecturer"
                  />
                </div>
              </div>

               <div className="grid grid-cols-2 gap-4">
                 <div className="space-y-1.5">
                  <label className="text-sm font-medium text-slate-700">Phone Number</label>
                  <input 
                    type="tel"
                    name="phone"
                    required
                    value={formData.phone}
                    onChange={handleInputChange}
                    className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all text-sm"
                    placeholder="024xxxxxxx"
                  />
                </div>
                 <div className="space-y-1.5">
                  <label className="text-sm font-medium text-slate-700">Date Joined</label>
                  <input 
                    type="date"
                    name="joinDate"
                    required
                    value={formData.joinDate}
                    onChange={handleInputChange}
                    className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all text-sm"
                  />
                </div>
              </div>

              {!editingEmployeeId && (
                <div className="p-4 bg-yellow-50 border border-yellow-100 rounded-lg flex gap-3 items-start">
                    <Mail className="text-yellow-600 mt-0.5 flex-shrink-0" size={16} />
                    <div>
                        <p className="text-xs font-bold text-yellow-800">Email Provisioning</p>
                        <p className="text-xs text-yellow-700 mt-0.5">
                            An institutional email will be requested from IT automatically upon creating this profile. You do not need to enter one.
                        </p>
                    </div>
                </div>
              )}

              <div className="pt-2 flex justify-end gap-3 sticky bottom-0 bg-white border-t border-slate-100 mt-auto">
                <button 
                  type="button"
                  onClick={() => setIsModalOpen(false)}
                  className="px-4 py-2 border border-slate-200 text-slate-600 rounded-lg hover:bg-slate-50 transition-colors text-sm font-medium"
                >
                  Cancel
                </button>
                <button 
                  type="submit"
                  className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors text-sm font-medium shadow-sm"
                >
                  {editingEmployeeId ? 'Save Changes' : 'Add Staff Member'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default StaffDirectory;

import React, { useState } from 'react';
import { MOCK_EMPLOYEES } from '../constants';
import { Employee } from '../types';
import { Search, Plus, Filter, MoreHorizontal, Mail, Phone, X, CheckCircle, Send, Upload, User, Edit2, Trash2, Eye, Building } from 'lucide-react';

const StaffDirectory: React.FC = () => {
  const [employees, setEmployees] = useState<Employee[]>(MOCK_EMPLOYEES);
  const [searchTerm, setSearchTerm] = useState('');

  // Modal States
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isViewModalOpen, setIsViewModalOpen] = useState(false);

  const [notification, setNotification] = useState<{show: boolean, ticketId: string | null, count?: number}>({ show: false, ticketId: null });
  const [selectedIds, setSelectedIds] = useState<string[]>([]);

  // Selection States
  const [viewingEmployee, setViewingEmployee] = useState<Employee | null>(null);
  const [editingEmployeeId, setEditingEmployeeId] = useState<string | null>(null);

  // Form State
  const [formData, setFormData] = useState<Partial<Employee>>({
    firstName: '',
    lastName: '',
    id: '',
    department: '',
    role: '',
    phone: '',
    joinDate: new Date().toISOString().split('T')[0],
    photo: undefined
  });

  const filteredEmployees = employees.filter(emp =>
    emp.lastName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    emp.firstName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    emp.department.toLowerCase().includes(searchTerm.toLowerCase()) ||
    emp.role.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handlePhotoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      const photoUrl = URL.createObjectURL(file);
      setFormData(prev => ({ ...prev, photo: photoUrl }));
    }
  };

  const handleSelectAll = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.checked) {
      setSelectedIds(filteredEmployees.map(emp => emp.id));
    } else {
      setSelectedIds([]);
    }
  };

  const handleSelectOne = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    setSelectedIds(prev => 
      prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]
    );
  };

  const handleBulkEmail = () => {
    if (selectedIds.length === 0) return;
    const ticketId = `IT-BULK-${Math.floor(1000 + Math.random() * 9000)}`;
    setNotification({ show: true, ticketId, count: selectedIds.length });
    setSelectedIds([]);
    setTimeout(() => setNotification({ show: false, ticketId: null }), 6000);
  };

  // --- Action Handlers ---

  const handleAddClick = () => {
    setEditingEmployeeId(null);
    setFormData({
      firstName: '',
      lastName: '',
      id: '',
      department: '',
      role: '',
      phone: '',
      joinDate: new Date().toISOString().split('T')[0],
      photo: undefined
    });
    setIsModalOpen(true);
  };

  const handleEditClick = (e: React.MouseEvent, emp: Employee) => {
    e.stopPropagation();
    setEditingEmployeeId(emp.id);
    setFormData(emp);
    setIsModalOpen(true);
  };

  const handleDeleteClick = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (window.confirm("Are you sure you want to delete this staff member? This action cannot be undone.")) {
      setEmployees(prev => prev.filter(emp => emp.id !== id));
      if (viewingEmployee?.id === id) {
        setIsViewModalOpen(false);
        setViewingEmployee(null);
      }
    }
  };

  const handleRowClick = (emp: Employee) => {
    setViewingEmployee(emp);
    setIsViewModalOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (editingEmployeeId) {
      // Update existing
      setEmployees(prev => prev.map(emp => 
        emp.id === editingEmployeeId ? { ...emp, ...formData } as Employee : emp
      ));
    } else {
      // Create new
      const ticketId = `IT-${Math.floor(1000 + Math.random() * 9000)}`;
      const newEmployee: Employee = {
        ...formData as Employee,
        id: formData.id || `EMP-${Math.floor(Math.random() * 1000)}`,
        email: formData.email || 'pending.verification@ola.edu.gh'
      };
      setEmployees(prev => [newEmployee, ...prev]);
      setNotification({ show: true, ticketId, count: 1 });
      setTimeout(() => setNotification({ show: false, ticketId: null }), 6000);
    }

    setIsModalOpen(false);
    setEditingEmployeeId(null);
    setFormData({
      firstName: '',
      lastName: '',
      id: '',
      department: '',
      role: '',
      phone: '',
      joinDate: new Date().toISOString().split('T')[0],
      photo: undefined
    });
  };

  return (
    <div className="space-y-6 relative">
      {/* Notification Toast */}
      {notification.show && (
        <div className="fixed top-24 right-8 z-50 animate-in slide-in-from-right duration-300">
           <div className="bg-white border-l-4 border-green-500 rounded-lg shadow-xl p-4 flex items-start gap-3 max-w-md">
              <div className="text-green-500 p-1">
                <CheckCircle size={24} />
              </div>
              <div>
                <h4 className="font-bold text-slate-800">Success</h4>
                <p className="text-sm text-slate-600 mt-1">
                  Ticket <span className="font-mono font-bold text-slate-800">#{notification.ticketId}</span> created.
                  {notification.count && notification.count > 1 
                    ? ` Processing ${notification.count} staff members.`
                    : ' IT has been notified.'
                  }
                </p>
              </div>
              <button 
                onClick={() => setNotification({ show: false, ticketId: null })}
                className="text-slate-400 hover:text-slate-600 ml-auto"
              >
                <X size={16} />
              </button>
           </div>
        </div>
      )}

      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <h2 className="text-2xl font-bold text-slate-800">Staff Directory</h2>
        <div className="flex items-center gap-3 w-full sm:w-auto">
          {selectedIds.length > 0 && (
            <button 
              onClick={handleBulkEmail}
              className="bg-indigo-600 hover:bg-indigo-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition-colors shadow-sm animate-in fade-in zoom-in duration-200 text-sm"
            >
              <Send size={18} />
              <span className="hidden sm:inline">Bulk Email IT ({selectedIds.length})</span>
            </button>
          )}
          <button 
            onClick={handleAddClick}
            className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition-colors shadow-sm text-sm ml-auto sm:ml-0"
          >
            <Plus size={18} />
            <span>Add New Staff</span>
          </button>
        </div>
      </div>

      {/* Filters and Search */}
      <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-100 flex flex-col sm:flex-row gap-4 justify-between items-center">
        <div className="relative w-full sm:w-96">
          <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400" size={18} />
          <input
            type="text"
            placeholder="Search staff by name, role or dept..."
            className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent text-sm"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
        <div className="flex gap-2 w-full sm:w-auto">
          <button className="flex items-center gap-2 px-3 py-2 border border-slate-200 rounded-lg text-slate-600 hover:bg-slate-50 text-sm">
            <Filter size={16} />
            Filter
          </button>
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm">
            <thead className="bg-slate-50 border-b border-slate-200">
              <tr>
                <th className="px-6 py-4 w-12">
                   <input 
                    type="checkbox" 
                    className="rounded border-slate-300 text-blue-600 focus:ring-blue-500 h-4 w-4"
                    checked={filteredEmployees.length > 0 && selectedIds.length === filteredEmployees.length}
                    onChange={handleSelectAll}
                  />
                </th>
                <th className="px-6 py-4 font-semibold text-slate-600">Employee</th>
                <th className="px-6 py-4 font-semibold text-slate-600">Role & Dept</th>
                <th className="px-6 py-4 font-semibold text-slate-600">Contact</th>
                <th className="px-6 py-4 font-semibold text-slate-600">Join Date</th>
                <th className="px-6 py-4 font-semibold text-slate-600 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredEmployees.map((emp) => (
                <tr 
                  key={emp.id} 
                  onClick={() => handleRowClick(emp)}
                  className={`hover:bg-slate-50 transition-colors cursor-pointer ${selectedIds.includes(emp.id) ? 'bg-blue-50/30' : ''}`}
                >
                  <td className="px-6 py-4" onClick={(e) => e.stopPropagation()}>
                     <input 
                      type="checkbox" 
                      className="rounded border-slate-300 text-blue-600 focus:ring-blue-500 h-4 w-4 cursor-pointer"
                      checked={selectedIds.includes(emp.id)}
                      onClick={(e) => handleSelectOne(e, emp.id)}
                      onChange={() => {}} // Handled by onClick to prevent propagation issues
                    />
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-3">
                      <div className="w-10 h-10 rounded-full bg-indigo-100 text-indigo-600 flex items-center justify-center font-bold text-sm overflow-hidden flex-shrink-0">
                         {emp.photo ? (
                            <img src={emp.photo} alt={`${emp.firstName} ${emp.lastName}`} className="w-full h-full object-cover" />
                         ) : (
                            <span>{emp.firstName[0]}{emp.lastName[0]}</span>
                         )}
                      </div>
                      <div>
                        <p className="font-medium text-slate-900">{emp.firstName} {emp.lastName}</p>
                        <p className="text-xs text-slate-500">{emp.id}</p>
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div>
                      <p className="text-slate-900 font-medium">{emp.role}</p>
                      <p className="text-slate-500 text-xs">{emp.department}</p>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex flex-col gap-1">
                      <div className="flex items-center gap-2 text-slate-600 text-xs">
                        <Mail size={12} />
                        {emp.email}
                      </div>
                      <div className="flex items-center gap-2 text-slate-600 text-xs">
                        <Phone size={12} />
                        {emp.phone}
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-slate-600">
                    {emp.joinDate}
                  </td>
                  <td className="px-6 py-4 text-right">
                    <div className="flex justify-end gap-2">
                        <button 
                            onClick={(e) => handleEditClick(e, emp)}
                            className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                            title="Edit Details"
                        >
                            <Edit2 size={16} />
                        </button>
                        <button 
                            onClick={(e) => handleDeleteClick(e, emp.id)}
                            className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                            title="Delete Staff"
                        >
                            <Trash2 size={16} />
                        </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
           {filteredEmployees.length === 0 && (
              <div className="p-8 text-center text-slate-500">
                No staff found matching your search.
              </div>
            )}
        </div>
      </div>

       {/* View Employee Modal */}
       {isViewModalOpen && viewingEmployee && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
            <div className="bg-white rounded-xl shadow-2xl w-full max-w-lg overflow-hidden animate-in fade-in zoom-in duration-200">
                <div className="relative h-32 bg-slate-900">
                     <button 
                        onClick={() => setIsViewModalOpen(false)}
                        className="absolute top-4 right-4 text-white/70 hover:text-white bg-black/20 hover:bg-black/40 p-2 rounded-full backdrop-blur-sm transition-all"
                    >
                        <X size={20} />
                    </button>
                </div>
                <div className="px-6 pb-6 -mt-16">
                    <div className="flex flex-col items-center">
                         <div className="w-32 h-32 rounded-full bg-white p-1 shadow-xl">
                             <div className="w-full h-full rounded-full bg-slate-100 flex items-center justify-center overflow-hidden text-2xl font-bold text-slate-400">
                                {viewingEmployee.photo ? (
                                    <img src={viewingEmployee.photo} alt="" className="w-full h-full object-cover" />
                                ) : (
                                    <span>{viewingEmployee.firstName[0]}{viewingEmployee.lastName[0]}</span>
                                )}
                             </div>
                         </div>
                         <h2 className="text-2xl font-bold text-slate-800 mt-4">{viewingEmployee.firstName} {viewingEmployee.lastName}</h2>
                         <p className="text-blue-600 font-medium">{viewingEmployee.role}</p>
                         <div className="flex items-center gap-2 text-slate-500 text-sm mt-1">
                             <Building size={14} />
                             {viewingEmployee.department}
                         </div>
                    </div>

                    <div className="mt-8 space-y-4">
                        <div className="grid grid-cols-2 gap-4">
                            <div className="p-3 bg-slate-50 rounded-lg">
                                <p className="text-xs text-slate-500 uppercase font-bold tracking-wider mb-1">Staff ID</p>
                                <p className="font-mono text-slate-700">{viewingEmployee.id}</p>
                            </div>
                            <div className="p-3 bg-slate-50 rounded-lg">
                                <p className="text-xs text-slate-500 uppercase font-bold tracking-wider mb-1">Joined</p>
                                <p className="text-slate-700">{viewingEmployee.joinDate}</p>
                            </div>
                        </div>

                        <div className="p-4 border border-slate-100 rounded-xl space-y-3">
                             <div className="flex items-center gap-3">
                                 <div className="p-2 bg-blue-50 text-blue-600 rounded-lg">
                                     <Mail size={18} />
                                 </div>
                                 <div>
                                     <p className="text-xs text-slate-500">Email Address</p>
                                     <a href={`mailto:${viewingEmployee.email}`} className="text-sm font-medium text-slate-800 hover:text-blue-600">{viewingEmployee.email}</a>
                                 </div>
                             </div>
                             <div className="flex items-center gap-3">
                                 <div className="p-2 bg-blue-50 text-blue-600 rounded-lg">
                                     <Phone size={18} />
                                 </div>
                                 <div>
                                     <p className="text-xs text-slate-500">Phone Number</p>
                                     <a href={`tel:${viewingEmployee.phone}`} className="text-sm font-medium text-slate-800 hover:text-blue-600">{viewingEmployee.phone}</a>
