              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-sm font-medium text-slate-700">First Name</label>
                  <input 
                    name="firstName"
                    required
                    value={formData.firstName}
                    onChange={handleInputChange}
                    className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all text-sm"
                    placeholder="e.g. Samuel"
                  />
                </div>
                <div className="space-y-1.5">
                  <label className="text-sm font-medium text-slate-700">Last Name</label>
                  <input 
                    name="lastName"
                    required
                    value={formData.lastName}
                    onChange={handleInputChange}
                    className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all text-sm"
                    placeholder="e.g. Adjei"
                  />
                </div>
              </div>

              <div className="space-y-1.5">
                <label className="text-sm font-medium text-slate-700">Staff ID {editingEmployeeId && '(Read Only)'}</label>
                <input 
                  name="id"
                  value={formData.id}
                  readOnly={!!editingEmployeeId}
                  onChange={handleInputChange}
                  className={`w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all text-sm ${editingEmployeeId ? 'bg-slate-50 cursor-not-allowed text-slate-500' : ''}`}
                  placeholder="Will be auto-generated if left blank"
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-sm font-medium text-slate-700">Department</label>
                  <select 
                    name="department"
                    required
                    value={formData.department}
                    onChange={handleInputChange}
                    className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all text-sm"
                  >
                    <option value="">Select Dept</option>
                    <option value="Administration">Administration</option>
                    <option value="Academic Affairs">Academic Affairs</option>
                    <option value="Mathematics">Mathematics</option>
                    <option value="Science">Science</option>
                    <option value="Education">Education</option>
                    <option value="ICT">ICT</option>
                  </select>
                </div>
                <div className="space-y-1.5">
                  <label className="text-sm font-medium text-slate-700">Role / Job Title</label>
                  <input 
                    name="role"
                    required
                    value={formData.role}
                    onChange={handleInputChange}
                    className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all text-sm"
                    placeholder="e.g. Lecturer"
                  />
                </div>
              </div>

               <div className="grid grid-cols-2 gap-4">
                 <div className="space-y-1.5">
                  <label className="text-sm font-medium text-slate-700">Phone Number</label>
                  <input 
                    type="tel"
                    name="phone"
                    required
                    value={formData.phone}
                    onChange={handleInputChange}
                    className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all text-sm"
                    placeholder="024xxxxxxx"
                  />
                </div>
                 <div className="space-y-1.5">
                  <label className="text-sm font-medium text-slate-700">Date Joined</label>
                  <input 
                    type="date"
                    name="joinDate"
                    required
                    value={formData.joinDate}
                    onChange={handleInputChange}
                    className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all text-sm"
                  />
                </div>
              </div>

              {!editingEmployeeId && (
                <div className="p-4 bg-yellow-50 border border-yellow-100 rounded-lg flex gap-3 items-start">
                    <Mail className="text-yellow-600 mt-0.5 flex-shrink-0" size={16} />
                    <div>
                        <p className="text-xs font-bold text-yellow-800">Email Provisioning</p>
                        <p className="text-xs text-yellow-700 mt-0.5">
                            An institutional email will be requested from IT automatically upon creating this profile. You do not need to enter one.
                        </p>
                    </div>
                </div>
              )}

              <div className="pt-2 flex justify-end gap-3 sticky bottom-0 bg-white border-t border-slate-100 mt-auto">
                <button 
                  type="button"
                  onClick={() => setIsModalOpen(false)}
                  className="px-4 py-2 border border-slate-200 text-slate-600 rounded-lg hover:bg-slate-50 transition-colors text-sm font-medium"
                >
                  Cancel
                </button>
                <button 
                  type="submit"
                  className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors text-sm font-medium shadow-sm"
                >
                  {editingEmployeeId ? 'Save Changes' : 'Add Staff Member'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default StaffDirectory;

import React from 'react';

export enum UserRole {
  ADMIN = 'ADMIN',
  STAFF = 'STAFF',
  STUDENT = 'STUDENT'
}

export enum LeaveStatus {
  PENDING = 'PENDING',
  APPROVED = 'APPROVED',
  REJECTED = 'REJECTED'
}

export enum LeaveType {
  SICK = 'SICK',
  CASUAL = 'CASUAL',
  MATERNITY = 'MATERNITY',
  STUDY = 'STUDY',
  ANNUAL = 'ANNUAL'
}

export interface Student {
  id: string;
  firstName: string;
  lastName: string;
  email: string;
  program: string;
  year: number; // 1, 2, 3, 4
  enrollmentDate: string;
  status: 'Active' | 'Graduated' | 'Suspended';
  gpa: number;
  photo?: string;
}

export interface Education {
  id: string;
  degree: string;
  institution: string;
  admissionYear: string;
  completionYear: string;
  referenceNumber: string;
  certificateUrl?: string;
}

export interface EmergencyContact {
  name: string;
  relation: string;
  email: string;
  phone: string;
}

export interface NextOfKin {
  name: string;
  relation: string;
  phone: string;
  address: string;
}

export interface Employee {
  id: string;
  firstName: string;
  lastName: string;
  department: string;
  role: string;
  email: string;
  phone: string;
  joinDate: string;
  photo?: string;
  // Extended fields
  personalEmail?: string;
  houseAddress?: string;
  boxAddress?: string;
  education?: Education[];
  emergencyContact?: EmergencyContact;
  nextOfKin?: NextOfKin;
}

export interface LeaveRequest {
  id: string;
  employeeId: string;
  employeeName: string;
  type: LeaveType;
  startDate: string;
  endDate: string;
  reason: string;
  status: LeaveStatus;
  requestDate: string;
}

export interface MenuItem {
  id: string;
  label: string;
  icon: React.ReactNode;
}

// --- New Settings & Auth Types ---

export interface Department {
  id: string;
  name: string;
  headOfDept?: string; // Employee Name or ID
  description?: string;
}

export interface Role {
  id: string;
  name: string;
  description: string;
  permissions: string[]; // e.g., ['read:leave', 'write:student']
}

export interface SystemUser {
  id: string;
  username: string;
  password?: string; // In a real app, this would be hashed. For demo, plain text or masked.
  employeeId: string; // Links to Employee record
  roleId: string;
  isActive: boolean;
  lastLogin?: string;
}

export interface AuthContextType {
  user: SystemUser | null;
  login: (user: SystemUser) => void;
  logout: () => void;
}

import React, { useState, useEffect } from 'react';
import { MOCK_EMPLOYEES } from '../constants';
import { Employee, Education, EmergencyContact, NextOfKin } from '../types';
import { Search, Plus, Filter, MoreHorizontal, Mail, Phone, X, CheckCircle, Send, Upload, User, Edit2, Trash2, Eye, Building, GraduationCap, ArrowRight, ArrowLeft, Save } from 'lucide-react';

const StaffDirectory: React.FC = () => {
  const [employees, setEmployees] = useState<Employee[]>(MOCK_EMPLOYEES);
  const [searchTerm, setSearchTerm] = useState('');

  // Modal States
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isViewModalOpen, setIsViewModalOpen] = useState(false);
  const [currentStep, setCurrentStep] = useState(1);

  const [notification, setNotification] = useState<{show: boolean, ticketId: string | null, count?: number}>({ show: false, ticketId: null });
  const [selectedIds, setSelectedIds] = useState<string[]>([]);

  // Selection States
  const [viewingEmployee, setViewingEmployee] = useState<Employee | null>(null);
  const [editingEmployeeId, setEditingEmployeeId] = useState<string | null>(null);

  // Initial Empty State
  const initialFormState: Partial<Employee> = {
    firstName: '',
    lastName: '',
    id: '',
    department: '',
    role: '',
    phone: '',
    email: '', // Institutional email
    joinDate: new Date().toISOString().split('T')[0],
    photo: undefined,
    personalEmail: '',
    houseAddress: '',
    boxAddress: '',
    education: [],
    emergencyContact: { name: '', relation: '', email: '', phone: '' },
    nextOfKin: { name: '', relation: '', phone: '', address: '' }
  };

  const [formData, setFormData] = useState<Partial<Employee>>(initialFormState);

  // Temporary state for adding a single education record
  const [eduForm, setEduForm] = useState<Partial<Education>>({
    degree: '',
    institution: '',
    admissionYear: '',
    completionYear: '',
    referenceNumber: ''
  });

  // Load draft on open if creating new
  useEffect(() => {
    if (isModalOpen && !editingEmployeeId) {
        const savedDraft = localStorage.getItem('new_staff_draft');
        if (savedDraft) {
            try {
                const parsed = JSON.parse(savedDraft);
                // Ask user if they want to resume? For now, just load it if it exists and id matches or is empty
                if(window.confirm("Found a saved draft for a new staff member. Would you like to continue?")) {
                    setFormData(parsed);
                } else {
                    localStorage.removeItem('new_staff_draft');
                    generateNewId();
                }
            } catch (e) {
                console.error("Failed to load draft", e);
            }
        } else {
             generateNewId();
        }
    }
  }, [isModalOpen]);

  const generateNewId = () => {
     if(!formData.id) {
         setFormData(prev => ({...prev, id: `EMP-${Math.floor(10000 + Math.random() * 90000)}`}));
     }
  };

  const saveDraft = () => {
      if (!editingEmployeeId) {
          localStorage.setItem('new_staff_draft', JSON.stringify(formData));
      }
  };

  const filteredEmployees = employees.filter(emp =>
    emp.lastName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    emp.firstName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    emp.department.toLowerCase().includes(searchTerm.toLowerCase()) ||
    emp.role.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  // Nested input handlers
  const handleEmergencyChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
      const { name, value } = e.target;
      setFormData(prev => ({
          ...prev,
          emergencyContact: { ...prev.emergencyContact!, [name]: value }
      }));
  };

  const handleNextOfKinChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
      const { name, value } = e.target;
      setFormData(prev => ({
          ...prev,
          nextOfKin: { ...prev.nextOfKin!, [name]: value }
      }));
  };

  const handlePhotoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      const photoUrl = URL.createObjectURL(file);
      setFormData(prev => ({ ...prev, photo: photoUrl }));
    }
  };

  const handleAddEducation = () => {
      if(!eduForm.degree || !eduForm.institution) return;

      const newEdu: Education = {
          id: Date.now().toString(),
          degree: eduForm.degree!,
          institution: eduForm.institution!,
          admissionYear: eduForm.admissionYear || '',
          completionYear: eduForm.completionYear || '',
          referenceNumber: eduForm.referenceNumber || '',
          certificateUrl: eduForm.certificateUrl
      };

      setFormData(prev => ({
          ...prev,
          education: [...(prev.education || []), newEdu]
      }));

      // Reset edu form
      setEduForm({
        degree: '',
        institution: '',
        admissionYear: '',
        completionYear: '',
        referenceNumber: '',
        certificateUrl: undefined
      });
  };

  const handleRemoveEducation = (id: string) => {
      setFormData(prev => ({
          ...prev,
          education: prev.education?.filter(e => e.id !== id)
      }));
  };

  // --- Actions ---

  const handleSelectAll = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.checked) {
      setSelectedIds(filteredEmployees.map(emp => emp.id));
    } else {
      setSelectedIds([]);
    }
  };

  const handleSelectOne = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    setSelectedIds(prev => 
      prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]
    );
  };

  const handleAddClick = () => {
    setEditingEmployeeId(null);
    setFormData(initialFormState);
    setCurrentStep(1);
    setIsModalOpen(true);
  };

  const handleEditClick = (e: React.MouseEvent, emp: Employee) => {
    e.stopPropagation();
    setEditingEmployeeId(emp.id);
    setFormData({
        ...emp,
        education: emp.education || [],
        emergencyContact: emp.emergencyContact || { name: '', relation: '', email: '', phone: '' },
        nextOfKin: emp.nextOfKin || { name: '', relation: '', phone: '', address: '' }
    });
    setCurrentStep(1);
    setIsModalOpen(true);
  };

  const handleDeleteClick = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (window.confirm("Are you sure you want to delete this staff member? This action cannot be undone.")) {
      setEmployees(prev => prev.filter(emp => emp.id !== id));
      if (viewingEmployee?.id === id) {
        setIsViewModalOpen(false);
        setViewingEmployee(null);
      }
    }
  };

  const handleRowClick = (emp: Employee) => {
    setViewingEmployee(emp);
    setIsViewModalOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    // Auto-generate institutional email if missing
    const finalEmail = formData.email || `${formData.firstName?.charAt(0).toLowerCase()}.${formData.lastName?.toLowerCase()}@ola.edu.gh`;

    const finalData: Employee = {
        ...formData as Employee,
        email: finalEmail
    };

    if (editingEmployeeId) {
      setEmployees(prev => prev.map(emp => 
        emp.id === editingEmployeeId ? finalData : emp
      ));
    } else {
      setEmployees(prev => [finalData, ...prev]);
      localStorage.removeItem('new_staff_draft'); // Clear draft
    }

    setIsModalOpen(false);
    setEditingEmployeeId(null);
    setFormData(initialFormState);

    // Show success notification
    setNotification({ show: true, ticketId: null });
    setTimeout(() => setNotification({ show: false, ticketId: null }), 3000);
  };

  const nextStep = () => {
      saveDraft();
      setCurrentStep(prev => prev + 1);
  };

  const prevStep = () => setCurrentStep(prev => prev - 1);

  // --- Wizard Steps ---

  const renderStep1_BasicInfo = () => (
      <div className="space-y-4 animate-in fade-in slide-in-from-right-4 duration-300">
          <div className="flex flex-col items-center justify-center mb-6">
                <div className="w-24 h-24 bg-slate-100 rounded-full border-2 border-dashed border-slate-300 flex items-center justify-center overflow-hidden relative group transition-colors hover:border-blue-400">
                    {formData.photo ? (
                        <img src={formData.photo} alt="Preview" className="w-full h-full object-cover" />
                    ) : (
                        <User size={32} className="text-slate-400" />
                    )}
                    <label className="absolute inset-0 flex flex-col items-center justify-center bg-black/50 opacity-0 group-hover:opacity-100 transition-opacity cursor-pointer text-white text-xs font-medium">
                        <Upload size={20} className="mb-1" />
                        <span>Upload</span>
                        <input type="file" accept="image/*" className="hidden" onChange={handlePhotoChange} />
                    </label>
                </div>
                <p className="text-xs text-slate-500 mt-2">Passport Photo</p>
          </div>

          <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1">
                  <label className="text-xs font-semibold text-slate-600">First Name <span className="text-red-500">*</span></label>
                  <input name="firstName" value={formData.firstName} onChange={handleInputChange} className="w-full px-3 py-2 border rounded-lg text-sm" placeholder="e.g. Samuel" />
              </div>
              <div className="space-y-1">
                  <label className="text-xs font-semibold text-slate-600">Last Name <span className="text-red-500">*</span></label>
                  <input name="lastName" value={formData.lastName} onChange={handleInputChange} className="w-full px-3 py-2 border rounded-lg text-sm" placeholder="e.g. Adjei" />
              </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
               <div className="space-y-1">
                  <label className="text-xs font-semibold text-slate-600">Staff ID (Auto)</label>
                  <input name="id" value={formData.id} readOnly className="w-full px-3 py-2 border rounded-lg text-sm bg-slate-50 text-slate-500" />
               </div>
               <div className="space-y-1">
                  <label className="text-xs font-semibold text-slate-600">Department <span className="text-red-500">*</span></label>
                  <select name="department" value={formData.department} onChange={handleInputChange} className="w-full px-3 py-2 border rounded-lg text-sm">
                        <option value="">Select Dept</option>
                        <option value="Administration">Administration</option>
                        <option value="Academic Affairs">Academic Affairs</option>
                        <option value="Mathematics">Mathematics</option>
                        <option value="Science">Science</option>
                        <option value="Education">Education</option>
                        <option value="ICT">ICT</option>
                  </select>
               </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
               <div className="space-y-1">
                  <label className="text-xs font-semibold text-slate-600">Role / Job Title <span className="text-red-500">*</span></label>
                  <input name="role" value={formData.role} onChange={handleInputChange} className="w-full px-3 py-2 border rounded-lg text-sm" placeholder="e.g. Senior Lecturer" />
               </div>
               <div className="space-y-1">
                  <label className="text-xs font-semibold text-slate-600">Date Joined <span className="text-red-500">*</span></label>
                  <input type="date" name="joinDate" value={formData.joinDate} onChange={handleInputChange} className="w-full px-3 py-2 border rounded-lg text-sm" />
               </div>
          </div>

          <hr className="border-slate-100" />
          <h4 className="text-sm font-bold text-slate-700">Contact Information</h4>

          <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1">
                  <label className="text-xs font-semibold text-slate-600">Phone Number <span className="text-red-500">*</span></label>
                  <input type="tel" name="phone" value={formData.phone} onChange={handleInputChange} className="w-full px-3 py-2 border rounded-lg text-sm" placeholder="024xxxxxxx" />
              </div>
              <div className="space-y-1">
                  <label className="text-xs font-semibold text-slate-600">Personal Email</label>
                  <input type="email" name="personalEmail" value={formData.personalEmail} onChange={handleInputChange} className="w-full px-3 py-2 border rounded-lg text-sm" placeholder="personal@gmail.com" />
              </div>
          </div>

          <div className="space-y-1">
              <label className="text-xs font-semibold text-slate-600">House Address</label>
              <input name="houseAddress" value={formData.houseAddress} onChange={handleInputChange} className="w-full px-3 py-2 border rounded-lg text-sm" placeholder="Hse No. 123, Street Name, City" />
          </div>
           <div className="space-y-1">
              <label className="text-xs font-semibold text-slate-600">Box Address</label>
              <input name="boxAddress" value={formData.boxAddress} onChange={handleInputChange} className="w-full px-3 py-2 border rounded-lg text-sm" placeholder="P.O. Box 45, Cape Coast" />
          </div>
      </div>
  );

  const renderStep2_Education = () => (
      <div className="space-y-6 animate-in fade-in slide-in-from-right-4 duration-300">
          <div className="bg-blue-50 p-4 rounded-lg border border-blue-100">
               <h4 className="text-sm font-bold text-blue-800 mb-3 flex items-center gap-2">
                   <GraduationCap size={16} />
                   Add Qualification
               </h4>
               <div className="grid grid-cols-2 gap-3 mb-3">
                   <div>
                       <label className="text-xs font-medium text-blue-700 block mb-1">Degree</label>
                       <select 
                        value={eduForm.degree}
                        onChange={(e) => setEduForm({...eduForm, degree: e.target.value})}
                        className="w-full px-3 py-2 border border-blue-200 rounded-md text-sm focus:ring-2 focus:ring-blue-300"
                       >
                           <option value="">Select Degree</option>
                           <option value="PhD">PhD</option>
                           <option value="M.Sc">M.Sc</option>
