            className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition-colors shadow-sm text-sm ml-auto sm:ml-0"
          >
            <Plus size={18} />
            <span>Add New Staff</span>
          </button>
        </div>
      </div>

      {/* Filters and Search */}
      <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-100 flex flex-col sm:flex-row gap-4 justify-between items-center">
        <div className="relative w-full sm:w-96">
          <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400" size={18} />
          <input
            type="text"
            placeholder="Search staff by name, role or dept..."
            className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent text-sm"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
        <div className="flex gap-2 w-full sm:w-auto">
          <button className="flex items-center gap-2 px-3 py-2 border border-slate-200 rounded-lg text-slate-600 hover:bg-slate-50 text-sm">
            <Filter size={16} />
            Filter
          </button>
        </div>
      </div>

      {/* Table */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm">
            <thead className="bg-slate-50 border-b border-slate-200">
              <tr>
                <th className="px-6 py-4 w-12">
                   <input 
                    type="checkbox" 
                    className="rounded border-slate-300 text-blue-600 focus:ring-blue-500 h-4 w-4"
                    checked={filteredEmployees.length > 0 && selectedIds.length === filteredEmployees.length}
                    onChange={handleSelectAll}
                  />
                </th>
                <th className="px-6 py-4 font-semibold text-slate-600">Employee</th>
                <th className="px-6 py-4 font-semibold text-slate-600">Role & Dept</th>
                <th className="px-6 py-4 font-semibold text-slate-600">Contact</th>
                <th className="px-6 py-4 font-semibold text-slate-600">Join Date</th>
                <th className="px-6 py-4 font-semibold text-slate-600 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredEmployees.map((emp) => (
                <tr 
                  key={emp.id} 
                  onClick={() => handleRowClick(emp)}
                  className={`hover:bg-slate-50 transition-colors cursor-pointer ${selectedIds.includes(emp.id) ? 'bg-blue-50/30' : ''}`}
                >
                  <td className="px-6 py-4" onClick={(e) => e.stopPropagation()}>
                     <input 
                      type="checkbox" 
                      className="rounded border-slate-300 text-blue-600 focus:ring-blue-500 h-4 w-4 cursor-pointer"
                      checked={selectedIds.includes(emp.id)}
                      onClick={(e) => handleSelectOne(e, emp.id)}
                      onChange={() => {}} 
                    />
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-3">
                      <div className="w-10 h-10 rounded-full bg-indigo-100 text-indigo-600 flex items-center justify-center font-bold text-sm overflow-hidden flex-shrink-0">
                         {emp.photo ? (
                            <img src={emp.photo} alt={`${emp.firstName} ${emp.lastName}`} className="w-full h-full object-cover" />
                         ) : (
                            <span>{emp.firstName[0]}{emp.lastName[0]}</span>
                         )}
                      </div>
                      <div>
                        <p className="font-medium text-slate-900">{emp.firstName} {emp.lastName}</p>
                        <p className="text-xs text-slate-500">{emp.id}</p>
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div>
                      <p className="text-slate-900 font-medium">{emp.role}</p>
                      <p className="text-slate-500 text-xs">{emp.department}</p>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex flex-col gap-1">
                      <div className="flex items-center gap-2 text-slate-600 text-xs">
                        <Mail size={12} />
                        {emp.email}
                      </div>
                      <div className="flex items-center gap-2 text-slate-600 text-xs">
                        <Phone size={12} />
                        {emp.phone}
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-slate-600">
                    {emp.joinDate}
                  </td>
                  <td className="px-6 py-4 text-right">
                    <div className="flex justify-end gap-2">
                        <button 
                            onClick={(e) => handleEditClick(e, emp)}
                            className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                            title="Edit Details"
                        >
                            <Edit2 size={16} />
                        </button>
                        <button 
                            onClick={(e) => handleDeleteClick(e, emp.id)}
                            className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                            title="Delete Staff"
                        >
                            <Trash2 size={16} />
                        </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
           {filteredEmployees.length === 0 && (
              <div className="p-8 text-center text-slate-500">
                No staff found matching your search.
              </div>
            )}
        </div>
      </div>

       {/* View Modal - Reused from previous implementation but slightly simplified for brevity in this response */}
       {isViewModalOpen && viewingEmployee && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
          <div className="bg-white rounded-xl shadow-2xl w-full max-w-lg overflow-hidden animate-in fade-in zoom-in duration-200">
            <div className="bg-slate-800 p-6 text-white relative">
              <button 
                onClick={() => setIsViewModalOpen(false)}
                className="absolute top-4 right-4 text-white/70 hover:text-white transition-colors"
              >
                <X size={20} />
              </button>
              <div className="flex items-center gap-6">
                <div className="w-20 h-20 bg-white/10 rounded-full flex items-center justify-center font-bold text-2xl border-4 border-white/20 overflow-hidden">
                    {viewingEmployee.photo ? (
                        <img src={viewingEmployee.photo} alt="" className="w-full h-full object-cover"/>
                    ) : (
                        <span>{viewingEmployee.firstName[0]}{viewingEmployee.lastName[0]}</span>
                    )}
                </div>
                <div>
                  <h3 className="text-xl font-bold">{viewingEmployee.firstName} {viewingEmployee.lastName}</h3>
                  <p className="text-blue-300 font-medium">{viewingEmployee.role}</p>
                  <p className="text-xs text-slate-400 mt-1">{viewingEmployee.department}</p>
                </div>
              </div>
            </div>

            <div className="p-6 space-y-6">
              <div className="grid grid-cols-2 gap-4 text-sm">
                <div>
                  <p className="text-xs font-bold text-slate-400 uppercase">Employee ID</p>
                  <p className="text-slate-800 font-medium">{viewingEmployee.id}</p>
                </div>
                <div>
                  <p className="text-xs font-bold text-slate-400 uppercase">Joined Date</p>
                  <p className="text-slate-800 font-medium">{viewingEmployee.joinDate}</p>
                </div>
                <div>
                  <p className="text-xs font-bold text-slate-400 uppercase">Email</p>
                  <p className="text-slate-800 font-medium break-words">{viewingEmployee.email}</p>
                </div>
                <div>
                  <p className="text-xs font-bold text-slate-400 uppercase">Phone</p>
                  <p className="text-slate-800 font-medium">{viewingEmployee.phone}</p>
                </div>
              </div>

              {viewingEmployee.education && viewingEmployee.education.length > 0 && (
                <div>
                   <p className="text-xs font-bold text-slate-400 uppercase mb-2">Qualifications</p>
                   <div className="space-y-2">
                       {viewingEmployee.education.map((edu, i) => (
                           <div key={i} className="flex justify-between items-center text-sm p-2 bg-slate-50 rounded border border-slate-100">
                               <div>
                                   <p className="font-semibold text-slate-800">{edu.degree}</p>
                                   <p className="text-xs text-slate-500">{edu.institution}</p>
                               </div>
                               <span className="text-xs font-mono bg-white px-1 border border-slate-200 rounded">{edu.completionYear}</span>
                           </div>
                       ))}
                   </div>
                </div>
              )}

              <div className="flex justify-end gap-2 pt-2">
                <button 
                  onClick={(e) => {
                      setIsViewModalOpen(false);
                      handleEditClick(e, viewingEmployee);
                  }}
                  className="px-4 py-2 border border-slate-200 text-slate-600 rounded-lg hover:bg-slate-50 text-sm font-medium transition-colors"
                >
                  Edit Profile
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

       {/* Add/Edit Wizard Modal */}
       {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
          <div className="bg-white rounded-xl shadow-2xl w-full max-w-2xl overflow-hidden animate-in fade-in zoom-in duration-200 flex flex-col h-[90vh]">

            {/* Wizard Header */}
            <div className="flex justify-between items-center p-6 border-b border-slate-100 bg-slate-50">
              <div>
                  <h3 className="text-lg font-bold text-slate-800">{editingEmployeeId ? 'Edit Staff Profile' : 'New Staff Registration'}</h3>
                  <div className="flex items-center gap-2 mt-2">
                      {[1, 2, 3, 4].map(step => (
                          <div key={step} className={`h-1.5 w-8 rounded-full transition-colors ${currentStep >= step ? 'bg-blue-600' : 'bg-slate-200'}`} />
                      ))}
                      <span className="text-xs font-medium text-slate-500 ml-2">Step {currentStep} of 4</span>
                  </div>
              </div>
              <button 
                onClick={() => setIsModalOpen(false)}
                className="text-slate-400 hover:text-slate-600 transition-colors bg-white p-2 rounded-full border border-slate-200 hover:bg-slate-100"
              >
                <X size={20} />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="flex-1 overflow-y-auto p-6 custom-scrollbar">
                {currentStep === 1 && renderStep1_BasicInfo()}
                {currentStep === 2 && renderStep2_Education()}
                {currentStep === 3 && renderStep3_Contacts()}
                {currentStep === 4 && renderStep4_Preview()}
            </form>

            {/* Wizard Footer */}
            <div className="p-4 border-t border-slate-100 bg-slate-50 flex justify-between items-center">
                {currentStep > 1 ? (
                    <button 
                        type="button" 
                        onClick={prevStep}
                        className="px-4 py-2 text-slate-600 hover:bg-white hover:shadow-sm border border-transparent hover:border-slate-200 rounded-lg transition-all text-sm font-medium flex items-center gap-2"
                    >
                        <ArrowLeft size={16} /> Back
                    </button>
                ) : (
                    <div></div> // Spacer
                )}

                <div className="flex gap-3">
                    {currentStep < 4 ? (
                         <button 
                            type="button" 
                            onClick={nextStep}
                            className="px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors text-sm font-medium shadow-sm flex items-center gap-2"
                         >
                            Save & Continue <ArrowRight size={16} />
                         </button>
                    ) : (
                        <button 
                            type="button" 
                            onClick={handleSubmit}
                            className="px-6 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 transition-colors text-sm font-medium shadow-sm flex items-center gap-2"
                        >
                            <Save size={16} /> Submit Registration
                        </button>
                    )}
                </div>
            </div>

          </div>
        </div>
      )}
    </div>
  );
};

export default StaffDirectory;

import React, { useState, useEffect } from 'react';
import { MOCK_EMPLOYEES } from '../constants';
import { Employee, Education, EmergencyContact, NextOfKin } from '../types';
import { Search, Plus, Filter, MoreHorizontal, Mail, Phone, X, CheckCircle, Send, Upload, User, Edit2, Trash2, Eye, Building, GraduationCap, ArrowRight, ArrowLeft, Save } from 'lucide-react';

const StaffDirectory: React.FC = () => {
  const [employees, setEmployees] = useState<Employee[]>(MOCK_EMPLOYEES);
  const [searchTerm, setSearchTerm] = useState('');

  // Modal States
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isViewModalOpen, setIsViewModalOpen] = useState(false);
  const [currentStep, setCurrentStep] = useState(1);

  const [notification, setNotification] = useState<{show: boolean, ticketId: string | null, count?: number}>({ show: false, ticketId: null });
  const [selectedIds, setSelectedIds] = useState<string[]>([]);

  // Selection States
  const [viewingEmployee, setViewingEmployee] = useState<Employee | null>(null);
  const [editingEmployeeId, setEditingEmployeeId] = useState<string | null>(null);

  // Initial Empty State
  const initialFormState: Partial<Employee> = {
    firstName: '',
    lastName: '',
    id: '',
    department: '',
    role: '',
    phone: '',
    email: '', // Institutional email
    joinDate: new Date().toISOString().split('T')[0],
    photo: undefined,
    personalEmail: '',
    houseAddress: '',
    boxAddress: '',
    education: [],
    emergencyContact: { name: '', relation: '', email: '', phone: '' },
    nextOfKin: { name: '', relation: '', phone: '', address: '' }
  };

  const [formData, setFormData] = useState<Partial<Employee>>(initialFormState);

  // Temporary state for adding a single education record
  const [eduForm, setEduForm] = useState<Partial<Education>>({
    degree: '',
    institution: '',
    admissionYear: '',
    completionYear: '',
    referenceNumber: ''
  });

  // Load draft on open if creating new
  useEffect(() => {
    if (isModalOpen && !editingEmployeeId) {
        const savedDraft = localStorage.getItem('new_staff_draft');
        if (savedDraft) {
            try {
                const parsed = JSON.parse(savedDraft);
                // Ask user if they want to resume? For now, just load it if it exists and id matches or is empty
                if(window.confirm("Found a saved draft for a new staff member. Would you like to continue?")) {
                    setFormData(parsed);
                } else {
                    localStorage.removeItem('new_staff_draft');
                }
            } catch (e) {
                console.error("Failed to load draft", e);
            }
        }
    }
  }, [isModalOpen]);

  const saveDraft = () => {
      if (!editingEmployeeId) {
          localStorage.setItem('new_staff_draft', JSON.stringify(formData));
      }
  };

  const filteredEmployees = employees.filter(emp =>
    emp.lastName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    emp.firstName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    emp.department.toLowerCase().includes(searchTerm.toLowerCase()) ||
    emp.role.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  // Nested input handlers
  const handleEmergencyChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
      const { name, value } = e.target;
      setFormData(prev => ({
          ...prev,
          emergencyContact: { ...prev.emergencyContact!, [name]: value }
      }));
  };

  const handleNextOfKinChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
      const { name, value } = e.target;
      setFormData(prev => ({
          ...prev,
          nextOfKin: { ...prev.nextOfKin!, [name]: value }
      }));
  };

  const handlePhotoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      const photoUrl = URL.createObjectURL(file);
      setFormData(prev => ({ ...prev, photo: photoUrl }));
    }
  };

  const handleAddEducation = () => {
      if(!eduForm.degree || !eduForm.institution) return;

      const newEdu: Education = {
          id: Date.now().toString(),
          degree: eduForm.degree!,
          institution: eduForm.institution!,
          admissionYear: eduForm.admissionYear || '',
          completionYear: eduForm.completionYear || '',
          referenceNumber: eduForm.referenceNumber || '',
          certificateUrl: eduForm.certificateUrl
      };

      setFormData(prev => ({
          ...prev,
          education: [...(prev.education || []), newEdu]
      }));

      // Reset edu form
      setEduForm({
        degree: '',
        institution: '',
        admissionYear: '',
        completionYear: '',
        referenceNumber: '',
        certificateUrl: undefined
      });
  };

  const handleRemoveEducation = (id: string) => {
      setFormData(prev => ({
          ...prev,
          education: prev.education?.filter(e => e.id !== id)
      }));
  };

  // --- Actions ---

  const handleSelectAll = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.checked) {
      setSelectedIds(filteredEmployees.map(emp => emp.id));
    } else {
      setSelectedIds([]);
    }
  };

  const handleSelectOne = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    setSelectedIds(prev => 
      prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]
    );
  };

  const handleBulkEmail = () => {
    const selectedEmails = employees
        .filter(emp => selectedIds.includes(emp.id))
        .map(emp => emp.email)
        .filter(email => email);

    if (selectedEmails.length > 0) {
        window.location.href = `mailto:?bcc=${selectedEmails.join(',')}`;
    } else {
        alert("No valid email addresses found for the selected staff.");
    }
  };

  const handleAddClick = () => {
    setEditingEmployeeId(null);
    setFormData(initialFormState);
    setCurrentStep(1);
    setIsModalOpen(true);
  };

  const handleEditClick = (e: React.MouseEvent, emp: Employee) => {
    e.stopPropagation();
    setEditingEmployeeId(emp.id);
    setFormData({
        ...emp,
        education: emp.education || [],
        emergencyContact: emp.emergencyContact || { name: '', relation: '', email: '', phone: '' },
        nextOfKin: emp.nextOfKin || { name: '', relation: '', phone: '', address: '' }
    });
    setCurrentStep(1);
    setIsModalOpen(true);
  };

  const handleDeleteClick = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (window.confirm("Are you sure you want to delete this staff member? This action cannot be undone.")) {
      setEmployees(prev => prev.filter(emp => emp.id !== id));
      if (viewingEmployee?.id === id) {
        setIsViewModalOpen(false);
        setViewingEmployee(null);
      }
    }
  };

  const handleRowClick = (emp: Employee) => {
    setViewingEmployee(emp);
    setIsViewModalOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    // Auto-generate institutional email if missing
    const finalEmail = formData.email || `${formData.firstName?.charAt(0).toLowerCase()}.${formData.lastName?.toLowerCase()}@ola.edu.gh`;

    // Ensure ID is present if not editing
    if (!editingEmployeeId && !formData.id) {
        alert("Please enter a Staff ID");
        return;
    }

    const finalData: Employee = {
        ...formData as Employee,
        email: finalEmail
    };

    if (editingEmployeeId) {
      setEmployees(prev => prev.map(emp => 
        emp.id === editingEmployeeId ? finalData : emp
      ));
    } else {
      setEmployees(prev => [finalData, ...prev]);
      localStorage.removeItem('new_staff_draft'); // Clear draft
    }

    setIsModalOpen(false);
    setEditingEmployeeId(null);
    setFormData(initialFormState);

    // Show success notification
    setNotification({ show: true, ticketId: null });
    setTimeout(() => setNotification({ show: false, ticketId: null }), 3000);
  };

  const nextStep = () => {
      saveDraft();
      setCurrentStep(prev => prev + 1);
  };

  const prevStep = () => setCurrentStep(prev => prev - 1);

  // --- Wizard Steps ---

  const renderStep1_BasicInfo = () => (
      <div className="space-y-4 animate-in fade-in slide-in-from-right-4 duration-300">
          <div className="flex flex-col items-center justify-center mb-6">
                <div className="w-24 h-24 bg-slate-100 rounded-full border-2 border-dashed border-slate-300 flex items-center justify-center overflow-hidden relative group transition-colors hover:border-blue-400">
                    {formData.photo ? (
                        <img src={formData.photo} alt="Preview" className="w-full h-full object-cover" />
                    ) : (
                        <User size={32} className="text-slate-400" />
                    )}
                    <label className="absolute inset-0 flex flex-col items-center justify-center bg-black/50 opacity-0 group-hover:opacity-100 transition-opacity cursor-pointer text-white text-xs font-medium">
                        <Upload size={20} className="mb-1" />
                        <span>Upload</span>
                        <input type="file" accept="image/*" className="hidden" onChange={handlePhotoChange} />
                    </label>
                </div>
                <p className="text-xs text-slate-500 mt-2">Passport Photo</p>
          </div>

          <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1">
                  <label className="text-xs font-semibold text-slate-600">First Name <span className="text-red-500">*</span></label>
                  <input name="firstName" value={formData.firstName} onChange={handleInputChange} className="w-full px-3 py-2 border rounded-lg text-sm" placeholder="e.g. Samuel" required />
              </div>
              <div className="space-y-1">
                  <label className="text-xs font-semibold text-slate-600">Last Name <span className="text-red-500">*</span></label>
                  <input name="lastName" value={formData.lastName} onChange={handleInputChange} className="w-full px-3 py-2 border rounded-lg text-sm" placeholder="e.g. Adjei" required />
              </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
               <div className="space-y-1">
                  <label className="text-xs font-semibold text-slate-600">Staff ID <span className="text-red-500">*</span></label>
                  <input name="id" value={formData.id} onChange={handleInputChange} className="w-full px-3 py-2 border rounded-lg text-sm" placeholder="e.g. EMP-001" required />
               </div>
               <div className="space-y-1">
                  <label className="text-xs font-semibold text-slate-600">Department <span className="text-red-500">*</span></label>
                  <select name="department" value={formData.department} onChange={handleInputChange} className="w-full px-3 py-2 border rounded-lg text-sm" required>
                        <option value="">Select Dept</option>
                        <option value="Administration">Administration</option>
                        <option value="Academic Affairs">Academic Affairs</option>
                        <option value="Mathematics">Mathematics</option>
                        <option value="Science">Science</option>
                        <option value="Education">Education</option>
                        <option value="ICT">ICT</option>
                  </select>
               </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
               <div className="space-y-1">
                  <label className="text-xs font-semibold text-slate-600">Role / Job Title <span className="text-red-500">*</span></label>
                  <input name="role" value={formData.role} onChange={handleInputChange} className="w-full px-3 py-2 border rounded-lg text-sm" placeholder="e.g. Senior Lecturer" required />
               </div>
               <div className="space-y-1">
                  <label className="text-xs font-semibold text-slate-600">Date Joined <span className="text-red-500">*</span></label>
                  <input type="date" name="joinDate" value={formData.joinDate} onChange={handleInputChange} className="w-full px-3 py-2 border rounded-lg text-sm" required />
               </div>
          </div>

          <hr className="border-slate-100" />
          <h4 className="text-sm font-bold text-slate-700">Contact Information</h4>

          <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1">
                  <label className="text-xs font-semibold text-slate-600">Phone Number <span className="text-red-500">*</span></label>
                  <input type="tel" name="phone" value={formData.phone} onChange={handleInputChange} className="w-full px-3 py-2 border rounded-lg text-sm" placeholder="024xxxxxxx" required />
              </div>
              <div className="space-y-1">
