import React, { useState, useRef, useEffect } from 'react';
import { generateAIResponse } from '../services/geminiService';
import { Bot, Send, User, Sparkles } from 'lucide-react';

interface Message {
  id: string;
  role: 'user' | 'assistant';
  content: string;
  timestamp: Date;
}

const AIAssistant: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    {
      id: '1',
      role: 'assistant',
      content: 'Hello! I am the OLA College AI Assistant. How can I help you with administrative tasks, drafting policies, or analyzing data today?',
      timestamp: new Date()
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSendMessage = async () => {
    if (!input.trim()) return;

    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: input,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    try {
      // Provide context about the college
      const context = `
        You are an AI Assistant for OLA College of Education. 
        The college specializes in teacher education and runs a 4-year Bachelor of Education (B.Ed.) degree program.

        Key Programs offered include:
        - B.Ed. Primary Education
        - B.Ed. JHS Education
        - B.Ed. Early Childhood Education
        - B.Ed. Mathematics
        - B.Ed. Science

        Your role is to help administrators with tasks like:
        - Drafting official announcements and memos.
        - Summarizing student or staff data (generically, do not invent specific personal data).
        - Explaining HR policies related to leave (Sick, Casual, Maternity, Study, Annual).
        - Providing suggestions for improving college accountability and student record keeping.

        Recent Policy Focus:
        - Strict accountability for employee leave to ensure proper tracking.
        - Digitalization of student records for better academic monitoring.

        Keep responses professional, academic, formal, and helpful.
      `;

      const responseText = await generateAIResponse(userMessage.content, context);

      const aiMessage: Message = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        content: responseText,
        timestamp: new Date()
      };

      setMessages(prev => [...prev, aiMessage]);
    } catch (error) {
      console.error(error);
      setMessages(prev => [...prev, {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        content: "I apologize, but I encountered an issue connecting to the server.",
        timestamp: new Date()
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="h-[calc(100vh-6rem)] flex flex-col bg-white rounded-xl shadow-sm border border-slate-100 overflow-hidden">
      <div className="p-4 border-b border-slate-100 bg-slate-50 flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-blue-600 rounded-lg text-white">
            <Bot size={20} />
          </div>
          <div>
            <h3 className="font-bold text-slate-800">OLA AI Assistant</h3>
            <p className="text-xs text-slate-500">Powered by Gemini</p>
          </div>
        </div>
        <div className="px-3 py-1 bg-blue-100 text-blue-700 text-xs font-medium rounded-full flex items-center gap-1">
          <Sparkles size={12} />
          Online
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-6 bg-slate-50/50">
        {messages.map((msg) => (
          <div
            key={msg.id}
            className={`flex gap-3 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}
          >
            <div className={`
              w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0
              ${msg.role === 'user' ? 'bg-slate-700 text-white' : 'bg-blue-600 text-white'}
            `}>
              {msg.role === 'user' ? <User size={16} /> : <Bot size={16} />}
            </div>

            <div className={`
              max-w-[80%] rounded-2xl px-5 py-3 text-sm leading-relaxed shadow-sm
              ${msg.role === 'user' 
                ? 'bg-white text-slate-800 rounded-tr-none border border-slate-200' 
                : 'bg-white text-slate-700 rounded-tl-none border border-slate-200'}
            `}>
               {/* Basic formatting for line breaks */}
               {msg.content.split('\n').map((line, i) => (
                 <p key={i} className="min-h-[1rem]">{line}</p>
               ))}
               <p className="text-[10px] text-slate-400 mt-2 text-right">
                 {msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
               </p>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex gap-3">
            <div className="w-8 h-8 rounded-full bg-blue-600 text-white flex items-center justify-center flex-shrink-0">
              <Bot size={16} />
            </div>
            <div className="bg-white px-5 py-4 rounded-2xl rounded-tl-none border border-slate-200 shadow-sm flex items-center gap-2">
              <span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce"></span>
              <span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce delay-75"></span>
              <span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce delay-150"></span>
            </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <div className="p-4 bg-white border-t border-slate-100">
        <div className="flex items-center gap-2 relative">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
            placeholder="Ask AI to draft a leave policy or summarize data..."
            className="w-full pl-4 pr-12 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500/50 focus:border-blue-500 transition-all text-sm"
            disabled={isLoading}
          />
          <button
            onClick={handleSendMessage}
            disabled={!input.trim() || isLoading}
            className={`absolute right-2 p-2 rounded-lg transition-colors ${
              input.trim() && !isLoading 
                ? 'bg-blue-600 text-white hover:bg-blue-700' 
                : 'bg-slate-200 text-slate-400 cursor-not-allowed'
            }`}
          >
            <Send size={18} />
          </button>
        </div>
        <p className="text-center text-xs text-slate-400 mt-2">
          AI can make mistakes. Please verify important information.
        </p>
      </div>
    </div>
  );
};

export default AIAssistant;

import React, { useState, useEffect } from 'react';
import { MOCK_EMPLOYEES } from '../constants';
import { Employee, Education, EmergencyContact, NextOfKin } from '../types';
import { Search, Plus, Filter, MoreHorizontal, Mail, Phone, X, CheckCircle, Send, Upload, User, Edit2, Trash2, Eye, Building, GraduationCap, ArrowRight, ArrowLeft, Save } from 'lucide-react';

const StaffDirectory: React.FC = () => {
  const [employees, setEmployees] = useState<Employee[]>(MOCK_EMPLOYEES);
  const [searchTerm, setSearchTerm] = useState('');

  // Modal States
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isViewModalOpen, setIsViewModalOpen] = useState(false);
  const [currentStep, setCurrentStep] = useState(1);

  const [notification, setNotification] = useState<{show: boolean, ticketId: string | null, count?: number}>({ show: false, ticketId: null });
  const [selectedIds, setSelectedIds] = useState<string[]>([]);

  // Selection States
  const [viewingEmployee, setViewingEmployee] = useState<Employee | null>(null);
  const [editingEmployeeId, setEditingEmployeeId] = useState<string | null>(null);

  // Initial Empty State
  const initialFormState: Partial<Employee> = {
    firstName: '',
    lastName: '',
    id: '',
    department: '',
    role: '',
    phone: '',
    email: '', // Institutional email
    joinDate: new Date().toISOString().split('T')[0],
    photo: undefined,
    personalEmail: '',
    houseAddress: '',
    boxAddress: '',
    education: [],
    emergencyContact: { name: '', relation: '', email: '', phone: '' },
    nextOfKin: { name: '', relation: '', phone: '', address: '' }
  };

  const [formData, setFormData] = useState<Partial<Employee>>(initialFormState);

  // Temporary state for adding a single education record
  const [eduForm, setEduForm] = useState<Partial<Education>>({
    degree: '',
    institution: '',
    admissionYear: '',
    completionYear: '',
    referenceNumber: ''
  });

  // Load draft on open if creating new
  useEffect(() => {
    if (isModalOpen && !editingEmployeeId) {
        const savedDraft = localStorage.getItem('new_staff_draft');
        if (savedDraft) {
            try {
                const parsed = JSON.parse(savedDraft);
                // Ask user if they want to resume? For now, just load it if it exists and id matches or is empty
                if(window.confirm("Found a saved draft for a new staff member. Would you like to continue?")) {
                    setFormData(parsed);
                } else {
                    localStorage.removeItem('new_staff_draft');
                }
            } catch (e) {
                console.error("Failed to load draft", e);
            }
        }
    }
  }, [isModalOpen]);

  const saveDraft = () => {
      if (!editingEmployeeId) {
          localStorage.setItem('new_staff_draft', JSON.stringify(formData));
      }
  };

  const filteredEmployees = employees.filter(emp =>
    emp.lastName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    emp.firstName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    emp.department.toLowerCase().includes(searchTerm.toLowerCase()) ||
    emp.role.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  // Nested input handlers
  const handleEmergencyChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
      const { name, value } = e.target;
      setFormData(prev => ({
          ...prev,
          emergencyContact: { ...prev.emergencyContact!, [name]: value }
      }));
  };

  const handleNextOfKinChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
      const { name, value } = e.target;
      setFormData(prev => ({
          ...prev,
          nextOfKin: { ...prev.nextOfKin!, [name]: value }
      }));
  };

  const handlePhotoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      const photoUrl = URL.createObjectURL(file);
      setFormData(prev => ({ ...prev, photo: photoUrl }));
    }
  };

  const handleAddEducation = () => {
      if(!eduForm.degree || !eduForm.institution) return;

      const newEdu: Education = {
          id: Date.now().toString(),
          degree: eduForm.degree!,
          institution: eduForm.institution!,
          admissionYear: eduForm.admissionYear || '',
          completionYear: eduForm.completionYear || '',
          referenceNumber: eduForm.referenceNumber || '',
          certificateUrl: eduForm.certificateUrl
      };

      setFormData(prev => ({
          ...prev,
          education: [...(prev.education || []), newEdu]
      }));

      // Reset edu form
      setEduForm({
        degree: '',
        institution: '',
        admissionYear: '',
        completionYear: '',
        referenceNumber: '',
        certificateUrl: undefined
      });
  };

  const handleRemoveEducation = (id: string) => {
      setFormData(prev => ({
          ...prev,
          education: prev.education?.filter(e => e.id !== id)
      }));
  };

  // --- Actions ---

  const handleSelectAll = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.checked) {
      setSelectedIds(filteredEmployees.map(emp => emp.id));
    } else {
      setSelectedIds([]);
    }
  };

  const handleSelectOne = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    setSelectedIds(prev => 
      prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]
    );
  };

  const handleBulkEmail = () => {
    const selectedEmails = employees
        .filter(emp => selectedIds.includes(emp.id))
        .map(emp => emp.email)
        .filter(email => email);

    if (selectedEmails.length > 0) {
        window.location.href = `mailto:?bcc=${selectedEmails.join(',')}`;
    } else {
        alert("No valid email addresses found for the selected staff.");
    }
  };

  const handleAddClick = () => {
    setEditingEmployeeId(null);
    setFormData(initialFormState);
    setCurrentStep(1);
    setIsModalOpen(true);
  };

  const handleEditClick = (e: React.MouseEvent, emp: Employee) => {
    e.stopPropagation();
    setEditingEmployeeId(emp.id);
    setFormData({
        ...emp,
        education: emp.education || [],
        emergencyContact: emp.emergencyContact || { name: '', relation: '', email: '', phone: '' },
        nextOfKin: emp.nextOfKin || { name: '', relation: '', phone: '', address: '' }
    });
    setCurrentStep(1);
    setIsModalOpen(true);
  };

  const handleDeleteClick = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (window.confirm("Are you sure you want to delete this staff member? This action cannot be undone.")) {
      setEmployees(prev => prev.filter(emp => emp.id !== id));
      if (viewingEmployee?.id === id) {
        setIsViewModalOpen(false);
        setViewingEmployee(null);
      }
    }
  };

  const handleRowClick = (emp: Employee) => {
    setViewingEmployee(emp);
    setIsViewModalOpen(true);
