import React, { useState } from 'react';
import { School, User, Lock, AlertCircle, ArrowRight, Mail } from 'lucide-react';
import { SystemUser } from '../types';
import { signInWithEmailAndPassword } from 'firebase/auth';
import { auth } from '../services/firebase';

interface LoginProps {
  onLogin: (user: SystemUser) => void;
  onNavigateToRegister: () => void;
}

const Login: React.FC<LoginProps> = ({ onLogin, onNavigateToRegister }) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  // Password Strength Logic
  const getPasswordStrength = (pass: string) => {
    let score = 0;
    if (!pass) return 0;
    if (pass.length > 5) score += 1;
    if (pass.length > 9) score += 1;
    if (/[A-Z]/.test(pass)) score += 1;
    if (/[0-9]/.test(pass)) score += 1;
    if (/[^A-Za-z0-9]/.test(pass)) score += 1;
    return score;
  };

  const passwordStrength = getPasswordStrength(password);

  const getStrengthColor = (score: number) => {
    if (score < 3) return 'bg-red-400';
    if (score < 5) return 'bg-yellow-400';
    return 'bg-green-500';
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setIsLoading(true);

    try {
      const userCredential = await signInWithEmailAndPassword(auth, email, password);

      // Construct a minimal SystemUser from Firebase User
      // The full user hydration happens in App.tsx via onAuthStateChanged
      const user: SystemUser = {
        id: userCredential.user.uid,
        username: userCredential.user.email || '',
        employeeId: '',
        roleId: '',
        isActive: true
      };

      onLogin(user);
    } catch (err: any) {
      console.error(err);
      setError('Email or password is incorrect');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-100 flex items-center justify-center p-4">
