        <div className="relative w-full sm:w-96">
          <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400" size={18} />
          <input
            type="text"
            placeholder="Search by name or ID..."
            className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent text-sm"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
        <div className="flex gap-2 w-full sm:w-auto relative">
          <button 
            onClick={() => setShowFilterMenu(!showFilterMenu)}
            className={`flex items-center gap-2 px-3 py-2 border rounded-lg text-sm transition-colors ${
                filterProgram || showFilterMenu 
                ? 'bg-blue-50 border-blue-200 text-blue-600' 
                : 'border-slate-200 text-slate-600 hover:bg-slate-50'
            }`}
          >
            <Filter size={16} />
            Filter
            {filterProgram && <div className="w-2 h-2 rounded-full bg-blue-600 ml-1"></div>}
          </button>

          {showFilterMenu && (
             <div className="absolute top-full right-0 mt-2 w-64 bg-white rounded-xl shadow-xl border border-slate-100 z-20 animate-in fade-in zoom-in duration-200 overflow-hidden">
                <div className="p-1 bg-slate-50 border-b border-slate-100">
                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider px-3 py-2">Program</p>
                </div>
                <div className="max-h-64 overflow-y-auto p-1 custom-scrollbar">
                    <button
                        onClick={() => { setFilterProgram(''); setShowFilterMenu(false); }}
                        className={`w-full text-left px-3 py-2 text-sm rounded-lg flex items-center justify-between ${
                            filterProgram === '' ? 'bg-blue-50 text-blue-700 font-medium' : 'text-slate-600 hover:bg-slate-50'
                        }`}
                    >
                        All Programs
                        {filterProgram === '' && <Check size={14} />}
                    </button>
                    {uniquePrograms.map(prog => (
                         <button
                            key={prog}
                            onClick={() => { setFilterProgram(prog); setShowFilterMenu(false); }}
                            className={`w-full text-left px-3 py-2 text-sm rounded-lg flex items-center justify-between ${
                                filterProgram === prog ? 'bg-blue-50 text-blue-700 font-medium' : 'text-slate-600 hover:bg-slate-50'
                            }`}
                        >
                            <span className="truncate mr-2">{prog}</span>
                            {filterProgram === prog && <Check size={14} className="flex-shrink-0" />}
                        </button>
                    ))}
                </div>
             </div>
          )}
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
