import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import StudentRecords from './components/StudentRecords';
import LeaveManagement from './components/LeaveManagement';
import AIAssistant from './components/AIAssistant';
import StaffDirectory from './components/StaffDirectory';
import Settings from './components/Settings';
import Login from './components/Login';
import Register from './components/Register';
import HelpDesk from './components/HelpDesk';
import { SystemUser, Employee } from './types';
import { MOCK_EMPLOYEES, MOCK_USERS } from './constants';
import { Menu } from 'lucide-react';
import { auth } from './services/firebase';
import { onAuthStateChanged, signOut } from 'firebase/auth';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [currentUser, setCurrentUser] = useState<SystemUser | null>(null);
  const [currentEmployees, setCurrentEmployees] = useState<Employee[]>(MOCK_EMPLOYEES);

  const [activeTab, setActiveTab] = useState('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [authView, setAuthView] = useState<'login' | 'register'>('login');

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, (user) => {
      if (user) {
        // Retrieve persistent user roles from local storage (simulating DB)
        const storedUsers = JSON.parse(localStorage.getItem('ola_system_users') || '[]');
        const allSystemUsers: SystemUser[] = [...MOCK_USERS, ...storedUsers];

        // Find the system user config matching the logged-in email
        const matchedSystemUser = allSystemUsers.find(
            u => u.username.toLowerCase() === user.email?.toLowerCase()
        );

        // Find employee details if linked
        const matchedEmployee = MOCK_EMPLOYEES.find(e => e.email.toLowerCase() === user.email?.toLowerCase());

        // Determine Role
        // If system user exists, use that role. If not, default to ADMIN if created via Register component
        const userRole = matchedSystemUser ? matchedSystemUser.roleId : 'ROLE-ADMIN';
        const employeeId = matchedEmployee ? matchedEmployee.id : (matchedSystemUser?.employeeId || 'EMP-GUEST');

        const mappedUser: SystemUser = {
          id: user.uid,
          username: user.email || user.displayName || 'User',
          employeeId: employeeId,
          roleId: userRole, 
          isActive: true,
          lastLogin: new Date().toISOString()
        };

        if (!matchedEmployee) {
           // Create a temporary employee record for display purposes so the header name works
           const tempEmployee: Employee = {
              id: 'EMP-GUEST',
              firstName: user.displayName?.split(' ')[0] || 'Guest',
              lastName: user.displayName?.split(' ').slice(1).join(' ') || 'User',
              department: 'General',
              role: userRole === 'ROLE-HR' ? 'HR Manager' : (userRole === 'ROLE-STAFF' ? 'Academic Staff' : 'System User'),
              email: user.email || '',
              phone: '',
              joinDate: new Date().toISOString()
          };
          setCurrentEmployees(prev => {
              // Avoid duplicates
              if (prev.find(e => e.id === 'EMP-GUEST')) return prev;
              return [...prev, tempEmployee];
          });
        }

        setCurrentUser(mappedUser);
        setIsAuthenticated(true);

        // Redirect Logic based on Role
        if (userRole === 'ROLE-STAFF') {
            setActiveTab('students');
        } else if (userRole === 'ROLE-HR') {
            setActiveTab('employees'); // Staff Directory
        } else if (userRole === 'ROLE-IT') {
            setActiveTab('helpdesk');
        } else if (userRole === 'ROLE-NON-TEACHING') {
            setActiveTab('leave');
        } else {
            setActiveTab('dashboard'); // Admin default
        }

      } else {
        setCurrentUser(null);
        setIsAuthenticated(false);
      }
    });

    return () => unsubscribe();
  }, []);

  const handleLogin = (user: SystemUser) => {
    // Auth state is handled by useEffect
    // This callback helps trigger transitions if needed, but onAuthStateChanged is the source of truth.
  };

  const handleRegister = (user: SystemUser) => {
    // Auth state is handled by useEffect
  };

  const handleLogout = async () => {
    await signOut(auth);
    setAuthView('login');
  };

  // Get current employee details based on login
  const currentEmployee = currentUser 
    ? currentEmployees.find(e => e.id === currentUser.employeeId) 
    : null;

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard />;
      case 'students':
        return <StudentRecords />;
      case 'leave':
        return <LeaveManagement />;
      case 'assistant':
        return <AIAssistant />;
      case 'employees':
        return <StaffDirectory />;
      case 'helpdesk':
        return <HelpDesk />;
      case 'settings':
        return <Settings />;
      default:
        return <Dashboard />;
    }
  };

  if (!isAuthenticated) {
    if (authView === 'register') {
        return (
            <Register 
                onRegister={handleRegister} 
                onNavigateToLogin={() => setAuthView('login')} 
            />
        );
    }
    return (
        <Login 
            onLogin={handleLogin} 
            onNavigateToRegister={() => setAuthView('register')} 
        />
    );
  }

  return (
    <div className="flex min-h-screen bg-[#f3f4f6]">
      {/* Sidebar */}
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        onLogout={handleLogout} 
        isOpen={isSidebarOpen}
        onClose={() => setIsSidebarOpen(false)}
      />

      {/* Main Content Area */}
      <div className="flex-1 flex flex-col md:ml-64 transition-all duration-300 min-w-0">
        {/* Header */}
        <header className="h-16 bg-white shadow-sm border-b border-slate-200 flex items-center justify-between px-4 md:px-8 sticky top-0 z-20">
          <div className="flex items-center gap-3 md:gap-4 text-slate-600">
             <button 
                onClick={() => setIsSidebarOpen(true)}
                className="md:hidden p-1 hover:bg-slate-100 rounded-lg text-slate-600 transition-colors"
             >
                <Menu size={24} />
             </button>
             <div className="flex flex-col md:flex-row md:items-center md:gap-4">
               <span className="font-semibold text-base md:text-lg tracking-tight text-slate-800 truncate">OLA College</span>
               <span className="hidden md:inline text-slate-300">|</span>
               <span className="text-xs md:text-sm text-slate-500 hidden sm:inline">Management Information System</span>
             </div>
          </div>

          <div className="flex items-center gap-3 md:gap-4">
             <div className="text-right hidden sm:block">
                 <p className="text-sm font-bold text-slate-800">
                    {currentEmployee ? `${currentEmployee.firstName} ${currentEmployee.lastName}` : currentUser?.username}
                 </p>
                 <p className="text-xs text-slate-500">
                    {currentEmployee ? currentEmployee.role : 'System User'}
                 </p>
             </div>
             <div className="h-9 w-9 md:h-10 md:w-10 rounded-full bg-slate-900 text-white flex items-center justify-center font-bold overflow-hidden border-2 border-slate-200">
                 {currentEmployee?.photo ? (
                    <img src={currentEmployee.photo} alt="Profile" className="w-full h-full object-cover" />
                 ) : (
                    <span>
                        {currentEmployee 
                            ? `${currentEmployee.firstName[0]}${currentEmployee.lastName[0]}` 
                            : currentUser?.username?.[0]?.toUpperCase() || 'U'}
                    </span>
                 )}
             </div>
          </div>
        </header>

        {/* Dynamic Page Content */}
        <main className="p-4 md:p-8 flex-1 overflow-x-hidden">
          <div className="max-w-7xl mx-auto animate-fade-in">
            {renderContent()}
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { MOCK_USERS, MOCK_DEPARTMENTS, MOCK_ROLES, MOCK_EMPLOYEES } from '../constants';
import { SystemUser, Department, Role, Employee } from '../types';
import { Plus, Trash2, Edit2, Shield, Users, Building, Key, Check, Search, X, CheckSquare, Square } from 'lucide-react';
import { initializeApp, deleteApp } from 'firebase/app';
import { getAuth, createUserWithEmailAndPassword, signOut } from 'firebase/auth';
import { firebaseConfig } from '../services/firebase';

type SettingsTab = 'users' | 'departments' | 'roles';

const AVAILABLE_PERMISSIONS = [
  'read:students', 'write:students', 
  'read:staff', 'write:staff', 
  'read:leave', 'approve:leave', 
  'read:settings', 'write:settings',
  'read:ticket', 'write:ticket'
];

const Settings: React.FC = () => {
  const [activeTab, setActiveTab] = useState<SettingsTab>('users');
  const [users, setUsers] = useState<SystemUser[]>(MOCK_USERS);
  const [departments, setDepartments] = useState<Department[]>(MOCK_DEPARTMENTS);
  const [roles, setRoles] = useState<Role[]>(MOCK_ROLES);

  // Modal States
  const [isUserModalOpen, setIsUserModalOpen] = useState(false);
  const [isDeptModalOpen, setIsDeptModalOpen] = useState(false);
  const [isRoleModalOpen, setIsRoleModalOpen] = useState(false);

  // Edit States
  const [editingUserId, setEditingUserId] = useState<string | null>(null);
  const [editingRoleId, setEditingRoleId] = useState<string | null>(null);

  // Form States
  const [userForm, setUserForm] = useState<Partial<SystemUser>>({ isActive: true });
  const [deptForm, setDeptForm] = useState<Partial<Department>>({});
  const [roleForm, setRoleForm] = useState<Partial<Role>>({ permissions: [] });

  // Load users from local storage on mount to display them
  useEffect(() => {
    const storedUsers = localStorage.getItem('ola_system_users');
    if (storedUsers) {
      setUsers(prev => {
        const parsed = JSON.parse(storedUsers);
        // Merge mock and stored users, avoiding duplicates by ID
        const existingIds = new Set(prev.map(u => u.id));
        const newUsers = parsed.filter((u: SystemUser) => !existingIds.has(u.id));
        return [...prev, ...newUsers];
      });
    }
  }, []);

  // --- Handlers for Users ---

  const generateCredentials = (empId: string) => {
    const employee = MOCK_EMPLOYEES.find(e => e.id === empId);
    if (!employee) return;

    // We no longer auto-generate the username, allowing manual email entry.
    setUserForm(prev => ({
        ...prev,
        password: 'Ola@2024',
        employeeId: empId
    }));
  };

  const openCreateUserModal = () => {
      setEditingUserId(null);
      setUserForm({ isActive: true });
      setIsUserModalOpen(true);
  };

  const openEditUserModal = (user: SystemUser) => {
      setEditingUserId(user.id);
      setUserForm({ ...user, password: '' }); // Clear password field for security
      setIsUserModalOpen(true);
  };

  const handleSaveUser = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!userForm.username || !userForm.roleId || !userForm.employeeId) return;

    if (editingUserId) {
        // Update local state
        const updatedUsers = users.map(u => u.id === editingUserId ? { ...u, ...userForm, password: userForm.password || u.password } as SystemUser : u);
        setUsers(updatedUsers);

        // Update localStorage for persistence
        // Filter out mock users (assuming mock IDs start with USR-00)
        const persistentUsers = updatedUsers.filter(u => !MOCK_USERS.find(mu => mu.id === u.id));
        localStorage.setItem('ola_system_users', JSON.stringify(persistentUsers));

        setIsUserModalOpen(false);
        setUserForm({ isActive: true });
        setEditingUserId(null);

    } else {
        // Create New User
        let tempApp;
        try {
            // 1. Create in Firebase Auth
            // We use a unique app instance name to avoid "duplicate-app" errors and cleanup afterwards
            const appName = `UserCreationApp-${Date.now()}`;
            tempApp = initializeApp(firebaseConfig, appName);
            const tempAuth = getAuth(tempApp);

            const userCredential = await createUserWithEmailAndPassword(tempAuth, userForm.username, userForm.password || 'Ola@2024');
            await signOut(tempAuth); // Immediately sign out the temp user

            // 2. Create SystemUser object
            const newUser: SystemUser = {
                id: userCredential.user.uid,
                username: userForm.username,
                // We don't store password in state/storage for security, but we keep it in form for now
                employeeId: userForm.employeeId,
                roleId: userForm.roleId,
                isActive: userForm.isActive !== undefined ? userForm.isActive : true,
                lastLogin: undefined
            };

            // 3. Update State and LocalStorage
            const updatedUsers = [...users, newUser];
            setUsers(updatedUsers);

            const storedUsers = JSON.parse(localStorage.getItem('ola_system_users') || '[]');
            localStorage.setItem('ola_system_users', JSON.stringify([...storedUsers, newUser]));

            alert(`User ${newUser.username} created successfully! They can now log in.`);

            setIsUserModalOpen(false);
            setUserForm({ isActive: true });
            setEditingUserId(null);

        } catch (error: any) {
            console.error("Error creating user:", error);
            if (error.code === 'auth/email-already-in-use') {
                alert(`The username (email) '${userForm.username}' already exists in the system.`);
            } else {
                alert("Failed to create user: " + error.message);
            }
            // Don't close modal on error so user can correct it
        } finally {
            if (tempApp) {
                await deleteApp(tempApp);
            }
        }
    }
  };

  const handleDeleteUser = (userId: string) => {
      if(window.confirm('Are you sure you want to delete this user? (Note: This only removes system access, it does not delete the account from authentication provider in this demo)')) {
          const updatedUsers = users.filter(u => u.id !== userId);
          setUsers(updatedUsers);

          // Update persistence
          const persistentUsers = updatedUsers.filter(u => !MOCK_USERS.find(mu => mu.id === u.id));
          localStorage.setItem('ola_system_users', JSON.stringify(persistentUsers));
      }
  };

  // --- Handlers for Departments ---

  const handleCreateDept = (e: React.FormEvent) => {
    e.preventDefault();
    if (!deptForm.name) return;

    const newDept: Department = {
        id: `DEPT-${Date.now()}`,
        name: deptForm.name,
        headOfDept: deptForm.headOfDept,
        description: deptForm.description
    };

    setDepartments([...departments, newDept]);
    setIsDeptModalOpen(false);
    setDeptForm({});
  };

  const handleDeleteDept = (deptId: string) => {
    if(window.confirm('Delete this department?')) {
        setDepartments(departments.filter(d => d.id !== deptId));
    }
  };

  // --- Handlers for Roles ---

  const openCreateRoleModal = () => {
    setEditingRoleId(null);
    setRoleForm({ permissions: [] });
    setIsRoleModalOpen(true);
  };

  const openEditRoleModal = (role: Role) => {
    setEditingRoleId(role.id);
    setRoleForm({ ...role });
    setIsRoleModalOpen(true);
  };

  const handleSaveRole = (e: React.FormEvent) => {
    e.preventDefault();
    if (!roleForm.name) return;

    if (editingRoleId) {
        setRoles(roles.map(r => r.id === editingRoleId ? { ...r, ...roleForm } as Role : r));
    } else {
        const newRole: Role = {
            id: `ROLE-${Date.now()}`,
            name: roleForm.name,
            description: roleForm.description || '',
            permissions: roleForm.permissions || []
        };
        setRoles([...roles, newRole]);
    }

    setIsRoleModalOpen(false);
    setRoleForm({ permissions: [] });
    setEditingRoleId(null);
  };

  const togglePermission = (perm: string) => {
      setRoleForm(prev => {
          const current = prev.permissions || [];
          if (current.includes(perm)) {
              return { ...prev, permissions: current.filter(p => p !== perm) };
          } else {
              return { ...prev, permissions: [...current, perm] };
          }
      });
  };


  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">System Settings</h2>
          <p className="text-sm text-slate-500 mt-1">Manage users, departments, and access roles.</p>
        </div>
      </div>

      {/* Tabs */}
      <div className="border-b border-slate-200 overflow-x-auto">
        <div className="flex space-x-8 min-w-max">
            <button
                onClick={() => setActiveTab('users')}
                className={`pb-4 text-sm font-medium flex items-center gap-2 border-b-2 transition-colors ${
                    activeTab === 'users' ? 'border-blue-600 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'
                }`}
            >
                <Users size={18} />
                User Management
            </button>
            <button
                onClick={() => setActiveTab('departments')}
                className={`pb-4 text-sm font-medium flex items-center gap-2 border-b-2 transition-colors ${
                    activeTab === 'departments' ? 'border-blue-600 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'
                }`}
            >
                <Building size={18} />
                Departments
            </button>
            <button
                onClick={() => setActiveTab('roles')}
                className={`pb-4 text-sm font-medium flex items-center gap-2 border-b-2 transition-colors ${
                    activeTab === 'roles' ? 'border-blue-600 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'
                }`}
            >
                <Shield size={18} />
                Roles & Permissions
            </button>
        </div>
      </div>

      {/* Content Area */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-100 min-h-[500px]">

        {/* USERS TAB */}
        {activeTab === 'users' && (
            <div className="p-4 md:p-6">
                <div className="flex justify-between items-center mb-6">
                    <h3 className="text-lg font-bold text-slate-800">System Users</h3>
                    <button 
                        onClick={openCreateUserModal}
                        className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition-colors shadow-sm text-sm"
                    >
                        <Plus size={16} />
                        <span className="hidden sm:inline">Create User</span>
                        <span className="sm:hidden">Add</span>
                    </button>
                </div>
                <div className="overflow-x-auto">
                    <table className="w-full text-left text-sm">
