import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import StudentRecords from './components/StudentRecords';
import LeaveManagement from './components/LeaveManagement';
import AIAssistant from './components/AIAssistant';
import StaffDirectory from './components/StaffDirectory';
import Settings from './components/Settings';
import Login from './components/Login';
import Register from './components/Register';
import HelpDesk from './components/HelpDesk';
import { SystemUser, Employee } from './types';
import { Menu } from 'lucide-react';
import { auth, db } from './services/firebase';
import { onAuthStateChanged, signOut } from 'firebase/auth';
import { doc, getDoc, collection, query, where, getDocs } from 'firebase/firestore';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [currentUser, setCurrentUser] = useState<SystemUser | null>(null);
  const [currentEmployee, setCurrentEmployee] = useState<Employee | null>(null);

  const [activeTab, setActiveTab] = useState('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [authView, setAuthView] = useState<'login' | 'register'>('login');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (user) => {
      setLoading(true);
      if (user) {
        try {
            // 1. Get System User Config from Firestore
            const userDocRef = doc(db, 'system_users', user.uid);
            const userDoc = await getDoc(userDocRef);

            let systemUserData: SystemUser;

            if (userDoc.exists()) {
                systemUserData = userDoc.data() as SystemUser;
            } else {
                // Fallback for users not in DB yet (or created outside app flow)
                 systemUserData = {
                    id: user.uid,
                    username: user.email || 'User',
                    employeeId: 'EMP-GUEST',
                    roleId: 'ROLE-ADMIN', // Defaulting to Admin for demo flow if missing
                    isActive: true
                };
            }

            // 2. Get Employee Data
            // We search for employee record either by ID linked in system user or by email
            let employeeData: Employee | null = null;

            if (systemUserData.employeeId && systemUserData.employeeId !== 'EMP-GUEST') {
                 const empDoc = await getDoc(doc(db, 'employees', systemUserData.employeeId));
                 if (empDoc.exists()) {
                     employeeData = { id: empDoc.id, ...empDoc.data() } as Employee;
                 }
            }

            if (!employeeData && user.email) {
                 const q = query(collection(db, "employees"), where("email", "==", user.email));
                 const querySnapshot = await getDocs(q);
                 if (!querySnapshot.empty) {
                     employeeData = { id: querySnapshot.docs[0].id, ...querySnapshot.docs[0].data() } as Employee;
                     // Optional: Update system user with found employee ID
                 }
            }

            // Create temporary guest employee if none found
            if (!employeeData) {
               employeeData = {
                  id: 'EMP-GUEST',
                  firstName: user.displayName?.split(' ')[0] || 'Guest',
                  lastName: user.displayName?.split(' ').slice(1).join(' ') || 'User',
                  department: 'General',
                  role: systemUserData.roleId === 'ROLE-HR' ? 'HR Manager' : (systemUserData.roleId === 'ROLE-STAFF' ? 'Academic Staff' : 'System User'),
                  email: user.email || '',
                  phone: '',
                  joinDate: new Date().toISOString()
              };
            }

            setCurrentUser(systemUserData);
            setCurrentEmployee(employeeData);
            setIsAuthenticated(true);

            // Redirect Logic based on Role
            const userRole = systemUserData.roleId;
            if (userRole === 'ROLE-STAFF') {
                setActiveTab('students');
            } else if (userRole === 'ROLE-HR') {
                setActiveTab('employees');
            } else if (userRole === 'ROLE-IT') {
                setActiveTab('helpdesk');
            } else if (userRole === 'ROLE-NON-TEACHING') {
                setActiveTab('leave');
            } else {
                setActiveTab('dashboard');
            }

        } catch (error) {
            console.error("Error fetching user profile:", error);
            // Handle error state or logout
        }
      } else {
        setCurrentUser(null);
        setCurrentEmployee(null);
        setIsAuthenticated(false);
      }
      setLoading(false);
    });

    return () => unsubscribe();
  }, []);

  const handleLogin = (user: SystemUser) => {
    // Auth state handled by listener
  };

  const handleRegister = (user: SystemUser) => {
     // Auth state handled by listener
  };

  const handleLogout = async () => {
    await signOut(auth);
    setAuthView('login');
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard />;
      case 'students':
        return <StudentRecords />;
      case 'leave':
        return <LeaveManagement />;
      case 'assistant':
        return <AIAssistant />;
      case 'employees':
        return <StaffDirectory />;
      case 'helpdesk':
        return <HelpDesk />;
      case 'settings':
        return <Settings />;
      default:
        return <Dashboard />;
    }
  };

  if (loading) {
      return (
          <div className="min-h-screen flex items-center justify-center bg-slate-100">
              <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
          </div>
      );
  }

  if (!isAuthenticated) {
    if (authView === 'register') {
        return (
            <Register 
                onRegister={handleRegister} 
                onNavigateToLogin={() => setAuthView('login')} 
            />
        );
    }
    return (
        <Login 
            onLogin={handleLogin} 
            onNavigateToRegister={() => setAuthView('register')} 
        />
    );
  }

  return (
    <div className="flex min-h-screen bg-[#f3f4f6]">
      {/* Sidebar */}
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        onLogout={handleLogout} 
        isOpen={isSidebarOpen}
        onClose={() => setIsSidebarOpen(false)}
      />

      {/* Main Content Area */}
      <div className="flex-1 flex flex-col md:ml-64 transition-all duration-300 min-w-0">
        {/* Header */}
        <header className="h-16 bg-white shadow-sm border-b border-slate-200 flex items-center justify-between px-4 md:px-8 sticky top-0 z-20">
          <div className="flex items-center gap-3 md:gap-4 text-slate-600">
             <button 
                onClick={() => setIsSidebarOpen(true)}
                className="md:hidden p-1 hover:bg-slate-100 rounded-lg text-slate-600 transition-colors"
             >
                <Menu size={24} />
             </button>
             <div className="flex flex-col md:flex-row md:items-center md:gap-4">
               <span className="font-semibold text-base md:text-lg tracking-tight text-slate-800 truncate">OLA College</span>
               <span className="hidden md:inline text-slate-300">|</span>
               <span className="text-xs md:text-sm text-slate-500 hidden sm:inline">Management Information System</span>
             </div>
          </div>

          <div className="flex items-center gap-3 md:gap-4">
             <div className="text-right hidden sm:block">
                 <p className="text-sm font-bold text-slate-800">
                    {currentEmployee ? `${currentEmployee.firstName} ${currentEmployee.lastName}` : currentUser?.username}
                 </p>
                 <p className="text-xs text-slate-500">
                    {currentEmployee ? currentEmployee.role : 'System User'}
                 </p>
             </div>
             <div className="h-9 w-9 md:h-10 md:w-10 rounded-full bg-slate-900 text-white flex items-center justify-center font-bold overflow-hidden border-2 border-slate-200">
                 {currentEmployee?.photo ? (
                    <img src={currentEmployee.photo} alt="Profile" className="w-full h-full object-cover" />
                 ) : (
                    <span>
                        {currentEmployee 
                            ? `${currentEmployee.firstName[0]}${currentEmployee.lastName[0]}` 
                            : currentUser?.username?.[0]?.toUpperCase() || 'U'}
                    </span>
                 )}
             </div>
          </div>
        </header>

        {/* Dynamic Page Content */}
        <main className="p-4 md:p-8 flex-1 overflow-x-hidden">
          <div className="max-w-7xl mx-auto animate-fade-in">
            {renderContent()}
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useEffect, useState } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, PieChart, Pie, Cell } from 'recharts';
import { Users, GraduationCap, CalendarOff, AlertCircle } from 'lucide-react';
import { LeaveStatus } from '../types';
import { db } from '../services/firebase';
import { collection, onSnapshot, query } from 'firebase/firestore';

const Dashboard: React.FC = () => {
  const [totalStudents, setTotalStudents] = useState(0);
  const [totalStaff, setTotalStaff] = useState(0);
  const [pendingLeaves, setPendingLeaves] = useState(0);
  const [activeLeaves, setActiveLeaves] = useState(0);
  const [rejectedLeaves, setRejectedLeaves] = useState(0);
  const [studentData, setStudentData] = useState<{name: string, count: number}[]>([]);

  useEffect(() => {
    // 1. Fetch Students
    const unsubStudents = onSnapshot(collection(db, 'students'), (snapshot) => {
        setTotalStudents(snapshot.size);

        // Calculate year distribution
        const years = [0, 0, 0, 0]; // Index 0 = Year 1, etc.
        snapshot.forEach(doc => {
            const y = doc.data().year;
            if (y >= 1 && y <= 4) years[y-1]++;
        });

        setStudentData([
            { name: 'Year 1', count: years[0] },
            { name: 'Year 2', count: years[1] },
            { name: 'Year 3', count: years[2] },
            { name: 'Year 4', count: years[3] },
        ]);
    });

    // 2. Fetch Employees
    const unsubEmployees = onSnapshot(collection(db, 'employees'), (snapshot) => {
        setTotalStaff(snapshot.size);
    });

    // 3. Fetch Leaves
    const unsubLeaves = onSnapshot(collection(db, 'leave_requests'), (snapshot) => {
        let pending = 0;
        let approved = 0;
        let rejected = 0;

        snapshot.forEach(doc => {
            const status = doc.data().status;
            if (status === LeaveStatus.PENDING) pending++;
            else if (status === LeaveStatus.APPROVED) approved++;
            else if (status === LeaveStatus.REJECTED) rejected++;
        });

        setPendingLeaves(pending);
        setActiveLeaves(approved);
        setRejectedLeaves(rejected);
    });

    return () => {
        unsubStudents();
        unsubEmployees();
        unsubLeaves();
    };
  }, []);

  const leaveData = [
    { name: 'Pending', value: pendingLeaves, color: '#F59E0B' },
    { name: 'Approved', value: activeLeaves, color: '#10B981' },
    { name: 'Rejected', value: rejectedLeaves, color: '#EF4444' },
  ];

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-slate-800">Administrator Dashboard</h2>
        <div className="text-sm text-slate-500">
          Last updated: {new Date().toLocaleDateString()}
        </div>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex items-center gap-4">
          <div className="p-3 bg-blue-100 text-blue-600 rounded-full">
            <GraduationCap size={24} />
          </div>
          <div>
            <p className="text-sm text-slate-500 font-medium">Total Students</p>
            <h3 className="text-2xl font-bold text-slate-800">{totalStudents}</h3>
          </div>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex items-center gap-4">
          <div className="p-3 bg-indigo-100 text-indigo-600 rounded-full">
            <Users size={24} />
          </div>
          <div>
            <p className="text-sm text-slate-500 font-medium">Active Staff</p>
            <h3 className="text-2xl font-bold text-slate-800">{totalStaff}</h3>
          </div>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex items-center gap-4">
          <div className="p-3 bg-amber-100 text-amber-600 rounded-full">
            <AlertCircle size={24} />
          </div>
          <div>
            <p className="text-sm text-slate-500 font-medium">Pending Leaves</p>
            <h3 className="text-2xl font-bold text-slate-800">{pendingLeaves}</h3>
          </div>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex items-center gap-4">
          <div className="p-3 bg-green-100 text-green-600 rounded-full">
            <CalendarOff size={24} />
          </div>
          <div>
            <p className="text-sm text-slate-500 font-medium">Staff on Leave</p>
            <h3 className="text-2xl font-bold text-slate-800">{activeLeaves}</h3>
          </div>
        </div>
      </div>

      {/* Charts Section */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Student Enrollment Chart */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-semibold text-slate-800 mb-4">Student Enrollment by Year</h3>
          <div className="h-80 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={studentData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} />
                <XAxis dataKey="name" axisLine={false} tickLine={false} />
                <YAxis axisLine={false} tickLine={false} />
                <Tooltip 
                  contentStyle={{ backgroundColor: '#1e293b', color: '#fff', borderRadius: '8px', border: 'none' }}
                  cursor={{ fill: '#f1f5f9' }}
                />
                <Bar dataKey="count" fill="#3B82F6" radius={[4, 4, 0, 0]} barSize={50} />
              </BarChart>
            </ResponsiveContainer>
