             ) : (
                 <div className="text-slate-400">No leave data available</div>
             )}
            <div className="space-y-2 ml-4">
              {leaveData.map((item, index) => (
                <div key={index} className="flex items-center gap-2">
                  <div className="w-3 h-3 rounded-full" style={{ backgroundColor: item.color }}></div>
                  <span className="text-sm text-slate-600">{item.name}: {item.value}</span>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>

      {/* Quick Actions / Recent Activity Placeholder */}
      <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
        <h3 className="text-lg font-semibold text-slate-800 mb-4">Recent System Activities</h3>
        <div className="space-y-4">
          {[1, 2, 3].map((_, i) => (
            <div key={i} className="flex items-center justify-between p-3 hover:bg-slate-50 rounded-lg transition-colors border-b last:border-0 border-slate-100">
              <div className="flex items-center gap-3">
                <div className="w-8 h-8 rounded-full bg-slate-200 flex items-center justify-center text-xs font-bold text-slate-600">
                  SYS
                </div>
                <div>
                  <p className="text-sm font-medium text-slate-800">System Backup Completed</p>
                  <p className="text-xs text-slate-500">Automated task ran successfully</p>
                </div>
              </div>
              <span className="text-xs text-slate-400">2 hours ago</span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

