      Current GPA: ${student.gpa}
      Enrollment Date: ${student.enrollmentDate}

      The tone should be professional and encouraging, suitable for a progress report or reference letter. 
      Mention their potential based on the GPA.
    `;

    try {
      const response = await generateAIResponse(prompt);
      setAiAnalysis(response);
