import React, { useState, useEffect } from 'react';
import { LeaveRequest, LeaveStatus, LeaveType, Employee } from '../types';
import { Check, X, Clock, CalendarDays, Plus, AlertTriangle } from 'lucide-react';
import { db } from '../services/firebase';
import { collection, addDoc, onSnapshot, query, orderBy, updateDoc, doc, getDocs } from 'firebase/firestore';

const LeaveManagement: React.FC = () => {
  const [requests, setRequests] = useState<LeaveRequest[]>([]);
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [filterStatus, setFilterStatus] = useState<string>('ALL');
  const [isModalOpen, setIsModalOpen] = useState(false);

  const [formData, setFormData] = useState({
    employeeId: '',
    type: LeaveType.SICK,
    startDate: '',
    endDate: '',
    reason: ''
  });

  useEffect(() => {
    // Fetch Leave Requests
    const q = query(collection(db, 'leave_requests'), orderBy('requestDate', 'desc'));
    const unsubLeaves = onSnapshot(q, (snapshot) => {
        setRequests(snapshot.docs.map(doc => ({id: doc.id, ...doc.data()} as LeaveRequest)));
    });

    // Fetch Employees for dropdown
    const unsubEmployees = onSnapshot(collection(db, 'employees'), (snapshot) => {
        setEmployees(snapshot.docs.map(doc => ({id: doc.id, ...doc.data()} as Employee)));
    });

    return () => {
        unsubLeaves();
        unsubEmployees();
    };
  }, []);

  const handleStatusChange = async (id: string, newStatus: LeaveStatus) => {
    try {
        await updateDoc(doc(db, 'leave_requests', id), { status: newStatus });
    } catch (error) {
        console.error("Error updating leave status", error);
    }
  };

  const filteredRequests = filterStatus === 'ALL' 
    ? requests 
    : requests.filter(r => r.status === filterStatus);

  const getStatusColor = (status: LeaveStatus) => {
    switch (status) {
      case LeaveStatus.APPROVED: return 'bg-green-100 text-green-700 border-green-200';
      case LeaveStatus.REJECTED: return 'bg-red-100 text-red-700 border-red-200';
      default: return 'bg-amber-100 text-amber-700 border-amber-200';
    }
  };

  const getStatusIcon = (status: LeaveStatus) => {
    switch (status) {
      case LeaveStatus.APPROVED: return <Check size={14} />;
      case LeaveStatus.REJECTED: return <X size={14} />;
      default: return <Clock size={14} />;
    }
  };

