              <div className="space-y-1.5">
                <label className="text-sm font-medium text-slate-700">Leave Type</label>
                <select 
                  name="type"
                  required
                  value={formData.type}
                  onChange={handleInputChange}
                  className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all text-sm"
                >
                  {Object.values(LeaveType).map(type => (
                    <option key={type} value={type}>{type}</option>
                  ))}
                </select>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-sm font-medium text-slate-700">Start Date</label>
                  <input 
                    type="date"
                    name="startDate"
                    required
                    value={formData.startDate}
                    onChange={handleInputChange}
                    className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all text-sm"
                  />
                </div>
                <div className="space-y-1.5">
                  <label className="text-sm font-medium text-slate-700">End Date</label>
                  <input 
                    type="date"
                    name="endDate"
                    required
                    value={formData.endDate}
                    onChange={handleInputChange}
                    className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all text-sm"
                  />
                </div>
              </div>

              <div className="space-y-1.5">
                <label className="text-sm font-medium text-slate-700">Reason</label>
                <textarea 
                  name="reason"
                  required
                  rows={3}
                  value={formData.reason}
                  onChange={handleInputChange}
                  placeholder="Please provide a brief reason for the leave request..."
                  className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all text-sm resize-none"
                />
              </div>

              <div className="pt-2 flex justify-end gap-3">
                <button 
                  type="button"
                  onClick={() => setIsModalOpen(false)}
                  className="px-4 py-2 border border-slate-200 text-slate-600 rounded-lg hover:bg-slate-50 transition-colors text-sm font-medium"
                >
                  Cancel
                </button>
                <button 
                  type="submit"
                  className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors text-sm font-medium shadow-sm"
                >
                  Submit Request
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default LeaveManagement;

import React, { useState, useEffect, useRef } from 'react';
import { Employee, Education, EmergencyContact, NextOfKin } from '../types';
import { Search, Plus, Filter, MoreHorizontal, Mail, Phone, X, CheckCircle, Send, Upload, User, Edit2, Trash2, Eye, Building, GraduationCap, ArrowRight, ArrowLeft, Save, AlertCircle, Check, FileSpreadsheet, Download, UploadCloud } from 'lucide-react';
import { db } from '../services/firebase';
import { collection, onSnapshot, deleteDoc, doc, setDoc } from 'firebase/firestore';

const StaffDirectory: React.FC = () => {
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [searchTerm, setSearchTerm] = useState('');

  // Filter States
  const [filterDept, setFilterDept] = useState('');
  const [showFilterMenu, setShowFilterMenu] = useState(false);

  // Modal States
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isViewModalOpen, setIsViewModalOpen] = useState(false);
  const [isBulkModalOpen, setIsBulkModalOpen] = useState(false);

  const [currentStep, setCurrentStep] = useState(1);
  const [errors, setErrors] = useState<Record<string, string>>({});

  const [notification, setNotification] = useState<{show: boolean, ticketId: string | null, message?: string}>({ show: false, ticketId: null });
  const [selectedIds, setSelectedIds] = useState<string[]>([]);

  // Selection States
  const [viewingEmployee, setViewingEmployee] = useState<Employee | null>(null);
  const [editingEmployeeId, setEditingEmployeeId] = useState<string | null>(null);

  // Bulk Upload State
  const [bulkFile, setBulkFile] = useState<File | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Initial Empty State
  const initialFormState: Partial<Employee> = {
    firstName: '',
    lastName: '',
    id: '',
    department: '',
    role: '',
    phone: '',
    email: '', // Institutional email
    joinDate: new Date().toISOString().split('T')[0],
    photo: undefined,
    personalEmail: '',
    houseAddress: '',
    boxAddress: '',
    education: [],
    emergencyContact: { name: '', relation: '', email: '', phone: '' },
    nextOfKin: { name: '', relation: '', phone: '', address: '' }
  };

  const [formData, setFormData] = useState<Partial<Employee>>(initialFormState);

  // Temporary state for adding a single education record
  const [eduForm, setEduForm] = useState<Partial<Education>>({
    degree: '',
    institution: '',
    admissionYear: '',
    completionYear: '',
    referenceNumber: ''
  });

  // Fetch Employees from Firestore
  useEffect(() => {
    const unsub = onSnapshot(collection(db, 'employees'), (snapshot) => {
        setEmployees(snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Employee)));
    });
    return () => unsub();
  }, []);

  // Load draft on open if creating new
  useEffect(() => {
    if (isModalOpen && !editingEmployeeId) {
        const savedDraft = localStorage.getItem('new_staff_draft');
        if (savedDraft) {
            try {
                const parsed = JSON.parse(savedDraft);
                if(window.confirm("Found a saved draft for a new staff member. Would you like to continue?")) {
                    setFormData(parsed);
                } else {
                    localStorage.removeItem('new_staff_draft');
                }
            } catch (e) {
                console.error("Failed to load draft", e);
            }
        }
    }
  }, [isModalOpen]);

  const saveDraft = () => {
      if (!editingEmployeeId) {
          localStorage.setItem('new_staff_draft', JSON.stringify(formData));
      }
  };

  // --- Validation Helpers ---
  const sanitizePhone = (value: string) => {
    // Only allow digits, +, -, (, ), and space
    return value.replace(/[^0-9+\-()\s]/g, '');
  };

  const validatePhoneFormat = (value: string) => {
    // Simple check: allowed chars and at least 10 digits/symbols
    const validChars = /^[\d\+\-\(\)\s]+$/;
    const hasMinLength = value.trim().length >= 10;
    return validChars.test(value) && hasMinLength;
  };

  const filteredEmployees = employees.filter(emp => {
    const matchesSearch = emp.lastName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    emp.firstName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    emp.department.toLowerCase().includes(searchTerm.toLowerCase()) ||
    emp.role.toLowerCase().includes(searchTerm.toLowerCase());

    const matchesDept = filterDept ? emp.department === filterDept : true;

    return matchesSearch && matchesDept;
  });

  // Unique Departments for filter
  const uniqueDepts = Array.from(new Set(employees.map(e => e.department))).sort();

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;

    if (name === 'phone') {
        const sanitized = sanitizePhone(value);
        setFormData(prev => ({ ...prev, [name]: sanitized }));
        // Clear error if user is typing
        if (errors.phone) setErrors(prev => ({ ...prev, phone: '' }));
    } else {
        setFormData(prev => ({ ...prev, [name]: value }));
    }
  };

  // Nested input handlers
  const handleEmergencyChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
      const { name, value } = e.target;
      if (name === 'phone') {
          const sanitized = sanitizePhone(value);
          setFormData(prev => ({
              ...prev,
              emergencyContact: { ...prev.emergencyContact!, [name]: sanitized }
          }));
          if (errors.emergencyPhone) setErrors(prev => ({ ...prev, emergencyPhone: '' }));
      } else {
          setFormData(prev => ({
              ...prev,
              emergencyContact: { ...prev.emergencyContact!, [name]: value }
          }));
      }
  };

  const handleNextOfKinChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
      const { name, value } = e.target;
      if (name === 'phone') {
          const sanitized = sanitizePhone(value);
          setFormData(prev => ({
              ...prev,
              nextOfKin: { ...prev.nextOfKin!, [name]: sanitized }
          }));
          if (errors.nokPhone) setErrors(prev => ({ ...prev, nokPhone: '' }));
      } else {
          setFormData(prev => ({
              ...prev,
              nextOfKin: { ...prev.nextOfKin!, [name]: value }
          }));
      }
  };

  const handlePhotoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      const photoUrl = URL.createObjectURL(file);
      setFormData(prev => ({ ...prev, photo: photoUrl }));
    }
  };

  const handleAddEducation = () => {
      if(!eduForm.degree || !eduForm.institution) return;

      const newEdu: Education = {
          id: Date.now().toString(),
          degree: eduForm.degree!,
          institution: eduForm.institution!,
          admissionYear: eduForm.admissionYear || '',
          completionYear: eduForm.completionYear || '',
          referenceNumber: eduForm.referenceNumber || '',
          certificateUrl: eduForm.certificateUrl
      };

      setFormData(prev => ({
          ...prev,
          education: [...(prev.education || []), newEdu]
      }));

      // Reset edu form
      setEduForm({
        degree: '',
        institution: '',
        admissionYear: '',
        completionYear: '',
        referenceNumber: '',
        certificateUrl: undefined
      });
  };

  const handleRemoveEducation = (id: string) => {
      setFormData(prev => ({
          ...prev,
          education: prev.education?.filter(e => e.id !== id)
      }));
  };

  // --- Actions ---

  const handleSelectAll = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.checked) {
      setSelectedIds(filteredEmployees.map(emp => emp.id));
    } else {
      setSelectedIds([]);
    }
  };

  const handleSelectOne = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    setSelectedIds(prev => 
      prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]
    );
  };

  const handleBulkEmail = () => {
    const selectedEmails = employees
        .filter(emp => selectedIds.includes(emp.id))
        .map(emp => emp.email)
        .filter(email => email);

    if (selectedEmails.length > 0) {
        window.location.href = `mailto:?bcc=${selectedEmails.join(',')}`;
    } else {
        alert("No valid email addresses found for the selected staff.");
    }
  };

  const handleAddClick = () => {
    setEditingEmployeeId(null);
    setFormData(initialFormState);
    setCurrentStep(1);
    setErrors({});
    setIsModalOpen(true);
  };

  const handleEditClick = (e: React.MouseEvent, emp: Employee) => {
    e.stopPropagation();
    setEditingEmployeeId(emp.id);
    setFormData({
        ...emp,
        education: emp.education || [],
        emergencyContact: emp.emergencyContact || { name: '', relation: '', email: '', phone: '' },
        nextOfKin: emp.nextOfKin || { name: '', relation: '', phone: '', address: '' }
    });
    setCurrentStep(1);
    setErrors({});
    setIsModalOpen(true);
  };

  const handleDeleteClick = async (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (window.confirm("Are you sure you want to delete this staff member? This action cannot be undone.")) {
      try {
          await deleteDoc(doc(db, 'employees', id));
          if (viewingEmployee?.id === id) {
            setIsViewModalOpen(false);
            setViewingEmployee(null);
          }
      } catch (error) {
          console.error("Error deleting document: ", error);
          alert("Failed to delete staff member.");
      }
    }
  };

  const handleRowClick = (emp: Employee) => {
    setViewingEmployee(emp);
    setIsViewModalOpen(true);
  };

  // --- Bulk Upload Handlers ---
  const handleDownloadTemplate = () => {
    const headers = ["FirstName", "LastName", "StaffID", "Department", "Role", "Email", "Phone", "DateJoined", "HouseAddress"];
    // Using simple CSV content generation
    const rows = [
      headers,
      ["Kwame", "Mensah", "EMP-NEW-01", "Science", "Lecturer", "k.mensah@ola.edu.gh", "0240000000", "2024-01-01", "\"Hse 10, Cape Coast\""]
    ];

    const csvContent = rows.map(r => r.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);

    const link = document.createElement("a");
    link.href = url;
    link.setAttribute("download", "staff_upload_template.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleBulkFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setBulkFile(e.target.files[0]);
    }
  };

  const handleProcessBulkUpload = () => {
    if (!bulkFile) return;

    const reader = new FileReader();
    reader.onload = async (evt) => {
        const text = evt.target?.result as string;
        if (!text) return;

        // Split by new line
        const lines = text.split(/\r\n|\n/);
        let skippedCount = 0;
        let successCount = 0;

        // Skip header row (index 0)
        for (let i = 1; i < lines.length; i++) {
            const line = lines[i].trim();
            if (!line) continue;

            // Regex to parse CSV line, correctly handling quotes (e.g. "City, Country")
            const parts = line.split(/,(?=(?:(?:[^"]*"){2})*[^"]*$)/).map(val => val.trim().replace(/^"|"$/g, '').trim());

            // Basic validation: needs at least First Name, Last Name, ID (indices 0, 1, 2)
            if (parts.length < 3) {
                skippedCount++;
                continue;
            }

            const empId = parts[2] || `EMP-${Date.now()}-${i}`;

            // Map based on template headers: 
            // 0:FN, 1:LN, 2:ID, 3:Dept, 4:Role, 5:Email, 6:Phone, 7:Date, 8:Addr
            const newEmp: Employee = {
                firstName: parts[0] || 'Unknown',
                lastName: parts[1] || 'Staff',
                id: empId,
                department: parts[3] || 'General',
                role: parts[4] || 'Staff',
                email: parts[5] || '',
                phone: parts[6] || '',
                joinDate: parts[7] || new Date().toISOString().split('T')[0],
                houseAddress: parts[8] || '',
                // Initialize others
                education: [],
                emergencyContact: { name: '', relation: '', email: '', phone: '' },
                nextOfKin: { name: '', relation: '', phone: '', address: '' }
            };

            // Save to Firestore - use ID as doc ID for easier access
            try {
                await setDoc(doc(db, 'employees', empId), newEmp);
                successCount++;
            } catch (err) {
                console.error(`Failed to upload ${empId}`, err);
                skippedCount++;
            }
        }

        if (successCount > 0) {
            setNotification({ 
                show: true, 
                ticketId: null, 
                message: `Successfully imported ${successCount} staff members.${skippedCount > 0 ? ` Skipped ${skippedCount} invalid/failed rows.` : ''}` 
            });
            setIsBulkModalOpen(false);
            setBulkFile(null);
            setTimeout(() => setNotification({ show: false, ticketId: null }), 4000);
        } else {
            alert("No valid records were uploaded.");
        }
    };
    reader.readAsText(bulkFile);
  };

  const handleCloseBulkModal = () => {
      setIsBulkModalOpen(false);
      setBulkFile(null);
      if (fileInputRef.current) {
          fileInputRef.current.value = "";
      }
  };

  const validateCurrentStep = () => {
      const newErrors: Record<string, string> = {};
      let isValid = true;

      if (currentStep === 1) {
          if (!formData.firstName) { newErrors.firstName = 'First name is required'; isValid = false; }
          if (!formData.lastName) { newErrors.lastName = 'Last name is required'; isValid = false; }
          if (!formData.id && !editingEmployeeId) { newErrors.id = 'Staff ID is required'; isValid = false; }

          if (formData.phone && !validatePhoneFormat(formData.phone)) {
              newErrors.phone = 'Invalid phone number format';
              isValid = false;
          } else if (!formData.phone) {
              newErrors.phone = 'Phone number is required';
              isValid = false;
          }
      }

      if (currentStep === 3) {
          if (formData.emergencyContact?.phone && !validatePhoneFormat(formData.emergencyContact.phone)) {
              newErrors.emergencyPhone = 'Invalid phone number';
              isValid = false;
          }
          if (formData.nextOfKin?.phone && !validatePhoneFormat(formData.nextOfKin.phone)) {
              newErrors.nokPhone = 'Invalid phone number';
              isValid = false;
          }
      }

      setErrors(newErrors);
      return isValid;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!validateCurrentStep()) return;

    // Auto-generate institutional email if missing
    const finalEmail = formData.email || `${formData.firstName?.charAt(0).toLowerCase()}.${formData.lastName?.toLowerCase()}@ola.edu.gh`;

    // Ensure ID is present if not editing
    if (!editingEmployeeId && !formData.id) {
        alert("Please enter a Staff ID");
        return;
    }

    const finalData: Employee = {
        ...formData as Employee,
        email: finalEmail
    };

    try {
        if (editingEmployeeId) {
           await setDoc(doc(db, 'employees', editingEmployeeId), finalData);
        } else {
           await setDoc(doc(db, 'employees', finalData.id), finalData);
           localStorage.removeItem('new_staff_draft'); // Clear draft
        }

        setIsModalOpen(false);
        setEditingEmployeeId(null);
        setFormData(initialFormState);
        setErrors({});

        // Show success notification
        setNotification({ show: true, ticketId: null });
        setTimeout(() => setNotification({ show: false, ticketId: null }), 3000);

    } catch (error) {
        console.error("Error saving employee:", error);
        alert("Failed to save employee record.");
    }
  };

  const nextStep = () => {
      if (validateCurrentStep()) {
        saveDraft();
        setCurrentStep(prev => prev + 1);
      }
  };

  const prevStep = () => setCurrentStep(prev => prev - 1);

  // --- Wizard Steps ---

  const renderStep1_BasicInfo = () => (
      <div className="space-y-4 animate-in fade-in slide-in-from-right-4 duration-300">
          <div className="flex flex-col items-center justify-center mb-6">
                <div className="w-24 h-24 bg-slate-100 rounded-full border-2 border-dashed border-slate-300 flex items-center justify-center overflow-hidden relative group transition-colors hover:border-blue-400">
                    {formData.photo ? (
                        <img src={formData.photo} alt="Preview" className="w-full h-full object-cover" />
                    ) : (
                        <User size={32} className="text-slate-400" />
                    )}
                    <label className="absolute inset-0 flex flex-col items-center justify-center bg-black/50 opacity-0 group-hover:opacity-100 transition-opacity cursor-pointer text-white text-xs font-medium">
                        <Upload size={20} className="mb-1" />
                        <span>Upload</span>
                        <input type="file" accept="image/*" className="hidden" onChange={handlePhotoChange} />
                    </label>
                </div>
                <p className="text-xs text-slate-500 mt-2">Passport Photo</p>
          </div>

          <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1">
                  <label className="text-xs font-semibold text-slate-600">First Name <span className="text-red-500">*</span></label>
                  <input name="firstName" value={formData.firstName} onChange={handleInputChange} className={`w-full px-3 py-2 border rounded-lg text-sm ${errors.firstName ? 'border-red-500' : ''}`} placeholder="e.g. Samuel" required />
                  {errors.firstName && <span className="text-red-500 text-[10px] flex items-center gap-1"><AlertCircle size={10} /> {errors.firstName}</span>}
              </div>
              <div className="space-y-1">
