                        <div>
                          <p className="font-medium text-slate-900">{emp.firstName} {emp.lastName}</p>
                          <p className="text-xs text-slate-500">{emp.id}</p>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4 text-slate-600">
                        <div className="flex flex-col gap-1">
                            <div className="flex items-center gap-2 text-xs">
                                <Mail size={12} className="text-slate-400"/>
                                <span className="truncate max-w-[150px]" title={emp.email}>{emp.email}</span>
                            </div>
                            <div className="flex items-center gap-2 text-xs">
                                <Phone size={12} className="text-slate-400"/>
                                <span>{emp.phone}</span>
                            </div>
                        </div>
                    </td>
                    <td className="px-6 py-4">
                        <div className="flex flex-col">
                            <span className="font-medium text-slate-800">{emp.department}</span>
                            <span className="text-xs text-slate-500">{emp.role}</span>
                        </div>
                    </td>
                    <td className="px-6 py-4 text-slate-600">
                        <span className="px-2 py-1 bg-slate-100 rounded text-xs">{emp.joinDate}</span>
                    </td>
                    <td className="px-6 py-4 text-right" onClick={(e) => e.stopPropagation()}>
                      <div className="flex justify-end gap-2">
                        <button onClick={(e) => handleEditClick(e, emp)} className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors" title="Edit">
                          <Edit2 size={16} />
                        </button>
                        <button onClick={(e) => handleDeleteClick(e, emp.id)} className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors" title="Delete">
                          <Trash2 size={16} />
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
            {filteredEmployees.length === 0 && (
              <div className="p-12 text-center text-slate-500 flex flex-col items-center">
                <div className="w-16 h-16 bg-slate-100 rounded-full flex items-center justify-center mb-4 text-slate-300">
                    <User size={32} />
                </div>
                <p className="text-lg font-medium text-slate-700">No staff members found.</p>
                <p className="text-sm text-slate-400 mt-1">Try adjusting your search or add a new staff member.</p>
              </div>
            )}
          </div>
      </div>

      {/* --- ADD / EDIT MODAL --- */}
      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
            <div className="bg-white rounded-xl shadow-2xl w-full max-w-2xl overflow-hidden animate-in fade-in zoom-in duration-200 flex flex-col max-h-[90vh]">
                {/* Modal Header */}
                <div className="flex justify-between items-center p-6 border-b border-slate-100 bg-slate-50">
                    <div>
                        <h3 className="text-xl font-bold text-slate-800">{editingEmployeeId ? 'Edit Staff Profile' : 'New Staff Onboarding'}</h3>
                        <p className="text-xs text-slate-500 mt-1">Step {currentStep} of 4</p>
                    </div>
                    <button onClick={() => setIsModalOpen(false)} className="text-slate-400 hover:text-slate-600 transition-colors"><X size={20} /></button>
                </div>

                {/* Progress Bar */}
                <div className="w-full bg-slate-100 h-1">
                    <div className="bg-blue-600 h-1 transition-all duration-300" style={{ width: `${(currentStep / 4) * 100}%` }}></div>
                </div>

                {/* Modal Content */}
                <div className="p-6 overflow-y-auto flex-1 custom-scrollbar">
                    {currentStep === 1 && renderStep1_BasicInfo()}
                    {currentStep === 2 && renderStep2_Education()}
                    {currentStep === 3 && renderStep3_Contacts()}
                    {currentStep === 4 && renderStep4_Preview()}
                </div>

                {/* Modal Footer */}
                <div className="p-6 border-t border-slate-100 bg-slate-50 flex justify-between items-center">
                    {currentStep > 1 ? (
                        <button onClick={prevStep} className="flex items-center gap-2 px-4 py-2 border border-slate-300 rounded-lg text-slate-600 hover:bg-white text-sm font-medium transition-colors">
                            <ArrowLeft size={16} /> Back
                        </button>
                    ) : (
                        <div></div>
                    )}

                    <div className="flex gap-3">
                         <button onClick={() => setIsModalOpen(false)} className="px-4 py-2 text-slate-500 hover:text-slate-700 text-sm font-medium">
                            Cancel
                        </button>
                        {currentStep < 4 ? (
                             <button onClick={nextStep} className="flex items-center gap-2 px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 text-sm font-medium transition-colors shadow-sm">
                                Next <ArrowRight size={16} />
                            </button>
                        ) : (
                             <button onClick={handleSubmit} className="flex items-center gap-2 px-6 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 text-sm font-medium transition-colors shadow-sm">
                                <Save size={16} /> {editingEmployeeId ? 'Save Changes' : 'Confirm & Add'}
                            </button>
                        )}
                    </div>
                </div>
            </div>
        </div>
      )}

      {/* --- VIEW MODAL --- */}
      {isViewModalOpen && viewingEmployee && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
             <div className="bg-white rounded-xl shadow-2xl w-full max-w-3xl overflow-hidden animate-in fade-in zoom-in duration-200 flex flex-col max-h-[90vh]">
                 <div className="relative h-32 bg-slate-800">
                     <button onClick={() => setIsViewModalOpen(false)} className="absolute top-4 right-4 text-white/70 hover:text-white bg-black/20 p-2 rounded-full backdrop-blur-sm"><X size={20}/></button>
                     <div className="absolute -bottom-12 left-8 flex items-end gap-4">
                         <div className="w-24 h-24 bg-white rounded-xl p-1 shadow-lg">
                             <div className="w-full h-full bg-slate-100 rounded-lg overflow-hidden flex items-center justify-center">
                                 {viewingEmployee.photo ? (
                                     <img src={viewingEmployee.photo} alt="" className="w-full h-full object-cover" />
                                 ) : (
                                     <User size={40} className="text-slate-300" />
                                 )}
                             </div>
                         </div>
                         <div className="mb-2">
                             <h2 className="text-2xl font-bold text-slate-800">{viewingEmployee.firstName} {viewingEmployee.lastName}</h2>
                             <p className="text-slate-500 font-medium">{viewingEmployee.role}</p>
                         </div>
                     </div>
                 </div>

                 <div className="mt-14 p-8 overflow-y-auto flex-1 custom-scrollbar">
                     <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                         <div className="space-y-6">
                             <div>
                                 <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-3">Employment Details</h4>
                                 <div className="bg-slate-50 p-4 rounded-xl border border-slate-100 space-y-3">
                                     <div className="flex justify-between">
                                         <span className="text-sm text-slate-500">Staff ID</span>
                                         <span className="text-sm font-semibold text-slate-800">{viewingEmployee.id}</span>
                                     </div>
                                     <div className="flex justify-between">
                                         <span className="text-sm text-slate-500">Department</span>
                                         <span className="text-sm font-semibold text-slate-800">{viewingEmployee.department}</span>
                                     </div>
                                     <div className="flex justify-between">
                                         <span className="text-sm text-slate-500">Date Joined</span>
                                         <span className="text-sm font-semibold text-slate-800">{viewingEmployee.joinDate}</span>
                                     </div>
                                      <div className="flex justify-between">
                                         <span className="text-sm text-slate-500">Official Email</span>
                                         <span className="text-sm font-semibold text-blue-600 truncate max-w-[150px]">{viewingEmployee.email}</span>
                                     </div>
                                 </div>
                             </div>

                             <div>
                                  <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-3">Education</h4>
                                  <div className="space-y-3">
                                      {viewingEmployee.education?.map((edu, i) => (
                                          <div key={i} className="flex items-start gap-3 p-3 border border-slate-100 rounded-lg">
                                              <div className="p-2 bg-blue-50 text-blue-600 rounded-lg">
                                                  <GraduationCap size={16} />
                                              </div>
                                              <div>
                                                  <p className="text-sm font-bold text-slate-800">{edu.degree}</p>
                                                  <p className="text-xs text-slate-500">{edu.institution} • {edu.completionYear}</p>
                                              </div>
                                          </div>
                                      ))}
                                      {(!viewingEmployee.education || viewingEmployee.education.length === 0) && (
                                          <p className="text-sm text-slate-400 italic">No records found.</p>
                                      )}
                                  </div>
                             </div>
                         </div>

                         <div className="space-y-6">
                             <div>
                                 <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-3">Contact Information</h4>
                                 <div className="space-y-4">
                                     <div className="flex items-center gap-3">
                                         <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center text-slate-500"><Phone size={14}/></div>
                                         <div>
                                             <p className="text-xs text-slate-500">Phone Number</p>
                                             <p className="text-sm font-medium text-slate-800">{viewingEmployee.phone}</p>
                                         </div>
                                     </div>
                                     <div className="flex items-center gap-3">
                                         <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center text-slate-500"><Mail size={14}/></div>
                                         <div>
                                             <p className="text-xs text-slate-500">Personal Email</p>
                                             <p className="text-sm font-medium text-slate-800">{viewingEmployee.personalEmail || 'N/A'}</p>
                                         </div>
                                     </div>
                                     <div className="flex items-center gap-3">
                                         <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center text-slate-500"><Building size={14}/></div>
                                         <div>
                                             <p className="text-xs text-slate-500">Residential Address</p>
                                             <p className="text-sm font-medium text-slate-800">{viewingEmployee.houseAddress || 'N/A'}</p>
                                         </div>
                                     </div>
                                 </div>
                             </div>

                             <div>
                                 <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-3">Next of Kin</h4>
                                 <div className="bg-amber-50 p-4 rounded-xl border border-amber-100">
                                     <p className="text-sm font-bold text-amber-900">{viewingEmployee.nextOfKin?.name || 'Not Provided'}</p>
                                     <p className="text-xs text-amber-700">{viewingEmployee.nextOfKin?.relation}</p>
                                     <p className="text-xs text-amber-700 mt-1">{viewingEmployee.nextOfKin?.phone}</p>
                                 </div>
                             </div>
                         </div>
                     </div>
                 </div>

                 <div className="p-6 bg-slate-50 border-t border-slate-200 flex justify-end gap-3">
                      <button onClick={(e) => { setIsViewModalOpen(false); handleEditClick(e, viewingEmployee); }} className="px-4 py-2 border border-slate-300 bg-white rounded-lg text-slate-700 hover:bg-slate-50 text-sm font-medium flex items-center gap-2">
                          <Edit2 size={16} /> Edit Profile
                      </button>
                      <button onClick={(e) => handleDeleteClick(e, viewingEmployee.id)} className="px-4 py-2 bg-red-50 text-red-600 rounded-lg hover:bg-red-100 text-sm font-medium flex items-center gap-2 transition-colors">
                          <Trash2 size={16} /> Delete Staff
                      </button>
                 </div>
             </div>
        </div>
      )}

      {/* --- BULK UPLOAD MODAL --- */}
      {isBulkModalOpen && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
              <div className="bg-white rounded-xl shadow-2xl w-full max-w-md overflow-hidden animate-in fade-in zoom-in duration-200">
                  <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
                      <h3 className="font-bold text-lg text-slate-800">Bulk Staff Import</h3>
                      <button onClick={handleCloseBulkModal}><X size={20} className="text-slate-400 hover:text-slate-600"/></button>
                  </div>
                  <div className="p-6 space-y-4">
                      <div className="p-4 bg-blue-50 border border-blue-100 rounded-lg flex gap-3">
                          <AlertCircle className="text-blue-500 shrink-0" size={20} />
                          <div className="text-sm text-blue-700">
                              <p className="font-semibold mb-1">Instructions</p>
                              <p>Upload a CSV file containing staff records. Ensure headers match the template.</p>
                          </div>
                      </div>

                      <button onClick={handleDownloadTemplate} className="w-full py-2 border border-dashed border-slate-300 rounded-lg text-sm text-slate-600 hover:border-blue-400 hover:text-blue-600 transition-colors flex items-center justify-center gap-2">
                          <Download size={16} /> Download CSV Template
                      </button>

                      <div className="relative">
                          <input 
                              type="file" 
                              accept=".csv"
                              ref={fileInputRef}
                              onChange={handleBulkFileChange}
                              className="block w-full text-sm text-slate-500
                                file:mr-4 file:py-2.5 file:px-4
                                file:rounded-lg file:border-0
                                file:text-sm file:font-semibold
                                file:bg-blue-600 file:text-white
                                hover:file:bg-blue-700
                                cursor-pointer
                              "
                          />
                      </div>
                  </div>
                  <div className="p-6 border-t border-slate-100 flex justify-end gap-3 bg-slate-50">
                      <button onClick={handleCloseBulkModal} className="px-4 py-2 text-slate-500 hover:text-slate-700 text-sm font-medium">Cancel</button>
                      <button 
                          onClick={handleProcessBulkUpload}
                          disabled={!bulkFile}
                          className={`px-4 py-2 rounded-lg text-sm font-medium text-white flex items-center gap-2 shadow-sm transition-all ${!bulkFile ? 'bg-slate-300 cursor-not-allowed' : 'bg-green-600 hover:bg-green-700'}`}
                      >
                          <UploadCloud size={16} /> Process Upload
                      </button>
                  </div>
              </div>
          </div>
      )}

      {/* --- NOTIFICATION TOAST --- */}
      {notification.show && (
          <div className="fixed bottom-6 right-6 bg-slate-900 text-white px-6 py-4 rounded-xl shadow-2xl flex items-center gap-4 animate-in slide-in-from-bottom-5 z-50">
              <div className="bg-green-500 p-2 rounded-full text-white">
                  <CheckCircle size={20} />
              </div>
              <div>
                  <h4 className="font-bold text-sm">Success</h4>
                  <p className="text-xs text-slate-300">{notification.message || 'Operation completed successfully.'}</p>
              </div>
              <button onClick={() => setNotification({...notification, show: false})} className="ml-2 text-slate-400 hover:text-white"><X size={16} /></button>
          </div>
      )}

    </div>
  );
};

export default StaffDirectory;
